def _find_ffmpeg_from_env() -> str:
    env_ffmpeg = os.environ.get("FV_FFMPEG")
    if env_ffmpeg and os.path.exists(env_ffmpeg):
        return env_ffmpeg

    here = os.path.dirname(os.path.abspath(__file__))
    candidates = [
        os.path.join(here, "..", "presets", "bin", "ffmpeg.exe"),
        os.path.join(here, "..", "presets", "bin", "ffmpeg"),
        "ffmpeg.exe",
        "ffmpeg",
    ]
    for c in candidates:
        if shutil.which(c) or os.path.exists(c):
            return c

    return "ffmpeg"


def _find_ffprobe_from_env() -> str:
    env_ffprobe = os.environ.get("FV_FFPROBE")
    if env_ffprobe and os.path.exists(env_ffprobe):
        return env_ffprobe

    here = os.path.dirname(os.path.abspath(__file__))
    candidates = [
        os.path.join(here, "..", "presets", "bin", "ffprobe.exe"),
        os.path.join(here, "..", "presets", "bin", "ffprobe"),
        "ffprobe.exe",
        "ffprobe",
    ]
    for c in candidates:
        if shutil.which(c) or os.path.exists(c):
            return c

    return "ffprobe"







def _musicclip_project_root() -> str:
    """Return the FrameVision project root from this helper file."""
    try:
        return os.path.abspath(os.path.join(os.path.dirname(os.path.abspath(__file__)), ".."))
    except Exception:
        return os.path.abspath(os.getcwd())


def _musicclip_settings_path() -> str:
    """Visible, portable settings file for Music Clip Creator."""
    return os.path.join(_musicclip_project_root(), "presets", "setsave", "musicclip_creator_settings.json")


def _musicclip_read_json_file(path: str) -> Dict[str, Any]:
    try:
        if not path or not os.path.isfile(path):
            return {}
        with open(path, "r", encoding="utf-8") as f:
            data = json.load(f)
        return data if isinstance(data, dict) else {}
    except Exception:
        return {}


def _musicclip_write_json_file(path: str, data: Dict[str, Any]) -> None:
    try:
        os.makedirs(os.path.dirname(path), exist_ok=True)
        tmp = path + ".tmp"
        with open(tmp, "w", encoding="utf-8") as f:
            json.dump(data if isinstance(data, dict) else {}, f, indent=2, ensure_ascii=False)
        os.replace(tmp, path)
    except Exception:
        pass


def _musicclip_coerce_bool(value: Any, default: bool = False) -> bool:
    if value is None:
        return bool(default)
    if isinstance(value, bool):
        return value
    if isinstance(value, (int, float)):
        return bool(value)
    text = str(value).strip().lower()
    if text in ("1", "true", "yes", "on", "checked"):
        return True
    if text in ("0", "false", "no", "off", "unchecked"):
        return False
    return bool(default)


def _musicclip_text_looks_like_path(value: Any) -> bool:
    """Return True when text is clearly a file/folder path, not a creative prompt.

    Used only to protect Planner Bridge creative text boxes from old corrupted
    settings where audio_path/video_path/output_path were accidentally saved
    into main_idea/style/characters fields.
    """
    try:
        s = str(value or "").strip().strip('"').strip("'")
    except Exception:
        return False
    if not s:
        return False
    low = s.lower().replace("\\", "/")
    if re.match(r"^[a-z]:/", low):
        return True
    if low.startswith(("/", "./", "../", "~/")):
        return True
    if "/" in low and any(tok in low for tok in ("output/", "outputs", "framevision", "wangp", "videoclips", "audio/", "presets/", "models/")):
        return True
    if re.search(r"\.(mp3|wav|flac|m4a|ogg|mp4|mov|mkv|avi|webm|srt|json)$", low):
        return True
    return False


class _MusicClipJsonSettings:
    """Tiny project-folder JSON settings store with a Qt-like value/setValue API.

    This keeps Music Clip Creator portable: settings live in FrameVision/presets/setsave
    instead of an invisible operating-system store.
    """

    def __init__(self, path: Optional[str] = None):
        self.path = str(path or _musicclip_settings_path())
        self._data: Dict[str, Any] = _musicclip_read_json_file(self.path)
        self._dirty = False

    def get(self, key: str, default: Any = None, type: Any = None) -> Any:
        value = self._data.get(str(key), default)
        if value is None:
            return default
        try:
            if type is bool:
                return _musicclip_coerce_bool(value, bool(default))
            if type is str:
                return str(value)
            if type is int:
                return int(float(value))
            if type is float:
                return float(value)
        except Exception:
            return default
        return value

    def set(self, key: str, value: Any) -> None:
        if isinstance(value, Path):
            value = str(value)
        self._data[str(key)] = value
        self._dirty = True

    def clear(self) -> None:
        self._data = {}
        self._dirty = True

    def contains(self, key: str) -> bool:
        return str(key) in self._data

    def remove(self, key: str) -> None:
        k = str(key)
        if k in self._data:
            del self._data[k]
            self._dirty = True

    def sync(self) -> None:
        if self._dirty:
            _musicclip_write_json_file(self.path, self._data)
            self._dirty = False


def _load_musicclip_bridge_file(filename: str, module_name: str):
    """Best-effort optional import for a private Music Clip Creator LTX bridge file.

    The public Music Clip Creator must never depend on these private bridge files.
    If a helper is missing or broken, its matching workflow option stays hidden and
    normal rendering/queue behavior continues unchanged.
    """
    try:
        here = os.path.dirname(os.path.abspath(__file__))
        bridge_path = os.path.join(here, str(filename or ""))
        if not os.path.isfile(bridge_path):
            return None
        spec = importlib.util.spec_from_file_location(str(module_name or "_framevision_musicclip_bridge"), bridge_path)
        if spec is None or spec.loader is None:
            return None
        mod = importlib.util.module_from_spec(spec)
        spec.loader.exec_module(mod)
        is_available = getattr(mod, "is_available", None)
        required = (
            "export_musicclip_scene_plan",
            "create_prompt_plan",
            "create_ltx_shot_plan",
            "create_ltx_director_plan",
        )
        if not callable(is_available):
            return None
        for name in required:
            if not callable(getattr(mod, name, None)):
                return None
        if not bool(is_available()):
            return None
        return mod
    except BaseException:
        return None


# ---------------------------- Krea 2 LTX start-image bridge ----------------

def _musicclip_krea2_is_mode(payload: dict) -> bool:
    model = str((payload or {}).get("image_model") or (payload or {}).get("image_mode") or "").strip().lower()
    return model in ("krea2", "krea_2", "krea-2")


def _musicclip_krea2_path(root_dir: str, value: str) -> Path:
    root = Path(str(root_dir or _musicclip_project_root())).resolve()
    p = Path(str(value or "").strip().strip('"'))
    return p if p.is_absolute() else (root / p).resolve()


def _musicclip_krea2_settings(root_dir: str) -> dict:
    try:
        p = Path(str(root_dir or _musicclip_project_root())).resolve() / "presets" / "setsave" / "krea2.json"
        if p.is_file():
            data = json.loads(p.read_text(encoding="utf-8"))
            return data if isinstance(data, dict) else {}
    except Exception:
        pass
    return {}


def _musicclip_krea2_first_gguf(root_dir: str, llm: bool = False) -> str:
    try:
        root = Path(str(root_dir or _musicclip_project_root())).resolve()
        files = sorted((root / "models" / "krea2").glob("*.gguf"), key=lambda p: ("turbo" not in p.name.lower(), p.name.lower()))
        for f in files:
            low = f.name.lower()
            if llm:
                if "qwen" in low and ("vl" in low or "vision" in low):
                    return str(f)
            elif "krea" in low:
                return str(f)
    except Exception:
        pass
    return ""


def _musicclip_krea2_files(root_dir: str) -> tuple[dict, list[str]]:
    root = str(root_dir or _musicclip_project_root())
    s = _musicclip_krea2_settings(root)
    paths = {
        "sd_cli": _musicclip_krea2_path(root, str(s.get("sdcli") or "presets/bin/sd-cli.exe")),
        "model": _musicclip_krea2_path(root, str(s.get("model") or _musicclip_krea2_first_gguf(root, False))),
        "llm": _musicclip_krea2_path(root, str(s.get("llm") or _musicclip_krea2_first_gguf(root, True))),
        "vae": _musicclip_krea2_path(root, str(s.get("vae") or "models/krea2/wan_2.1_vae.safetensors")),
        "output_dir": _musicclip_krea2_path(root, str(s.get("output_dir") or "output/images/krea2")),
    }
    labels = {"sd_cli": "sd-cli", "model": "Krea 2 GGUF", "llm": "Krea 2 Qwen3VL text encoder", "vae": "Krea 2 VAE"}
    missing = [f"{labels[k]}: {v}" for k, v in paths.items() if k in labels and (not v or not Path(v).is_file())]
    return {"settings": s, "paths": paths}, missing


def _musicclip_krea2_resolution(payload: dict) -> tuple[int, int]:
    raw = str((payload or {}).get("resolution") or (payload or {}).get("ltx_resolution") or "").lower()
    if "704x1280" in raw or raw in ("portrait", "9:16"):
        return 704, 1280
    if "704x704" in raw or raw in ("square", "1:1"):
        return 704, 704
    m = re.search(r"(\d+)\s*[x×]\s*(\d+)", raw)
    if m:
        return int(m.group(1)), int(m.group(2))
    return 1280, 704


def _musicclip_krea2_find_output(path_text: str) -> str:
    p = Path(str(path_text or ""))
    if "%" not in str(p):
        return str(p) if p.is_file() else ""
    matches = sorted(p.parent.glob(p.name.split("%")[0] + "*.png"), key=lambda x: x.stat().st_mtime, reverse=True)
    return str(matches[0]) if matches else ""


def _musicclip_krea2_shots(plan_data: dict) -> list[dict]:
    for key in ("shots", "ltx_shots", "director_shots", "items"):
        val = plan_data.get(key) if isinstance(plan_data, dict) else None
        if isinstance(val, list):
            return [x for x in val if isinstance(x, dict)]
    return []


def _musicclip_krea2_shot_id(shot: dict, index: int) -> str:
    for key in ("id", "shot_id", "ltx_id", "name"):
        val = str((shot or {}).get(key) or "").strip()
        if val:
            return val
    return f"LTX{index + 1:02d}"


def _musicclip_krea2_prompt(shot: dict) -> str:
    for key in ("director_image_prompt", "image_prompt", "start_image_prompt", "visual_prompt", "director_visual_prompt", "scene_image_prompt", "prompt"):
        val = str((shot or {}).get(key) or "").strip()
        if val:
            return val
    bits = [str((shot or {}).get(k) or "").strip() for k in ("scene_role_summary", "microclip_style", "title", "description")]
    bits = [b for b in bits if b]
    return ", ".join(bits) if bits else "cinematic music video start image, sharp, detailed"


def _musicclip_krea2_review_paths(plan_path: str) -> tuple[str, str]:
    """Return the shared review image folder and canonical review-state file.

    Older Krea 2 builds wrote a private state file inside ltx_review_current.
    The review tab reads musicclip_ltx_review_state.json next to the director
    plan, so Krea 2 must write the same file or previously generated images
    look missing when an old job is loaded.
    """
    pp = Path(str(plan_path or _musicclip_project_root())).resolve()
    review_dir = pp.parent / "ltx_review_current"
    return str(review_dir), str(pp.parent / "musicclip_ltx_review_state.json")


def _musicclip_krea2_legacy_state_path(plan_path: str) -> str:
    try:
        pp = Path(str(plan_path or _musicclip_project_root())).resolve()
        return str(pp.parent / "ltx_review_current" / "ltx_review_state.json")
    except Exception:
        return ""


def _musicclip_krea2_read_state(plan_path: str) -> dict:
    merged = {}
    for state_path in (_musicclip_krea2_legacy_state_path(plan_path), _musicclip_krea2_review_paths(plan_path)[1]):
        try:
            if state_path and os.path.isfile(state_path):
                data = json.loads(Path(state_path).read_text(encoding="utf-8"))
                if isinstance(data, dict):
                    # Preserve canonical keys when both files exist, but merge
                    # older Krea-only shot paths so old jobs recover cleanly.
                    if not merged:
                        merged = data
                    else:
                        merged.setdefault("shots", {})
                        for sid, item in (data.get("shots") or {}).items():
                            if isinstance(item, dict):
                                cur = merged["shots"].setdefault(sid, {})
                                if isinstance(cur, dict):
                                    for k, v in item.items():
                                        cur.setdefault(k, v)
        except Exception:
            pass
    return merged if isinstance(merged, dict) else {}


def _musicclip_krea2_write_state(plan_path: str, state: dict) -> None:
    try:
        review_dir, state_path = _musicclip_krea2_review_paths(plan_path)
        os.makedirs(review_dir, exist_ok=True)
        if not isinstance(state, dict):
            state = {}
        state.setdefault("shots", {})
        state["updated_at"] = datetime.now().isoformat(timespec="seconds")
        state["director_plan_path"] = str(plan_path or "")
        state.setdefault("review_dir", review_dir)
        text = json.dumps(state, indent=2, ensure_ascii=False)
        Path(state_path).write_text(text, encoding="utf-8")
        # Keep the old location in sync so rollback builds do not lose review data.
        legacy = _musicclip_krea2_legacy_state_path(plan_path)
        if legacy and legacy != state_path:
            Path(legacy).parent.mkdir(parents=True, exist_ok=True)
            Path(legacy).write_text(text, encoding="utf-8")
    except Exception:
        pass


def _musicclip_generate_krea2_start_image(payload: dict) -> dict:
    payload = dict(payload or {})
    root = str(payload.get("root_dir") or _musicclip_project_root())
    info, missing = _musicclip_krea2_files(root)
    if missing:
        return {"ok": False, "message": "Missing Krea 2 file(s):\n" + "\n".join(missing)}
    s, paths = info["settings"], info["paths"]
    prompt = str(payload.get("image_prompt_override") or payload.get("image_prompt") or "cinematic music video start image, sharp, detailed").strip()
    seed = payload.get("seed", -1)
    try: seed = int(seed) if seed not in (None, "") else -1
    except Exception: seed = -1
    w, h = _musicclip_krea2_resolution(payload)
    out_dir = Path(str(payload.get("output_dir") or paths["output_dir"]))
    if not out_dir.is_absolute(): out_dir = Path(root) / out_dir
    out_dir.mkdir(parents=True, exist_ok=True)
    shot_id = re.sub(r"[^A-Za-z0-9_.-]+", "_", str(payload.get("shot_id") or "ltx")).strip("._") or "ltx"
    name = str(payload.get("start_image_name") or f"{shot_id}_krea2_start.png")
    output_path = out_dir / name
    if output_path.suffix.lower() != ".png": output_path = output_path.with_suffix(".png")
    is_turbo = "turbo" in str(paths["model"]).lower()
    steps = int(s.get("steps", 8 if is_turbo else 30) or (8 if is_turbo else 30))
    cfg = float(s.get("cfg", 1.0 if is_turbo else 3.0) or (1.0 if is_turbo else 3.0))
    guidance = float(s.get("guidance", 3.5) or 3.5)
    cmd = [str(paths["sd_cli"]), "--diffusion-model", str(paths["model"]), "--llm", str(paths["llm"]), "--vae", str(paths["vae"]), "-p", prompt, "--steps", str(steps), "--cfg-scale", str(cfg), "--guidance", str(guidance), "--width", str(w), "--height", str(h), "--seed", str(seed), "--batch-count", "1", "--output", str(output_path)]
    neg = str(s.get("negative") or "").strip()
    if neg: cmd += ["--negative-prompt", neg]
    try:
        flow = float(s.get("flow_shift", 1.15))
        if flow >= 0: cmd += ["--flow-shift", str(flow)]
    except Exception: pass
    if bool(s.get("diffusion_fa", True)): cmd.append("--diffusion-fa")
    if bool(s.get("offload", False)): cmd.append("--offload-to-cpu")
    if bool(s.get("vae_tiling", False)): cmd.append("--vae-tiling")
    if bool(s.get("disable_metadata", False)): cmd.append("--disable-image-metadata")
    for key, flag in (("backend", "--backend"), ("params_backend", "--params-backend")):
        val = str(s.get(key) or "").strip()
        if val: cmd += [flag, val]
    sampler = str(s.get("sampler", "euler") or "euler")
    scheduler = str(s.get("scheduler", "auto") or "auto")
    if sampler and sampler != "auto": cmd += ["--sampling-method", sampler]
    if scheduler and scheduler != "auto": cmd += ["--scheduler", scheduler]
    extra = str(s.get("extra_args") or "").strip()
    if extra: cmd += extra.split()
    if bool(s.get("verbose", True)): cmd.append("-v")
    cb = payload.get("progress_callback")
    def emit(msg):
        if callable(cb):
            try: cb(str(msg))
            except Exception: pass
    emit("Krea 2: running sd-cli start-image generation...")
    log_path = out_dir / str(payload.get("start_image_log_name") or f"{shot_id}_krea2_imagegen.log.txt")
    try:
        with open(log_path, "w", encoding="utf-8", errors="ignore") as logf:
            logf.write("Command:\n" + " ".join('"'+c+'"' if " " in c else c for c in cmd) + "\n\n")
            proc = subprocess.Popen(cmd, cwd=root, stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, encoding="utf-8", errors="replace")
            assert proc.stdout is not None
            for line in proc.stdout:
                logf.write(line)
                if line.strip(): emit("[Krea 2] " + line.strip()[:240])
            code = proc.wait()
        if code != 0:
            return {"ok": False, "message": f"Krea 2 sd-cli failed with exit code {code}. Log: {log_path}"}
    except Exception as exc:
        return {"ok": False, "message": f"Krea 2 image generation failed: {exc}"}
    start_path = _musicclip_krea2_find_output(str(output_path))
    if not start_path:
        return {"ok": False, "message": f"Krea 2 sd-cli finished but no output image was found: {output_path}"}
    try:
        payload_name = str(payload.get("start_image_payload_name") or f"{shot_id}_krea2_start_image_payload.json")
        (out_dir / payload_name).write_text(json.dumps({"image_model": "krea2", "prompt": prompt, "seed": seed, "width": w, "height": h, "command": cmd, "start_image_path": start_path}, indent=2, ensure_ascii=False), encoding="utf-8")
    except Exception: pass
    return {"ok": True, "start_image_path": start_path, "seed": seed, "image_model": "krea2", "message": "Krea 2 start image ready."}


def _musicclip_prepare_krea2_full_run_payload(payload: dict) -> dict:
    payload = dict(payload or {})
    plan_path = str(payload.get("ltx_director_plan_path") or "").strip()
    if not plan_path or not os.path.isfile(plan_path): return {"ok": False, "message": f"LTX director plan was not found: {plan_path or '[empty]'}"}
    try: plan_data = json.loads(Path(plan_path).read_text(encoding="utf-8"))
    except Exception as exc: return {"ok": False, "message": f"Could not read LTX director plan for Krea 2 full run: {exc}"}
    shots = _musicclip_krea2_shots(plan_data)
    if not shots: return {"ok": False, "message": "LTX director plan has no shots for Krea 2 full run."}
    progress = payload.get("progress_callback")
    def emit(msg):
        if callable(progress):
            try: progress(str(msg))
            except Exception: pass
    review_dir, state_path = _musicclip_krea2_review_paths(plan_path)
    state = _musicclip_krea2_read_state(plan_path)
    shots_state = state.setdefault("shots", {}) if isinstance(state, dict) else {}
    if not isinstance(shots_state, dict): shots_state = {}; state["shots"] = shots_state
    generated = updated = 0
    for idx, shot in enumerate(shots):
        sid = _musicclip_krea2_shot_id(shot, idx)
        item = shots_state.get(sid) if isinstance(shots_state.get(sid), dict) else {}
        shots_state[sid] = item
        start_path = str(item.get("current_start_image_path") or shot.get("current_start_image_path") or shot.get("start_image_path") or "").strip()
        if not (start_path and os.path.isfile(start_path)):
            emit(f"Krea 2: generating start image {idx+1}/{len(shots)} ({sid})...")
            stem = re.sub(r"[^A-Za-z0-9_.-]+", "_", sid).strip("._") or f"LTX{idx+1:02d}"
            result = _musicclip_generate_krea2_start_image({"root_dir": payload.get("root_dir") or _musicclip_project_root(), "ltx_director_plan_path": plan_path, "shot_id": sid, "image_model": "krea2", "image_prompt_override": _musicclip_krea2_prompt(shot), "seed": item.get("image_seed", payload.get("seed", -1)), "output_dir": review_dir, "start_image_name": f"{stem}_krea2_start.png", "start_image_payload_name": f"{stem}_krea2_start_image_payload.json", "start_image_log_name": f"{stem}_krea2_imagegen.log.txt", "progress_callback": progress, "resolution": payload.get("resolution") or payload.get("ltx_resolution") or ""})
            if not isinstance(result, dict) or not result.get("ok"):
                return {"ok": False, "message": str(result.get("message") if isinstance(result, dict) else f"Krea 2 start image failed for {sid}")}
            start_path = str(result.get("start_image_path") or "")
            item["last_image_result"] = result
            generated += 1
        item.update({"status": "Image ready - clip needs recreate", "image_prompt": _musicclip_krea2_prompt(shot), "current_start_image_path": start_path, "clip_invalidated_by_new_image": True})
        shot["start_image_path"] = shot["current_start_image_path"] = shot["existing_start_image_path"] = start_path
        shot["image_mode"] = "existing"
        updated += 1
    _musicclip_krea2_write_state(plan_path, state)
    temp_plan = copy.deepcopy(plan_data)
    for idx, shot in enumerate(_musicclip_krea2_shots(temp_plan)):
        sid = _musicclip_krea2_shot_id(shot, idx)
        item = shots_state.get(sid) or {}
        sp = str(item.get("current_start_image_path") or "")
        if sp:
            shot["start_image_path"] = shot["current_start_image_path"] = shot["existing_start_image_path"] = sp
            shot["image_mode"] = "existing"
    temp_path = Path(plan_path).resolve().parent / "musicclip_ltx_director_plan_krea2_prepared.json"
    temp_path.write_text(json.dumps(temp_plan, indent=2, ensure_ascii=False), encoding="utf-8")
    new_payload = dict(payload)
    new_payload.update({"image_mode": "existing", "image_model": "existing", "ltx_director_plan_path": str(temp_path), "krea2_prepared_from_plan": plan_path, "use_review_current_images": True, "review_state_path": state_path})
    emit(f"Krea 2: prepared {updated} start image(s), generated {generated} new image(s). Continuing LTX with existing start images...")
    return {"ok": True, "payload": new_payload}


def _musicclip_prepare_krea2_single_payload(payload: dict) -> dict:
    payload = dict(payload or {})
    if not _musicclip_krea2_is_mode(payload): return {"ok": True, "payload": payload}
    plan_path = str(payload.get("ltx_director_plan_path") or "")
    shot_id = str(payload.get("shot_id") or "LTX")
    prompt = str(payload.get("image_prompt_override") or payload.get("image_prompt") or "").strip()
    if not prompt and plan_path and os.path.isfile(plan_path):
        try:
            data = json.loads(Path(plan_path).read_text(encoding="utf-8"))
            for idx, shot in enumerate(_musicclip_krea2_shots(data)):
                if _musicclip_krea2_shot_id(shot, idx) == shot_id:
                    prompt = _musicclip_krea2_prompt(shot); break
        except Exception: pass
    review_dir, _state = _musicclip_krea2_review_paths(plan_path)
    stem = re.sub(r"[^A-Za-z0-9_.-]+", "_", shot_id).strip("._") or "LTX"
    res = _musicclip_generate_krea2_start_image({"root_dir": payload.get("root_dir") or _musicclip_project_root(), "ltx_director_plan_path": plan_path, "shot_id": shot_id, "image_model": "krea2", "image_prompt_override": prompt, "seed": payload.get("seed", -1), "output_dir": review_dir, "start_image_name": f"{stem}_krea2_start.png", "start_image_log_name": f"{stem}_krea2_imagegen.log.txt", "progress_callback": payload.get("progress_callback"), "resolution": payload.get("resolution") or payload.get("ltx_resolution") or ""})
    if not isinstance(res, dict) or not res.get("ok"):
        return {"ok": False, "message": str(res.get("message") if isinstance(res, dict) else "Krea 2 start image failed.")}
    new_payload = dict(payload)
    new_payload.update({"image_mode": "existing", "image_model": "existing", "existing_start_image_path": str(res.get("start_image_path") or "")})
    return {"ok": True, "payload": new_payload, "image_result": res}




# ---------------------------- LTX hard duration guard -----------------------

def _musicclip_ltx_hard_cap_seconds_from_payload(payload: dict) -> float:
    """Return the effective hard max shot duration for LTX-VRAMLab plans.

    The bridge files are optional and can change independently from this UI file,
    so the UI enforces the 241-frame / 10-second limit again after a bridge writes
    the shot/director JSON. This prevents a stale or LLM-cleaned plan from putting
    a 14s item back into the LTX shot list while the generator can only create the
    first 10s of it.
    """
    try:
        payload = dict(payload or {})
    except Exception:
        payload = {}
    settings = payload.get("bridge_generation_settings")
    if not isinstance(settings, dict):
        settings = {}
    backend = str(settings.get("ltx_backend") or payload.get("ltx_backend") or payload.get("generation_backend") or "").strip().lower()
    has_vramlab_limit = backend == "vramlab" or settings.get("ltx_max_generation_frames") or settings.get("hard_max_ltx_shot_seconds") or settings.get("ltx_max_generation_seconds")
    if not has_vramlab_limit:
        return 0.0
    for key in ("hard_max_ltx_shot_seconds", "ltx_max_generation_seconds", "max_ltx_shot_seconds"):
        try:
            v = float(settings.get(key) or payload.get(key) or 0.0)
            if v > 0.05:
                return max(0.5, min(10.0, v))
        except Exception:
            pass
    return 10.0


def _musicclip_ltx_shot_list_ref(plan: dict):
    if not isinstance(plan, dict):
        return None, ""
    for key in ("shots", "ltx_shots", "director_shots", "items"):
        shots = plan.get(key)
        if isinstance(shots, list):
            return shots, key
    return None, ""


def _musicclip_ltx_float(value: Any, default: float = 0.0) -> float:
    try:
        if value is None or value == "":
            return float(default)
        return float(value)
    except Exception:
        return float(default)


def _musicclip_ltx_read_timing(shot: dict) -> tuple[float, float, float]:
    if not isinstance(shot, dict):
        return 0.0, 0.0, 0.0
    start = None
    end = None
    for key in ("song_start", "start", "start_time", "t_start", "time_start"):
        if key in shot:
            start = _musicclip_ltx_float(shot.get(key), 0.0)
            break
    for key in ("song_end", "end", "end_time", "t_end", "time_end"):
        if key in shot:
            end = _musicclip_ltx_float(shot.get(key), 0.0)
            break
    dur = 0.0
    for key in ("duration", "duration_seconds", "clip_duration", "shot_duration", "length_seconds"):
        if key in shot:
            dur = _musicclip_ltx_float(shot.get(key), 0.0)
            break
    if start is None:
        start = 0.0
    if end is None or end <= start:
        end = start + dur if dur > 0.0 else start
    if dur <= 0.0 and end > start:
        dur = end - start
    return float(start), float(end), max(0.0, float(dur))


def _musicclip_ltx_write_timing(shot: dict, start: float, end: float) -> None:
    if not isinstance(shot, dict):
        return
    start = max(0.0, float(start))
    end = max(start, float(end))
    dur = max(0.0, end - start)
    for key in ("song_start", "start", "start_time", "t_start", "time_start"):
        if key in shot:
            shot[key] = float(start)
    for key in ("song_end", "end", "end_time", "t_end", "time_end"):
        if key in shot:
            shot[key] = float(end)
    if not any(k in shot for k in ("song_start", "start", "start_time", "t_start", "time_start")):
        shot["song_start"] = float(start)
    if not any(k in shot for k in ("song_end", "end", "end_time", "t_end", "time_end")):
        shot["song_end"] = float(end)
    for key in ("duration", "duration_seconds", "clip_duration", "shot_duration", "length_seconds"):
        if key in shot:
            shot[key] = float(dur)
    if not any(k in shot for k in ("duration", "duration_seconds", "clip_duration", "shot_duration", "length_seconds")):
        shot["duration"] = float(dur)


def _musicclip_ltx_sanitize_plan_file(plan_path: str, payload: dict, label: str = "LTX plan") -> dict:
    """Split over-cap LTX shots in an already-written JSON plan.

    Returns a small report. It is intentionally conservative: it only runs when
    the payload/settings indicate the LTX-VRAMLab 241-frame limit. It rewrites the
    same JSON file atomically and keeps all creative prompt fields from the source
    shot on each split segment.
    """
    cap = _musicclip_ltx_hard_cap_seconds_from_payload(payload)
    if cap <= 0.05:
        return {"changed": False, "split_count": 0, "cap_seconds": 0.0, "message": "no hard cap active"}
    try:
        path = str(plan_path or "").strip()
        if not path or not os.path.isfile(path):
            return {"changed": False, "split_count": 0, "cap_seconds": cap, "message": "plan not found"}
        with open(path, "r", encoding="utf-8") as f:
            plan = json.load(f)
        if not isinstance(plan, dict):
            return {"changed": False, "split_count": 0, "cap_seconds": cap, "message": "plan is not an object"}
        shots, key = _musicclip_ltx_shot_list_ref(plan)
        if not isinstance(shots, list) or not shots:
            return {"changed": False, "split_count": 0, "cap_seconds": cap, "message": "no shots"}

        new_shots = []
        split_count = 0
        max_seen = 0.0
        eps = 0.035
        for shot in shots:
            if not isinstance(shot, dict):
                new_shots.append(shot)
                continue
            start, end, dur = _musicclip_ltx_read_timing(shot)
            if dur <= 0.0 and end > start:
                dur = end - start
            max_seen = max(max_seen, dur)
            if dur <= cap + eps:
                new_shots.append(shot)
                continue
            pieces = max(2, int(math.ceil(dur / cap)))
            piece_len = dur / float(pieces)
            # Keep every part at or below the hard cap even with rounding.
            if piece_len > cap:
                pieces += 1
                piece_len = dur / float(pieces)
            original_id = str(shot.get("id") or shot.get("shot_id") or "LTX").strip() or "LTX"
            for pi in range(pieces):
                a = start + (dur * pi / float(pieces))
                b = start + (dur * (pi + 1) / float(pieces))
                part = copy.deepcopy(shot)
                _musicclip_ltx_write_timing(part, a, b)
                part["source_ltx_shot_id"] = original_id
                part["split_from_overlong_ltx_shot"] = True
                part["split_part"] = int(pi + 1)
                part["split_parts"] = int(pieces)
                new_shots.append(part)
            split_count += 1

        if split_count <= 0:
            return {"changed": False, "split_count": 0, "cap_seconds": cap, "max_seen_seconds": max_seen, "message": "already within cap"}

        # Renumber LTX ids after splitting, so UI labels, output stems and review
        # state stay unique and ordered.
        for idx, shot in enumerate(new_shots, start=1):
            if isinstance(shot, dict):
                sid = f"LTX{idx:02d}"
                shot["id"] = sid
                if "shot_id" in shot:
                    shot["shot_id"] = sid
        plan[key] = new_shots
        for count_key in ("ltx_shot_count", "shot_count", "director_shot_count"):
            if count_key in plan:
                plan[count_key] = int(len(new_shots))
        notes = plan.get("warnings")
        if not isinstance(notes, list):
            notes = []
        notes.append(f"{label}: split {split_count} over-10s LTX shot(s) for LTX-VRAMLab 241-frame limit.")
        plan["warnings"] = notes
        tmp = path + ".tmp"
        with open(tmp, "w", encoding="utf-8") as f:
            json.dump(plan, f, indent=2, ensure_ascii=False)
        os.replace(tmp, path)
        return {"changed": True, "split_count": split_count, "cap_seconds": cap, "shot_count": len(new_shots), "message": f"split {split_count} over-cap shot(s)"}
    except Exception as exc:
        return {"changed": False, "split_count": 0, "cap_seconds": cap, "message": str(exc)}



def _musicclip_ltx_audio_exts() -> set[str]:
    return {".wav", ".mp3", ".flac", ".m4a", ".ogg", ".aac"}


def _musicclip_ltx_find_audio_path(obj: Any) -> str:
    """Best-effort source-song finder for LTX audio chunk regeneration."""
    seen: set[int] = set()

    def _check_path(value: Any) -> str:
        try:
            text = str(value or "").strip().strip('"').strip("'")
        except Exception:
            return ""
        if not text:
            return ""
        try:
            path = os.path.abspath(os.path.expanduser(text))
        except Exception:
            path = text
        try:
            if os.path.isfile(path) and Path(path).suffix.lower() in _musicclip_ltx_audio_exts():
                return path
        except Exception:
            return ""
        return ""

    def _walk(value: Any, depth: int = 0) -> str:
        if depth > 8:
            return ""
        try:
            oid = id(value)
            if oid in seen:
                return ""
            seen.add(oid)
        except Exception:
            pass
        direct = _check_path(value)
        if direct:
            return direct
        if isinstance(value, dict):
            # Prefer explicit source/full-song keys over per-shot generated chunk keys.
            priority = []
            for k in value.keys():
                lk = str(k).lower()
                if any(tok in lk for tok in ("source_audio", "full_song", "music_file", "music_path", "song_path", "audio_path", "media_path")) and "chunk" not in lk:
                    priority.append(k)
            for k in priority:
                found = _walk(value.get(k), depth + 1)
                if found:
                    return found
            for k, v in value.items():
                lk = str(k).lower()
                if "chunk" in lk or "output" in lk:
                    continue
                found = _walk(v, depth + 1)
                if found:
                    return found
        elif isinstance(value, (list, tuple)):
            for item in value:
                found = _walk(item, depth + 1)
                if found:
                    return found
        return ""

    return _walk(obj)


def _musicclip_ltx_load_json_if_file(path: str) -> Any:
    try:
        p = str(path or "").strip()
        if p and os.path.isfile(p) and Path(p).suffix.lower() == ".json":
            with open(p, "r", encoding="utf-8") as f:
                return json.load(f)
    except Exception:
        pass
    return None


def _musicclip_ltx_regenerate_audio_chunks_for_plan(plan_path: str, payload: dict, label: str = "LTX plan") -> dict:
    """Regenerate audio_chunks/LTXxx.wav after the duration guard splits shots.

    The private bridge can export WAV chunks before this UI-side hard guard runs.
    When an overlong shot is split here, the old WAV files no longer match the new
    LTX IDs/timings. This pass rewrites the chunks from the original song so LTX01,
    LTX02, etc. stay aligned with the sanitized plan.
    """
    try:
        if not bool((payload or {}).get("export_audio_chunks", True)):
            return {"ok": True, "changed": False, "message": "audio chunk export disabled"}
        path = str(plan_path or "").strip()
        if not path or not os.path.isfile(path):
            return {"ok": False, "changed": False, "message": "plan not found"}
        with open(path, "r", encoding="utf-8") as f:
            plan = json.load(f)
        if not isinstance(plan, dict):
            return {"ok": False, "changed": False, "message": "plan is not an object"}
        shots, _key = _musicclip_ltx_shot_list_ref(plan)
        if not isinstance(shots, list) or not shots:
            return {"ok": True, "changed": False, "message": "no shots"}

        search_blobs: list[Any] = [payload, plan]
        for key in ("scene_plan_path", "prompt_plan_path", "ltx_shot_plan_path", "ltx_director_plan_path", "director_plan_path", "shot_plan_path", "plan_path"):
            try:
                val = (payload or {}).get(key) or plan.get(key)
            except Exception:
                val = ""
            loaded = _musicclip_ltx_load_json_if_file(str(val or ""))
            if loaded is not None:
                search_blobs.append(loaded)
        audio_path = ""
        for blob in search_blobs:
            audio_path = _musicclip_ltx_find_audio_path(blob)
            if audio_path:
                break
        if not audio_path:
            return {"ok": False, "changed": False, "message": "source audio not found"}

        out_dir = ""
        for key in ("audio_chunks_dir", "ltx_audio_chunks_dir", "audio_chunk_dir"):
            try:
                cand = str(plan.get(key) or (payload or {}).get(key) or "").strip()
            except Exception:
                cand = ""
            if cand:
                out_dir = cand
                break
        if not out_dir:
            out_dir = os.path.join(os.path.dirname(path), "audio_chunks")
        os.makedirs(out_dir, exist_ok=True)

        ffmpeg = str((payload or {}).get("ffmpeg") or "").strip() or _find_ffmpeg_from_env()
        # Remove stale LTX chunk names first; after splitting, every later number can shift.
        try:
            for old in Path(out_dir).glob("LTX*.wav"):
                try:
                    old.unlink()
                except Exception:
                    pass
        except Exception:
            pass

        exported = 0
        changed_plan = False
        for idx, shot in enumerate(shots, start=1):
            if not isinstance(shot, dict):
                continue
            start, end, dur = _musicclip_ltx_read_timing(shot)
            if dur <= 0.03:
                continue
            sid = str(shot.get("id") or shot.get("shot_id") or f"LTX{idx:02d}").strip() or f"LTX{idx:02d}"
            safe_sid = re.sub(r"[^A-Za-z0-9_\-]+", "_", sid) or f"LTX{idx:02d}"
            out_wav = os.path.join(out_dir, f"{safe_sid}.wav")
            cmd = [
                ffmpeg,
                "-y",
                "-hide_banner",
                "-loglevel",
                "error",
                "-ss",
                f"{max(0.0, start):.6f}",
                "-t",
                f"{max(0.03, dur):.6f}",
                "-i",
                audio_path,
                "-vn",
                "-ac",
                "2",
                "-ar",
                "44100",
                "-c:a",
                "pcm_s16le",
                out_wav,
            ]
            proc = subprocess.run(cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True)
            if proc.returncode != 0 or not os.path.isfile(out_wav):
                return {"ok": False, "changed": exported > 0, "message": f"ffmpeg failed while exporting {safe_sid}.wav: {(proc.stderr or proc.stdout or '').strip()}"}
            shot["audio_chunk_path"] = out_wav
            shot["ltx_audio_chunk_path"] = out_wav
            changed_plan = True
            exported += 1

        if changed_plan:
            plan["audio_chunks_dir"] = out_dir
            tmp = path + ".tmp"
            with open(tmp, "w", encoding="utf-8") as f:
                json.dump(plan, f, indent=2, ensure_ascii=False)
            os.replace(tmp, path)
        return {"ok": True, "changed": exported > 0, "exported": exported, "audio_chunks_dir": out_dir, "message": f"regenerated {exported} audio chunk(s)"}
    except Exception as exc:
        return {"ok": False, "changed": False, "message": str(exc)}

def _musicclip_ltx_apply_sanitize_result(result: dict, payload: dict, path_keys: tuple[str, ...], label: str) -> dict:
    if not isinstance(result, dict) or not bool(result.get("ok")):
        return result
    for key in path_keys:
        path = str(result.get(key) or "").strip()
        if not path:
            continue
        report = _musicclip_ltx_sanitize_plan_file(path, payload, label)
        if report.get("changed"):
            try:
                result["ltx_shot_count"] = int(report.get("shot_count") or result.get("ltx_shot_count") or 0)
            except Exception:
                pass
            warnings = result.get("warnings")
            if not isinstance(warnings, list):
                warnings = []
            warnings.append(str(report.get("message") or "LTX plan duration guard applied."))
            audio_report = _musicclip_ltx_regenerate_audio_chunks_for_plan(path, payload, label)
            result["ltx_audio_chunk_guard_report"] = audio_report
            if audio_report.get("changed"):
                warnings.append(str(audio_report.get("message") or "LTX audio chunks regenerated after duration split."))
            elif not audio_report.get("ok", True):
                warnings.append("LTX plan was split, but audio chunks could not be regenerated: " + str(audio_report.get("message") or "unknown error"))
            result["warnings"] = warnings
            result["ltx_duration_guard_report"] = report
        break
    return result

def _musicclip_patch_krea2_bridge(mod):
    if mod is None or bool(getattr(mod, "_framevision_krea2_ltx_patched", False)): return mod
    try:
        original_create_shot = getattr(mod, "create_ltx_shot_plan", None)
        if callable(original_create_shot):
            def _create_shot(payload):
                result = original_create_shot(payload)
                return _musicclip_ltx_apply_sanitize_result(result, dict(payload or {}), ("ltx_shot_plan_path", "shot_plan_path", "plan_path"), "LTX shot plan")
            setattr(mod, "create_ltx_shot_plan", _create_shot)
        original_create_director = getattr(mod, "create_ltx_director_plan", None)
        if callable(original_create_director):
            def _create_director(payload):
                result = original_create_director(payload)
                return _musicclip_ltx_apply_sanitize_result(result, dict(payload or {}), ("ltx_director_plan_path", "director_plan_path", "plan_path"), "LTX director plan")
            setattr(mod, "create_ltx_director_plan", _create_director)
        original_gen = getattr(mod, "generate_ltx_start_image_for_shot", None)
        if callable(original_gen):
            def _gen(payload):
                if _musicclip_krea2_is_mode(payload or {}): return _musicclip_generate_krea2_start_image(dict(payload or {}))
                return original_gen(payload)
            setattr(mod, "generate_ltx_start_image_for_shot", _gen)
        original_single = getattr(mod, "run_single_ltx_shot_test", None)
        if callable(original_single):
            def _single(payload):
                if _musicclip_krea2_is_mode(payload or {}):
                    prep = _musicclip_prepare_krea2_single_payload(dict(payload or {}))
                    if not prep.get("ok"): return {"ok": False, "message": str(prep.get("message") or "Krea 2 single-shot preparation failed.")}
                    return original_single(dict(prep.get("payload") or {}))
                return original_single(payload)
            setattr(mod, "run_single_ltx_shot_test", _single)
        original_run_all = getattr(mod, "run_all_ltx_director_shots", None)
        if callable(original_run_all):
            def _run_all(payload):
                if _musicclip_krea2_is_mode(payload or {}):
                    prep = _musicclip_prepare_krea2_full_run_payload(dict(payload or {}))
                    if not prep.get("ok"): return {"ok": False, "message": str(prep.get("message") or "Krea 2 full-run preparation failed.")}
                    return original_run_all(dict(prep.get("payload") or {}))
                return original_run_all(payload)
            setattr(mod, "run_all_ltx_director_shots", _run_all)
        setattr(mod, "_framevision_krea2_ltx_patched", True)
    except Exception:
        pass
    return mod



def _load_musicclip_planner_bridge():
    # Original/Wan2GP bridge. Keep this separate so the option can hide again
    # when this file is removed.
    return _musicclip_patch_krea2_bridge(_load_musicclip_bridge_file("musicclip_planner_bridge.py", "_framevision_musicclip_planner_bridge"))


def _load_clip2ltx_bridge():
    # Own LTX-VRAMLab bridge. This is the copy of the original bridge that calls
    # helpers/ltx23_vram_lab_cli.py directly. It must not depend on the Wan2GP bridge.
    return _musicclip_patch_krea2_bridge(_load_musicclip_bridge_file("clip2ltx_cli.py", "_framevision_clip2ltx_bridge"))


def _musicclip_default_llama_runner() -> str:
    """Best-effort portable llama-server lookup for Music Clip Creator LTX.

    Kept local to Music Clip Creator so this workflow no longer has to send new
    users to Planner just to select an own GGUF text model.
    """
    try:
        bin_dir = Path(_musicclip_project_root()) / "presets" / "bin"
        for name in ("llama-server.exe", "llama-server", "server.exe", "server"):
            cand = bin_dir / name
            if cand.is_file():
                return str(cand.resolve())
    except Exception:
        pass
    return ""


def _musicclip_abs_path(root: str, path: str) -> str:
    """Resolve relative FrameVision paths against the project root."""
    p = str(path or "").strip()
    if not p:
        return ""
    try:
        if os.path.isabs(p):
            return os.path.abspath(p)
        return os.path.abspath(os.path.join(str(root or _musicclip_project_root()), p))
    except Exception:
        return p


def _musicclip_whisper_env_python(root: Optional[str] = None) -> str:
    base = str(root or _musicclip_project_root())
    if os.name == "nt":
        return os.path.join(base, "environments", ".whisper", "Scripts", "python.exe")
    return os.path.join(base, "environments", ".whisper", "bin", "python")


def _musicclip_whisper_model_dir(root: Optional[str] = None) -> str:
    return os.path.join(str(root or _musicclip_project_root()), "models", "faster_whisper", "medium")


def _musicclip_default_whisper_output_dir(root: Optional[str] = None) -> str:
    return os.path.join(str(root or _musicclip_project_root()), "output", "whisper")


def _musicclip_temp_dir(root: Optional[str] = None) -> str:
    return os.path.join(str(root or _musicclip_project_root()), "output", "_temp")


def _cine_grid_dims(screen_count: int) -> tuple[int, int]:
    """Return (cols, rows) for 2–9 tiles so the grid cleanly fills the frame.

    We keep it simple and deterministic: every value 2–9 maps to a fixed
    (cols, rows) pair with cols * rows == screen_count, so there are no
    unused "empty" cells in the xstack layout.
    """
    try:
        n = int(screen_count)
    except Exception:
        n = 4
    if n < 2:
        n = 2
    if n > 9:
        n = 9

    layout_map = {
        2: (2, 1),  # two vertical panels
        3: (3, 1),  # three vertical panels
        4: (2, 2),
        5: (5, 1),
        6: (3, 2),
        7: (7, 1),
        8: (4, 2),
        9: (3, 3),
    }
    return layout_map.get(n, (n, 1))


def _cine_grid_layout(screen_count: int, target_w: int, target_h: int):
    """Return per-tile (w, h, x, y) for 2–9 tiles.

    Layouts are tuned so that, for example, 5 ⇒ 3+2 and 7 ⇒ 4+3 rows,
    which keeps the overall grid closer to a cinematic 16:9 aspect ratio
    and avoids the ultra‑wide strip look while still filling the frame.
    """
    try:
        n = int(screen_count)
    except Exception:
        n = 4
    if n < 1:
        n = 1
    if n > 9:
        n = 9

    # Keep targets encoder-friendly (yuv420p / nvenc can be picky),
    # and avoid edge cases where padding ends up 1px smaller than the
    # scaled input due to rounding / SAR.
    try:
        target_w = int(target_w)
        target_h = int(target_h)
    except Exception:
        pass
    if target_w % 2:
        target_w += 1
    if target_h % 2:
        target_h += 1

    def _evenize_sizes(sizes: list[int], total: int) -> list[int]:
        """Make a list of sizes that sum to total, with each entry >= 2 and even."""
        if total % 2:
            total += 1
        if not sizes:
            return sizes
        if len(sizes) == 1:
            v = max(2, int(total))
            if v % 2:
                v += 1
            return [v]

        out = []
        for s in sizes[:-1]:
            v = max(2, int(s))
            if v % 2:
                v -= 1
            v = max(2, v)
            out.append(v)

        last = int(total) - sum(out)
        last = max(2, last)
        # Since total and sum(out) are both even, last should already be even.
        if last % 2:
            last -= 1
            if last < 2:
                last = 2
        out.append(last)

        # Final guard: fix any drift by adjusting the last cell.
        drift = int(total) - sum(out)
        if drift != 0:
            out[-1] = max(2, out[-1] + drift)
            if out[-1] % 2:
                out[-1] += 1
        return out

    # Rows are described as "how many tiles in this row", top to bottom.
    row_patterns = {
        1: [1],
        2: [2],
        3: [3],
        4: [2, 2],
        5: [3, 2],
        6: [3, 3],
        7: [4, 3],
        8: [4, 4],
        9: [3, 3, 3],
    }
    rows_spec = row_patterns.get(n, [n])
    total_rows = len(rows_spec)

    # Split the height evenly between rows, put any remainder on the last row
    # so the stacked rows always fill the frame top‑to‑bottom.
    base_h = max(1, target_h // max(1, total_rows))
    heights = [base_h for _ in range(total_rows)]
    used_h = base_h * total_rows
    remainder_h = target_h - used_h
    if remainder_h != 0 and heights:
        heights[-1] = max(1, heights[-1] + remainder_h)

    heights = _evenize_sizes(heights, target_h)

    layout = []
    y = 0
    idx_tile = 0
    for row_idx, cols_in_row in enumerate(rows_spec):
        if idx_tile >= n:
            break
        h = heights[row_idx]
        cols_in_row = max(1, int(cols_in_row))
        base_w = max(1, target_w // cols_in_row)
        widths = [base_w for _ in range(cols_in_row)]
        used_w = base_w * cols_in_row
        remainder_w = target_w - used_w
        if remainder_w != 0 and widths:
            widths[-1] = max(1, widths[-1] + remainder_w)

        widths = _evenize_sizes(widths, target_w)

        x = 0
        for col in range(cols_in_row):
            if idx_tile >= n:
                break
            w = widths[col]
            layout.append((w, h, x, y))
            x += w
            idx_tile += 1
        y += h

    return layout

def _run_ffmpeg(cmd: List[str]) -> Tuple[int, str]:
    try:
        proc = subprocess.Popen(
            cmd,
            stdout=subprocess.PIPE,
            stderr=subprocess.STDOUT,
            universal_newlines=True,
        )
        out, _ = proc.communicate()
        return proc.returncode, out or ""
    except Exception as e:
        return 1, f"Failed to run ffmpeg: {e!r}"


def _ffprobe_duration(ffprobe: str, path: str) -> Optional[float]:
    cmd = [
        ffprobe,
        "-v",
        "error",
        "-show_entries",
        "format=duration",
        "-of",
        "default=noprint_wrappers=1:nokey=1",
        path,
    ]
    try:
        out = subprocess.check_output(cmd, stderr=subprocess.STDOUT, text=True)
        return float(out.strip())
    except Exception:
        return None



def _ffprobe_resolution(ffprobe: str, path: str) -> Optional[Tuple[int, int]]:
    """Return (width, height) for the first video stream, or None."""
    cmd = [
        ffprobe,
        "-v",
        "error",
        "-select_streams",
        "v:0",
        "-show_entries",
        "stream=width,height",
        "-of",
        "csv=s=x:p=0",
        path,
    ]
    try:
        out = subprocess.check_output(cmd, stderr=subprocess.STDOUT, text=True).strip()
        if not out or "x" not in out:
            return None
        w_s, h_s = out.split("x", 1)
        w = int(float(w_s.strip()))
        h = int(float(h_s.strip()))
        if w > 0 and h > 0:
            return w, h
    except Exception:
        return None
    return None


def _ffprobe_video_bitrate(ffprobe: str, path: str) -> Optional[int]:
    """Return approximate *video* bitrate in bits/sec, or None.

    Tries stream bit_rate, then format bit_rate minus audio, then size/duration estimate.
    """
    cmd = [
        ffprobe,
        "-v",
        "error",
        "-show_entries",
        "format=duration,bit_rate,size:stream=index,codec_type,bit_rate",
        "-of",
        "json",
        path,
    ]
    try:
        raw = subprocess.check_output(cmd, stderr=subprocess.STDOUT, text=True)
        data = json.loads(raw or "{}")
    except Exception:
        return None

    streams = data.get("streams") or []
    fmt = data.get("format") or {}

    def _to_int(v) -> int:
        try:
            if v is None:
                return 0
            s = str(v).strip()
            if not s or s.lower() in ("n/a", "nan"):
                return 0
            return int(float(s))
        except Exception:
            return 0

    def _to_float(v) -> float:
        try:
            if v is None:
                return 0.0
            s = str(v).strip()
            if not s or s.lower() in ("n/a", "nan"):
                return 0.0
            return float(s)
        except Exception:
            return 0.0

    v_br = 0
    a_br = 0
    for st in streams:
        ct = (st.get("codec_type") or "").lower()
        if ct == "video" and v_br <= 0:
            v_br = _to_int(st.get("bit_rate"))
        elif ct == "audio" and a_br <= 0:
            a_br = _to_int(st.get("bit_rate"))

    if v_br > 0:
        return v_br

    fmt_br = _to_int(fmt.get("bit_rate"))
    if fmt_br > 0:
        if a_br > 0 and fmt_br > a_br:
            return int(fmt_br - a_br)
        return fmt_br

    dur = _to_float(fmt.get("duration"))
    size = _to_int(fmt.get("size"))
    if dur > 0.01 and size > 0:
        est_total = int((size * 8) / dur)
        if a_br > 0 and est_total > a_br:
            return int(est_total - a_br)
        return est_total

    return None


def _ffprobe_fps_expr(ffprobe: str, path: str) -> Optional[str]:
    """Return an ffmpeg-friendly FPS expression (e.g. '30000/1001') for v:0, or None."""
    cmd = [
        ffprobe,
        "-v",
        "error",
        "-select_streams",
        "v:0",
        "-show_entries",
        "stream=avg_frame_rate,r_frame_rate",
        "-of",
        "default=noprint_wrappers=1:nokey=0",
        path,
    ]
    try:
        out = subprocess.check_output(cmd, stderr=subprocess.STDOUT, text=True)
    except Exception:
        return None

    avg = None
    rfr = None
    for line in out.splitlines():
        line = line.strip()
        if line.startswith("avg_frame_rate="):
            avg = line.split("=", 1)[1].strip()
        elif line.startswith("r_frame_rate="):
            rfr = line.split("=", 1)[1].strip()

    def _clean(expr: Optional[str]) -> Optional[str]:
        if not expr:
            return None
        expr = expr.strip()
        if expr in ("0/0", "0", "N/A", "nan"):
            return None
        return expr

    avg = _clean(avg)
    rfr = _clean(rfr)
    return avg or rfr

def _ensure_dir(path: str) -> None:
    os.makedirs(path, exist_ok=True)




# ------------------------------------------------------------------
# Filename sanitizers (Windows-safe)
# ------------------------------------------------------------------

_INVALID_FILENAME_CHARS = set('<>:"/\\|?*')

def _sanitize_stem(stem: str, fallback: str = "output") -> str:
    """Return a filesystem-safe filename stem (no extension)."""
    try:
        s = str(stem)
    except Exception:
        s = fallback
    s = s.strip().replace(" ", "_")
    # Replace control chars and Windows-forbidden characters.
    out = []
    for ch in s:
        o = ord(ch)
        if o < 32 or ch in _INVALID_FILENAME_CHARS:
            out.append("_")
        else:
            out.append(ch)
    s = "".join(out)
    s = re.sub(r"_+", "_", s).strip(" ._")
    if not s:
        s = fallback
    # Keep it reasonably short to avoid path length issues.
    if len(s) > 120:
        s = s[:120].rstrip(" ._")
        if not s:
            s = fallback
    return s

def _sanitize_filename(name: str, fallback: str = "output.mp4") -> str:
    """Return a filesystem-safe filename (keeps extension if present)."""
    try:
        n = str(name)
    except Exception:
        return fallback
    n = n.strip()
    stem, ext = os.path.splitext(n)
    safe_stem = _sanitize_stem(stem, fallback=os.path.splitext(fallback)[0] or "output")
    safe_ext = ext
    # If extension has forbidden chars, drop it.
    if any((ch in _INVALID_FILENAME_CHARS or ord(ch) < 32) for ch in safe_ext):
        safe_ext = ""
    out = safe_stem + safe_ext
    # Avoid empty result
    if not out or out.strip(" ._") == "":
        out = fallback
    return out


def _load_clip_presets() -> List[Tuple[str, str, str]]:
    """Load 1-click clip presets from JSON, with minimal built-in fallback.

    JSON location (relative to app root):
        /presets/setsave/clip_presets.json

    Schema:
        {
            "version": 1,
            "presets": [
                {
                    "id": "clean",
                    "name": "Clean cuts (no FX)",
                    "description": "...",
                    "settings": { ... }
                },
                ...
            ]
        }
    """
    # Only keep the two "safe" built-ins as a fallback so the dialog
    # still works even if the JSON file is missing or broken.
    default_presets: List[Tuple[str, str, str]] = [
        ("clean", "Clean cuts (no FX)", "Very clean edit, slower cuts, no extra FX."),
        ("chill", "Chill / slow cinematic", "Soft cuts with gentle slow-motion and cinematic moves."),
    ]
    try:
        here = os.path.dirname(os.path.abspath(__file__))
        json_path = os.path.join(here, "..", "presets", "setsave", "clip_presets.json")
        if not os.path.exists(json_path):
            return default_presets

        with open(json_path, "r", encoding="utf-8") as f:
            data = json.load(f)

        items = data.get("presets", [])
        if not isinstance(items, list):
            return default_presets

        presets: List[Tuple[str, str, str]] = []
        for item in items:
            if not isinstance(item, dict):
                continue
            pid = str(item.get("id") or "").strip()
            if not pid:
                continue
            name = str(item.get("name") or "").strip() or pid
            desc = str(item.get("description") or "").strip()
            presets.append((pid, name, desc))

        # If JSON is empty or invalid, fall back to the two built-ins.
        return presets or default_presets
    except Exception:
        # Any error: fall back to the two built-in presets so the UI keeps working.
        return default_presets


def _get_clip_preset_settings(preset_id: str) -> dict | None:
    """Return the settings dict for a given preset id from clip_presets.json.

    This is used by _apply_preset so that all 1-click presets (including
    user-defined ones) live in JSON instead of being hardcoded here.

    Returns None if the file is missing, broken or the preset is not found.
    """
    try:
        here = os.path.dirname(os.path.abspath(__file__))
        json_path = os.path.join(here, "..", "presets", "setsave", "clip_presets.json")
        if not os.path.exists(json_path):
            return None

        with open(json_path, "r", encoding="utf-8") as f:
            data = json.load(f)

        items = data.get("presets", [])
        if not isinstance(items, list):
            return None

        for item in items:
            if not isinstance(item, dict):
                continue
            pid = str(item.get("id") or "").strip()
            if pid != preset_id:
                continue
            settings = item.get("settings")
            if isinstance(settings, dict):
                return settings
            return None
    except Exception:
        return None
    return None




def _clip_presets_json_path() -> str:
    """Return absolute path to presets/setsave/clip_presets.json."""
    here = os.path.dirname(os.path.abspath(__file__))
    return os.path.join(here, "..", "presets", "setsave", "clip_presets.json")


def _read_clip_presets_json() -> dict:
    """Read clip_presets.json. If missing/broken, return an empty structure."""
    path = _clip_presets_json_path()
    try:
        if not os.path.exists(path):
            return {"version": 1, "presets": []}
        with open(path, "r", encoding="utf-8") as f:
            data = json.load(f)
        if not isinstance(data, dict):
            return {"version": 1, "presets": []}
        if "version" not in data:
            data["version"] = 1
        if not isinstance(data.get("presets"), list):
            data["presets"] = []
        return data
    except Exception:
        return {"version": 1, "presets": []}


def _atomic_write_json(path: str, data: dict) -> None:
    """Atomic JSON write with .tmp and .bak (best-effort)."""
    os.makedirs(os.path.dirname(path), exist_ok=True)
    tmp = path + ".tmp"
    bak = path + ".bak"
    payload = json.dumps(data, ensure_ascii=False, indent=2)
    with open(tmp, "w", encoding="utf-8") as f:
        f.write(payload)
        f.flush()
        try:
            os.fsync(f.fileno())
        except Exception:
            pass
    # backup old
    try:
        if os.path.exists(path):
            try:
                if os.path.exists(bak):
                    os.remove(bak)
            except Exception:
                pass
            try:
                os.replace(path, bak)
            except Exception:
                # fallback: copy
                try:
                    shutil.copy2(path, bak)
                except Exception:
                    pass
    except Exception:
        pass
    os.replace(tmp, path)


def _write_clip_presets_json(data: dict) -> Tuple[bool, str]:
    """Validate and write clip_presets.json. Returns (ok, message)."""
    try:
        if not isinstance(data, dict):
            return False, "Invalid data (not a dict)."
        presets = data.get("presets")
        if not isinstance(presets, list):
            return False, "Invalid presets list."
        seen = set()
        for item in presets:
            if not isinstance(item, dict):
                return False, "Preset item is not an object."
            pid = str(item.get("id") or "").strip()
            if not pid:
                return False, "Preset id cannot be empty."
            if pid in seen:
                return False, f"Duplicate preset id: {pid}"
            seen.add(pid)
            if not isinstance(item.get("settings", {}), dict):
                return False, f"Preset '{pid}' settings must be an object."
        if "version" not in data:
            data["version"] = 1
        path = _clip_presets_json_path()
        _atomic_write_json(path, data)
        return True, "Saved."
    except Exception as e:
        return False, f"Failed to save: {e}"


class ClipPresetManagerDialog(QDialog):
    """Edit clip_presets.json without touching the 1-click 'run videoclip' flow."""

    def __init__(self, parent: QWidget, capture_fx_cb, apply_fx_cb):
        super().__init__(parent)
        self.setWindowTitle("Preset manager")
        self.resize(860, 520)
        self._capture_fx_cb = capture_fx_cb
        self._apply_fx_cb = apply_fx_cb
        self._data = _read_clip_presets_json()
        self._current_index: int | None = None

        root = QHBoxLayout(self)

        # left: list + actions
        left = QVBoxLayout()
        self.list = QListWidget(self)
        left.addWidget(self.list, 1)

        row_btns = QHBoxLayout()
        self.btn_new = QPushButton("New", self)
        self.btn_dup = QPushButton("Duplicate", self)
        self.btn_del = QPushButton("Delete", self)
        row_btns.addWidget(self.btn_new)
        row_btns.addWidget(self.btn_dup)
        row_btns.addWidget(self.btn_del)
        row_btns.addStretch(1)
        left.addLayout(row_btns)

        root.addLayout(left, 1)

        # right: editor
        right = QVBoxLayout()

        form = QFormLayout()
        self.edit_id = QLineEdit(self)
        self.edit_name = QLineEdit(self)
        self.edit_desc = QLineEdit(self)
        form.addRow("ID:", self.edit_id)
        form.addRow("Name:", self.edit_name)
        form.addRow("Description:", self.edit_desc)
        right.addLayout(form)

        # capture + edit controls
        row_caps = QHBoxLayout()
        self.btn_capture = QPushButton("Capture current Options + Advanced", self)
        self.btn_capture.setToolTip("Save current FX/transitions/effects settings into this preset.")
        self.btn_edit = QPushButton("Edit", self)
        self.btn_edit.setToolTip("Unlock Settings JSON for manual editing (advanced).")
        row_caps.addWidget(self.btn_capture, 1)
        row_caps.addWidget(self.btn_edit, 0)
        right.addLayout(row_caps)

        right.addWidget(QLabel("Settings (FX-only):", self))
        self.text_settings = QTextEdit(self)
        self.text_settings.setReadOnly(True)
        right.addWidget(self.text_settings, 1)

        self.btn_save_item = QPushButton("Apply edits to this preset", self)
        right.addWidget(self.btn_save_item)

        buttons = QDialogButtonBox(QDialogButtonBox.Apply | QDialogButtonBox.Save | QDialogButtonBox.Cancel, self)
        right.addWidget(buttons)

        try:
            btn_use = buttons.button(QDialogButtonBox.Apply)
            if btn_use is not None:
                btn_use.setText("Use this preset")
                btn_use.setToolTip("Apply this preset to the main UI (does not save the JSON file).")
        except Exception:
            pass

        root.addLayout(right, 2)

        # signals
        self.list.currentRowChanged.connect(self._on_select)
        self.btn_new.clicked.connect(self._on_new)
        self.btn_dup.clicked.connect(self._on_dup)
        self.btn_del.clicked.connect(self._on_del)
        self.btn_capture.clicked.connect(self._on_capture)
        self.btn_edit.clicked.connect(self._on_toggle_edit)
        self.btn_save_item.clicked.connect(self._on_save_item)
        buttons.accepted.connect(self._on_save_all)
        buttons.rejected.connect(self.reject)
        try:
            btn_use = buttons.button(QDialogButtonBox.Apply)
            if btn_use is not None:
                btn_use.clicked.connect(self._on_use_preset)
        except Exception:
            pass

        self._refresh_list(select_first=True)

    def _set_settings_editable(self, editable: bool) -> None:
        try:
            self.text_settings.setReadOnly(not editable)
        except Exception:
            pass
        try:
            self.btn_edit.setText("Lock" if editable else "Edit")
            self.btn_edit.setToolTip(
                "Lock Settings JSON (recommended)." if editable else "Unlock Settings JSON for manual editing (advanced)."
            )
        except Exception:
            pass

    def _on_toggle_edit(self) -> None:
        try:
            self._set_settings_editable(self.text_settings.isReadOnly())
        except Exception:
            # safest fallback
            try:
                self.text_settings.setReadOnly(False)
                self.btn_edit.setText("Lock")
            except Exception:
                pass

    def _presets(self) -> list:
        items = self._data.get("presets")
        return items if isinstance(items, list) else []

    def _refresh_list(self, select_first: bool = False) -> None:
        self.list.blockSignals(True)
        self.list.clear()
        for item in self._presets():
            pid = str(item.get("id") or "")
            name = str(item.get("name") or pid)
            it = QListWidgetItem(f"{name}  [{pid}]", self.list)
            it.setData(Qt.UserRole, pid)
        self.list.blockSignals(False)
        if select_first and self.list.count() > 0:
            self.list.setCurrentRow(0)
        elif self.list.count() == 0:
            self._current_index = None
            self.edit_id.setText("")
            self.edit_name.setText("")
            self.edit_desc.setText("")
            self.text_settings.setPlainText("{}")

    def _load_into_editor(self, idx: int) -> None:
        presets = self._presets()
        if idx < 0 or idx >= len(presets):
            return
        self._current_index = idx
        item = presets[idx]
        self.edit_id.setText(str(item.get("id") or ""))
        self.edit_name.setText(str(item.get("name") or ""))
        self.edit_desc.setText(str(item.get("description") or ""))
        settings = item.get("settings") if isinstance(item.get("settings"), dict) else {}
        self.text_settings.setPlainText(json.dumps(settings, ensure_ascii=False, indent=2))
        # default to locked when switching presets
        self._set_settings_editable(False)

    def _on_select(self, row: int) -> None:
        self._load_into_editor(row)

    def _message(self, title: str, text: str, icon=QMessageBox.Information) -> None:
        m = QMessageBox(self)
        m.setIcon(icon)
        m.setWindowTitle(title)
        m.setText(text)
        m.exec()

    def _on_new(self) -> None:
        presets = self._presets()
        base_id = "new_preset"
        n = 1
        ids = {str(p.get('id') or '') for p in presets}
        pid = base_id
        while pid in ids:
            n += 1
            pid = f"{base_id}_{n}"
        presets.append({"id": pid, "name": "New preset", "description": "", "settings": {}})
        self._refresh_list()
        self.list.setCurrentRow(len(presets) - 1)

    def _on_dup(self) -> None:
        idx = self.list.currentRow()
        presets = self._presets()
        if idx < 0 or idx >= len(presets):
            return
        src = presets[idx]
        ids = {str(p.get('id') or '') for p in presets}
        pid0 = str(src.get('id') or 'preset').strip() or 'preset'
        pid = pid0 + "_copy"
        n = 1
        while pid in ids:
            n += 1
            pid = f"{pid0}_copy{n}"
        presets.append({
            "id": pid,
            "name": str(src.get('name') or pid) + " (copy)",
            "description": str(src.get('description') or ""),
            "settings": dict(src.get('settings') or {}),
        })
        self._refresh_list()
        self.list.setCurrentRow(len(presets) - 1)

    def _on_del(self) -> None:
        idx = self.list.currentRow()
        presets = self._presets()
        if idx < 0 or idx >= len(presets):
            return
        pid = str(presets[idx].get('id') or '')
        resp = QMessageBox.question(self, "Delete preset", f"Delete preset '{pid}'?", QMessageBox.Yes | QMessageBox.No)
        if resp != QMessageBox.Yes:
            return
        presets.pop(idx)
        self._refresh_list(select_first=True)

    def _on_capture(self) -> None:
        idx = self.list.currentRow()
        presets = self._presets()
        if idx < 0 or idx >= len(presets):
            return
        try:
            settings = self._capture_fx_cb() or {}
            if not isinstance(settings, dict):
                settings = {}
            presets[idx]["settings"] = settings
            self.text_settings.setPlainText(json.dumps(settings, ensure_ascii=False, indent=2))
        except Exception as e:
            self._message("Capture failed", str(e), QMessageBox.Warning)

    
    def _on_use_preset(self) -> None:
        """Apply the selected preset to the main UI without saving JSON."""
        idx = self.list.currentRow()
        presets = self._presets()
        if idx < 0 or idx >= len(presets):
            return
        # keep in-memory edits (id/name/desc) in sync
        try:
            self._on_save_item()
        except Exception:
            pass
        settings = presets[idx].get("settings") or {}
        if not isinstance(settings, dict):
            settings = {}
        try:
            if callable(self._apply_fx_cb):
                self._apply_fx_cb(settings)
        except Exception as e:
            try:
                self._message("Use preset failed", str(e), QMessageBox.Warning)
            except Exception:
                pass

    def _on_save_item(self) -> None:
        idx = self.list.currentRow()
        presets = self._presets()
        if idx < 0 or idx >= len(presets):
            return

        # validate id
        new_id = self.edit_id.text().strip()
        if not new_id:
            self._message("Invalid preset", "Preset ID cannot be empty.", QMessageBox.Warning)
            return

        # prevent duplicate ids (except for the current row)
        for j, p in enumerate(presets):
            if j == idx:
                continue
            if str(p.get("id") or "").strip() == new_id:
                self._message("Invalid preset", f"Preset ID '{new_id}' already exists.", QMessageBox.Warning)
                return

        # parse settings JSON (always, so edits actually persist)
        raw = self.text_settings.toPlainText().strip() or "{}"
        try:
            parsed = json.loads(raw)
            if not isinstance(parsed, dict):
                raise ValueError("Settings must be a JSON object (dictionary).")
        except Exception as e:
            self._message("Invalid settings JSON", f"Could not parse Settings JSON:\n{e}", QMessageBox.Warning)
            return

        presets[idx]["id"] = new_id
        presets[idx]["name"] = self.edit_name.text().strip()
        presets[idx]["description"] = self.edit_desc.text().strip()
        presets[idx]["settings"] = parsed
        self._refresh_list()
        self.list.setCurrentRow(idx)

    def _on_save_all(self) -> None:
        # apply current edits to selected first
        try:
            self._on_save_item()
        except Exception:
            pass
        ok, msg = _write_clip_presets_json(self._data)
        if not ok:
            self._message("Save failed", msg, QMessageBox.Warning)
            return
        self.accept()

# --------------------------- smart director v1 ----------------------------

SMART_DIRECTOR_PRESETS: List[str] = [
    "Manual / Classic",
    "Balanced",
    "Clean Cinematic",
    "EDM / Festival",
    "DnB / Chaos",
    "Vocal Story",
    "Dreamy / Emotional",
]

SMART_SCENE_CUT_STYLES: List[str] = [
    "Auto",
    "Short",
    "Medium",
    "Long",
    "Strong beats only",
    "Busy music video",
]

SMART_SCENE_MAX_MODES: List[str] = [
    "Auto (source-aware)",
    "Manual",
    "Off",
]


def _clamp01(v: float) -> float:
    try:
        return max(0.0, min(1.0, float(v)))
    except Exception:
        return 0.0


def _norm_smart_name(value: str, choices: List[str], default: str) -> str:
    raw = str(value or "").strip().lower()
    if not raw:
        return default
    for item in choices:
        if raw == item.lower():
            return item
    # tolerate saved enum-ish names from older/dev builds
    raw2 = raw.replace("_", " ").replace("-", " /")
    for item in choices:
        if raw2 == item.lower():
            return item
    return default


def _normalize_director_preset(value: str) -> str:
    return _norm_smart_name(value, SMART_DIRECTOR_PRESETS, "Balanced")


def _normalize_cut_style(value: str) -> str:
    return _norm_smart_name(value, SMART_SCENE_CUT_STYLES, "Auto")


def _normalize_smart_scene_max_mode(value: str) -> str:
    raw = str(value or "").strip().lower()
    if raw in ("", "auto", "source", "source-aware", "source aware", "auto source", "auto source aware"):
        return "Auto (source-aware)"
    if raw in ("manual", "custom"):
        return "Manual"
    if raw in ("off", "none", "disabled", "disable", "no max", "unlimited"):
        return "Off"
    return _norm_smart_name(value, SMART_SCENE_MAX_MODES, "Auto (source-aware)")


def _normalize_smart_cut_timing_offset(value: float) -> float:
    try:
        v = float(value)
    except Exception:
        v = 0.0
    return max(-1.0, min(0.5, v))


def _percentile(values: List[float], q: float) -> float:
    vals = sorted(float(v) for v in (values or []) if float(v) > 0.0)
    if not vals:
        return 0.0
    if len(vals) == 1:
        return vals[0]
    pos = (len(vals) - 1) * max(0.0, min(1.0, float(q)))
    lo = int(math.floor(pos))
    hi = int(math.ceil(pos))
    if lo == hi:
        return vals[lo]
    frac = pos - lo
    return vals[lo] * (1.0 - frac) + vals[hi] * frac


def _smart_source_duration_stats(source_clip_durations: Optional[List[float]]) -> dict:
    vals: List[float] = []
    for raw in (source_clip_durations or []):
        try:
            v = float(raw)
        except Exception:
            continue
        if v > 0.20:
            vals.append(v)
    vals.sort()
    if not vals:
        return {
            "count": 0,
            "min": 0.0,
            "median": 0.0,
            "p75": 0.0,
            "p90": 0.0,
            "max": 0.0,
            "auto_max": 0.0,
        }
    median = _percentile(vals, 0.50)
    p75 = _percentile(vals, 0.75)
    p90 = _percentile(vals, 0.90)
    # Auto aims at the upper-middle of the loaded source clips. For a folder of
    # mostly 3-6s clips this lands around 4-5.5s, which avoids forcing most
    # clips into unwanted stretching/slow motion while still leaving room for
    # calmer intro/outro shots. Users can choose Manual or Off when they want
    # long, held shots from long source footage.
    auto_max = p75 * 0.95 if p75 > 0.0 else median
    auto_max = max(median * 0.95, auto_max)
    auto_max = max(1.0, min(12.0, auto_max))
    return {
        "count": len(vals),
        "min": float(vals[0]),
        "median": float(median),
        "p75": float(p75),
        "p90": float(p90),
        "max": float(vals[-1]),
        "auto_max": float(auto_max),
    }


def _resolve_smart_scene_duration_guard(
    enabled: bool,
    min_scene_len: float,
    max_scene_len: float,
    max_scene_mode: str,
    source_clip_durations: Optional[List[float]] = None,
) -> dict:
    mode = _normalize_smart_scene_max_mode(max_scene_mode)
    try:
        min_len = float(min_scene_len)
    except Exception:
        min_len = 1.5
    min_len = max(0.25, min(12.0, min_len))

    stats = _smart_source_duration_stats(source_clip_durations)
    max_len = 0.0
    if mode == "Manual":
        try:
            max_len = float(max_scene_len)
        except Exception:
            max_len = 5.0
        max_len = max(0.5, min(30.0, max_len))
    elif mode == "Auto (source-aware)":
        auto_max = float(stats.get("auto_max") or 0.0)
        if auto_max <= 0.0:
            # Safe fallback when the scene map is built without scanned video
            # durations, such as future/headless callers.
            auto_max = 6.0
        max_len = auto_max
    else:
        max_len = 0.0

    if max_len > 0.0 and max_len < min_len + 0.25:
        max_len = min_len + 0.25

    return {
        "enabled": bool(enabled),
        "min_len": float(min_len),
        "max_len": float(max_len),
        "max_mode": mode,
        "source_stats": stats,
    }


def _source_durations_from_sources(sources: Optional[List["ClipSource"]]) -> List[float]:
    out: List[float] = []
    for src in (sources or []):
        try:
            if bool(getattr(src, "is_image", False)):
                continue
            d = float(getattr(src, "duration", 0.0) or 0.0)
        except Exception:
            continue
        if d > 0.20:
            out.append(d)
    return out


def _director_profile(preset: str) -> dict:
    p = _normalize_director_preset(preset)
    profiles = {
        "Manual / Classic": {"length": 1.00, "effect": -0.10, "transition": -0.05, "cine_cooldown": 12.0},
        "Balanced": {"length": 1.00, "effect": 0.00, "transition": 0.00, "cine_cooldown": 10.0},
        "Clean Cinematic": {"length": 1.35, "effect": -0.30, "transition": -0.25, "cine_cooldown": 16.0},
        "EDM / Festival": {"length": 0.78, "effect": 0.22, "transition": 0.20, "cine_cooldown": 7.0},
        "DnB / Chaos": {"length": 0.45, "effect": 0.35, "transition": 0.30, "cine_cooldown": 4.0},
        "Vocal Story": {"length": 1.25, "effect": -0.12, "transition": -0.08, "cine_cooldown": 12.0},
        "Dreamy / Emotional": {"length": 1.65, "effect": -0.25, "transition": -0.18, "cine_cooldown": 15.0},
    }
    return dict(profiles.get(p, profiles["Balanced"]))


def _section_director_defaults(label: str) -> dict:
    lbl = str(label or "verse").lower()
    table = {
        "intro": {"length": 1.85, "transition": 0.18, "effect": 0.10, "role": "establishing"},
        "verse": {"length": 1.15, "transition": 0.35, "effect": 0.28, "role": "story"},
        "chorus": {"length": 0.78, "transition": 0.68, "effect": 0.62, "role": "hook"},
        "drop": {"length": 0.45, "transition": 0.95, "effect": 0.95, "role": "impact"},
        "break": {"length": 1.70, "transition": 0.25, "effect": 0.18, "role": "breather"},
        "outro": {"length": 1.95, "transition": 0.22, "effect": 0.14, "role": "ending"},
    }
    return dict(table.get(lbl, table["verse"]))


def _cut_style_multiplier(cut_style: str) -> float:
    style = _normalize_cut_style(cut_style)
    if style == "Short":
        return 0.55
    if style == "Medium":
        return 1.0
    if style == "Long":
        return 1.75
    if style == "Strong beats only":
        return 1.20
    if style == "Busy music video":
        return 0.34
    return 1.0


def _music_section_at(analysis: "MusicAnalysisResult", time_t: float) -> str:
    sections = getattr(analysis, "sections", None) or []
    if not sections:
        return "verse"
    last_idx = len(sections) - 1
    for idx, sct in enumerate(sections):
        try:
            start = float(getattr(sct, "start", 0.0) or 0.0)
            end = float(getattr(sct, "end", 0.0) or 0.0)
        except Exception:
            continue
        if start <= time_t < end or (idx == last_idx and time_t >= start):
            kind = str(getattr(sct, "kind", "verse") or "verse").lower()
            if idx == last_idx and kind not in ("intro",):
                return "outro"
            return kind
    return str(getattr(sections[-1], "kind", "verse") or "verse").lower()


def _music_section_end_at(analysis: "MusicAnalysisResult", time_t: float) -> Optional[float]:
    sections = getattr(analysis, "sections", None) or []
    for sct in sections:
        try:
            start = float(getattr(sct, "start", 0.0) or 0.0)
            end = float(getattr(sct, "end", 0.0) or 0.0)
        except Exception:
            continue
        if start <= time_t < end:
            return max(start, end)
    try:
        return float(getattr(analysis, "duration", 0.0) or 0.0)
    except Exception:
        return None


def _smart_section_start_cut_points(analysis: "MusicAnalysisResult", director_preset: str, cut_style: str) -> List[Tuple[float, str]]:
    """Return real music-structure starts that should be available as cut points.

    This is not a new scoring brain. It simply makes important analysed section
    starts part of the Smart Scene Map timing grid so chorus/drop entries can be
    hit on the actual section start instead of the next grouped beat.
    """
    try:
        duration = float(getattr(analysis, "duration", 0.0) or 0.0)
    except Exception:
        duration = 0.0
    sections = sorted(list(getattr(analysis, "sections", []) or []), key=lambda s: float(getattr(s, "start", 0.0) or 0.0))
    if duration <= 0.05 or len(sections) < 2:
        return []

    preset = _normalize_director_preset(director_preset)
    style = _normalize_cut_style(cut_style)
    energetic = preset in ("EDM / Festival", "DnB / Chaos") or style == "Busy music video"
    out: List[Tuple[float, str]] = []
    seen: List[float] = []

    def _add(t: float, reason: str) -> None:
        try:
            tt = float(t)
        except Exception:
            return
        if not (0.05 < tt < duration - 0.05):
            return
        # Keep one clean section boundary if the analyser produced nearly
        # duplicate starts. Prefer the first exact section boundary we saw.
        if any(abs(tt - old) <= 0.08 for old in seen):
            return
        seen.append(tt)
        out.append((tt, reason))

    for idx, sec in enumerate(sections):
        try:
            start = float(getattr(sec, "start", 0.0) or 0.0)
        except Exception:
            continue
        kind = str(getattr(sec, "kind", "verse") or "verse").lower()
        prev_kind = ""
        if idx > 0:
            prev_kind = str(getattr(sections[idx - 1], "kind", "") or "").lower()

        reason = "section_start"
        if kind == "drop":
            reason = "drop_start"
        elif kind == "chorus":
            reason = "chorus_start"
        elif kind == "outro":
            reason = "outro_start"
        elif prev_kind == "break" and kind != "break":
            reason = "break_exit"
        elif prev_kind == "intro" and kind != "intro":
            reason = "intro_end"
        elif kind == "break":
            reason = "break_start"

        # All real section starts are useful candidates. Energetic presets get
        # the most benefit from exact drop/chorus starts, but calm presets still
        # need verse/intro/outro boundaries available so the guard can decide.
        if reason in ("drop_start", "chorus_start", "break_exit", "intro_end", "outro_start") or energetic or idx > 0:
            _add(start, reason)

    return out


def _representative_beat_strength(beats: List["Beat"], start: float, end: float) -> float:
    if not beats:
        return 0.0
    try:
        max_strength = max(0.0001, max(float(getattr(b, "strength", 0.0) or 0.0) for b in beats))
    except Exception:
        max_strength = 1.0
    vals = []
    for b in beats:
        try:
            t = float(getattr(b, "time", 0.0) or 0.0)
            if start <= t < end:
                vals.append(float(getattr(b, "strength", 0.0) or 0.0))
        except Exception:
            continue
    if not vals:
        center = (float(start) + float(end)) * 0.5
        try:
            nearest = min(beats, key=lambda b: abs(float(getattr(b, "time", 0.0) or 0.0) - center))
            vals = [float(getattr(nearest, "strength", 0.0) or 0.0)]
        except Exception:
            vals = [0.0]
    return _clamp01(max(vals) / max_strength)


def _smart_energy_class(section_label: str, beat_strength: float) -> str:
    lbl = str(section_label or "verse").lower()
    if lbl in ("drop", "chorus") or beat_strength >= 0.72:
        return "high"
    if lbl in ("intro", "break", "outro") and beat_strength < 0.70:
        return "low"
    return "mid"


def _smart_target_beats(base_beats: int, section_label: str, cut_style: str, director_preset: str) -> int:
    base = max(1, int(base_beats or 1))
    section_cfg = _section_director_defaults(section_label)
    director_cfg = _director_profile(director_preset)
    mult = float(section_cfg.get("length", 1.0)) * float(director_cfg.get("length", 1.0)) * _cut_style_multiplier(cut_style)
    style = _normalize_cut_style(cut_style)
    preset = _normalize_director_preset(director_preset)
    if style == "Busy music video":
        mult *= 0.75
    if style == "Strong beats only":
        mult *= 1.15
    if preset == "DnB / Chaos" and str(section_label).lower() in ("drop", "chorus"):
        mult *= 0.75
    return max(1, min(96, int(round(base * mult))))


def _smart_pick_effect(fx_level: str, energy: str, section_label: str, effect_intensity: float, director_preset: str) -> str:
    fx = str(fx_level or "none").lower()
    if fx == "none":
        return "none"
    preset = _normalize_director_preset(director_preset)
    section = str(section_label or "verse").lower()
    intensity = _clamp01(effect_intensity)

    base_prob = 0.0
    if fx == "minimal":
        base_prob = 0.20
    elif fx == "moderate":
        base_prob = 0.50
    elif fx == "high":
        base_prob = 0.78
    else:
        base_prob = 0.35

    prob = base_prob * (0.35 + 0.85 * intensity)
    if section in ("intro", "outro") and preset not in ("DnB / Chaos", "EDM / Festival"):
        prob *= 0.42
    elif section == "break" and preset != "Dreamy / Emotional":
        prob *= 0.65
    elif section == "drop":
        prob *= 1.15
    if preset == "Clean Cinematic":
        prob *= 0.55
    elif preset == "Dreamy / Emotional":
        prob *= 0.62
    elif preset == "DnB / Chaos":
        prob *= 1.35
    elif preset == "EDM / Festival":
        prob *= 1.15
    prob = _clamp01(prob)
    if random.random() > prob:
        return "none"

    if preset == "Clean Cinematic":
        pool = ["zoom", "motion_blur"]
    elif preset == "Dreamy / Emotional":
        pool = ["zoom", "motion_blur", "rgb_split"] if section in ("chorus", "drop") else ["zoom", "motion_blur"]
    elif preset == "Vocal Story":
        pool = ["zoom", "motion_blur"] if section in ("intro", "verse", "break", "outro") else ["zoom", "flash", "motion_blur"]
    elif preset == "DnB / Chaos":
        pool = ["flash", "rgb_split", "vhs", "motion_blur", "zoom"]
    elif preset == "EDM / Festival":
        pool = ["zoom", "flash", "rgb_split", "motion_blur"]
    else:
        if energy == "high":
            pool = ["zoom", "flash", "rgb_split", "vhs", "motion_blur"]
        elif energy == "mid":
            pool = ["zoom", "rgb_split", "motion_blur"]
        else:
            pool = ["zoom", "motion_blur"]
    return random.choice(pool) if pool else "none"


def _smart_pick_transition_mode(default_mode: int, random_enabled: bool, allowed_modes: List[int], section_label: str, transition_intensity: float, director_preset: str) -> int:
    preset = _normalize_director_preset(director_preset)
    section = str(section_label or "verse").lower()
    intensity = _clamp01(transition_intensity)
    try:
        fallback = int(default_mode)
    except Exception:
        fallback = 1
    allowed = []
    for m in (allowed_modes or []):
        try:
            mi = int(m)
        except Exception:
            continue
        if 0 <= mi <= 14 and mi not in allowed:
            allowed.append(mi)
    if not allowed:
        allowed = [fallback]

    # Hard cuts selected by the user remain respected unless random transitions are on.
    if not random_enabled and fallback == 1:
        return 1

    clean_modes = [1, 0, 10]
    soft_modes = [0, 3, 10, 13, 8]
    balanced_modes = [0, 1, 2, 3, 5, 8, 9, 10, 13]
    aggressive_modes = [1, 2, 5, 6, 7, 8, 9, 12, 14]

    if preset == "Clean Cinematic":
        preferred = clean_modes
        use_prob = 0.24 + 0.42 * intensity
    elif preset == "Dreamy / Emotional":
        preferred = soft_modes
        use_prob = 0.28 + 0.45 * intensity
    elif preset == "Vocal Story":
        preferred = soft_modes if section not in ("drop",) else balanced_modes
        use_prob = 0.32 + 0.48 * intensity
    elif preset == "EDM / Festival":
        preferred = aggressive_modes if section in ("chorus", "drop") else balanced_modes
        use_prob = 0.45 + 0.50 * intensity
    elif preset == "DnB / Chaos":
        preferred = aggressive_modes
        use_prob = 0.62 + 0.38 * intensity
    elif preset == "Manual / Classic":
        preferred = allowed if random_enabled else [fallback]
        use_prob = 0.30 + 0.35 * intensity
    else:
        preferred = balanced_modes
        use_prob = 0.36 + 0.48 * intensity

    if section in ("intro", "outro") and preset not in ("DnB / Chaos",):
        use_prob *= 0.45
    if section == "break" and preset not in ("Dreamy / Emotional", "Clean Cinematic"):
        use_prob *= 0.70
    use_prob = _clamp01(use_prob)

    if random.random() > use_prob:
        # Low-intensity scenes intentionally get a clean cut or simple dissolve.
        if section in ("intro", "outro", "break") and fallback != 1:
            return 0
        return 1

    pool = [m for m in preferred if m in allowed]
    if not pool:
        pool = [fallback] if fallback in allowed or not random_enabled else allowed
    if not random_enabled:
        # Respect the selected look, but allow smart mode to turn some low-intensity scenes into clean cuts.
        return fallback
    return random.choice(pool) if pool else fallback


def _smart_cinematic_cooldown(director_preset: str) -> float:
    return float(_director_profile(director_preset).get("cine_cooldown", 10.0))


def _smart_scene_allows_cinematic(scene: Optional["MusicScene"], director_preset: str) -> bool:
    if scene is None:
        return True
    preset = _normalize_director_preset(director_preset)
    section = str(getattr(scene, "section_label", "verse") or "verse").lower()
    intensity = _clamp01(float(getattr(scene, "effect_intensity", 0.0) or 0.0))
    if section in ("intro", "outro") and preset not in ("DnB / Chaos", "EDM / Festival"):
        threshold = 0.78
    elif section == "break" and preset not in ("Dreamy / Emotional",):
        threshold = 0.62
    else:
        threshold = 0.35
    # Keep a little randomness so repeated sections do not feel copy-pasted.
    return intensity >= threshold or random.random() < max(0.03, intensity * 0.22)


def _scene_map_to_list(scenes: Optional[List["MusicScene"]]) -> list:
    if not scenes:
        return []
    try:
        from dataclasses import asdict
        return [asdict(s) for s in scenes]
    except Exception:
        out = []
        for sc in scenes:
            try:
                out.append(dict(getattr(sc, "__dict__", {})))
            except Exception:
                pass
        return out


# --------------------------- data classes ----------------------------------


@dataclass
class Beat:
    time: float
    strength: float
    kind: str  # "major" / "minor"


@dataclass
class Section:
    start: float
    end: float
    kind: str  # "intro", "verse", "chorus", "drop", "break"


@dataclass
class ClipSource:
    path: str
    duration: float
    is_image: bool = False


@dataclass
class TimelineSegment:
    clip_path: str
    clip_start: float
    duration: float
    effect: str
    energy_class: str  # "low", "mid", "high"
    transition: str    # "none", "fade", "flashcut"
    slow_factor: float = 1.0  # 1.0 = normal speed, <1.0 = slow motion (video only)
    # Cinematic one-off effects (freeze, stutter, reverse, speedups, ramp)
    cine_freeze: bool = False
    cine_stutter: bool = False
    cine_reverse: bool = False
    # Prism whip (horizontal drift)
    cine_tear_v: bool = False
    # Prism whip (vertical drift)
    cine_tear_h: bool = False
    # Speedup hits (play the source forward/backwards faster and repeat if needed)
    cine_speedup_forward: bool = False
    cine_speedup_backward: bool = False
    cine_speedup_forward_factor: float = 1.0
    cine_speedup_backward_factor: float = 1.0
    cine_speed_ramp: bool = False
    cine_freeze_len: float = 0.0
    cine_freeze_zoom: float = 0.0
    cine_tear_v_strength: float = 0.0
    cine_tear_h_strength: float = 0.0
    # Color-cycle glitch (cinematic)
    cine_color_cycle: bool = False
    cine_color_cycle_speed_ms: int = 400
    cine_stutter_repeats: int = 0
    cine_reverse_len: float = 0.0
    cine_reverse_window: float = 0.0
    cine_ramp_in: float = 0.0
    cine_ramp_out: float = 0.0
    cine_boomerang: bool = False
    cine_boomerang_bounces: int = 0
    # Dimension portal shapes (rect / trapezoid / diamond / portrait)
    cine_dimension: bool = False
    cine_dimension_kind: str = ""
    # Slice reveal / 1-3 window pan (boomerang across 3 positions)
    cine_pan916: bool = False
    cine_pan916_speed_ms: int = 400
    cine_pan916_parts: int = 3
    cine_pan916_transparent: bool = False
    cine_pan916_random: bool = False
    cine_pan916_phase: int = 0
    cine_pan916_flip_lr: bool = False
    # Mosaic multi-screen effect
    cine_mosaic: bool = False
    cine_mosaic_screens: int = 0
    # Multiply same-clip multi-screen effect
    cine_multiply: bool = False
    cine_multiply_screens: int = 0
    # Upside-down flip and rotating screen
    cine_flip: bool = False
    cine_rotate: bool = False
    cine_rotate_degrees: float = 0.0
    # Camera motion hits (dolly / Ken Burns)
    cine_dolly: bool = False
    cine_dolly_strength: float = 0.0
    cine_kenburns: bool = False
    cine_kenburns_strength: float = 0.0
    # Shared camera motion direction: 0=random, 1=zoom in, 2=zoom out,
    # 3=pan left, 4=pan right, 5=pan up, 6=pan down
    cine_motion_dir: int = 0
    # Break impact FX (first beat after a break)
    is_break_impact: bool = False
    impact_flash_strength: float = 0.0
    impact_flash_speed_ms: int = 250
    impact_shock_strength: float = 0.0
    impact_echo_trail_strength: float = 0.0
    impact_confetti_density: float = 0.0
    impact_zoom_amount: float = 0.0
    impact_shake_strength: float = 0.0
    impact_fog_density: float = 0.0
    impact_fire_gold_intensity: float = 0.0
    impact_fire_multi_intensity: float = 0.0
    impact_color_cycle_speed: float = 0.0
    # Timed strobe: list of offsets (seconds within this segment) where Flash strobe should fire.
    strobe_on_time_offsets: List[float] = field(default_factory=list)
    # Absolute position on the music timeline (seconds)
    timeline_start: float = 0.0
    timeline_end: float = 0.0
    is_image: bool = False  # Mark if this is an image (for special effects)


@dataclass
class MusicAnalysisConfig:
    sensitivity: int = 5


@dataclass
class MusicAnalysisResult:
    beats: List[Beat]
    sections: List[Section]
    duration: float


@dataclass
class LyricSegment:
    index: int
    start: float
    end: float
    text: str


def _parse_srt_timecode(value: str) -> Optional[float]:
    """Parse SRT timecode to seconds. Supports comma and dot milliseconds."""
    try:
        raw = str(value or "").strip().replace(",", ".")
        m = re.match(r"^(\d{1,2}):(\d{2}):(\d{2})(?:\.(\d{1,3}))?$", raw)
        if not m:
            return None
        hours = int(m.group(1))
        minutes = int(m.group(2))
        seconds = int(m.group(3))
        ms_txt = (m.group(4) or "0")[:3].ljust(3, "0")
        millis = int(ms_txt)
        return float(hours * 3600 + minutes * 60 + seconds) + (millis / 1000.0)
    except Exception:
        return None


def parse_srt_text(text: str) -> List[LyricSegment]:
    """Small self-contained SRT parser used for lyric timing hints."""
    if not text:
        return []
    raw = str(text).replace("\ufeff", "").replace("\r\n", "\n").replace("\r", "\n")
    blocks = re.split(r"\n\s*\n+", raw)
    out: List[LyricSegment] = []
    time_re = re.compile(
        r"(?P<start>\d{1,2}:\d{2}:\d{2}[,.]\d{1,3}|\d{1,2}:\d{2}:\d{2})\s*-->\s*"
        r"(?P<end>\d{1,2}:\d{2}:\d{2}[,.]\d{1,3}|\d{1,2}:\d{2}:\d{2})"
    )
    for block in blocks:
        lines = [ln.strip() for ln in str(block or "").split("\n") if ln.strip()]
        if not lines:
            continue
        idx = len(out) + 1
        pos = 0
        try:
            if re.match(r"^\d+$", lines[0]):
                idx = int(lines[0])
                pos = 1
        except Exception:
            pos = 0
        if pos >= len(lines):
            continue
        m = time_re.search(lines[pos])
        if not m:
            # Some loose SRT files omit the numeric index; search all lines.
            found_pos = -1
            for j, ln in enumerate(lines):
                m = time_re.search(ln)
                if m:
                    found_pos = j
                    break
            if not m:
                continue
            pos = found_pos
        start = _parse_srt_timecode(m.group("start"))
        end = _parse_srt_timecode(m.group("end"))
        if start is None or end is None or float(end) <= float(start):
            continue
        text_lines = lines[pos + 1:]
        lyric_text = " ".join(t.replace("\\N", " " ).strip() for t in text_lines if t.strip())
        lyric_text = re.sub(r"\s+", " ", lyric_text).strip()
        if not lyric_text:
            continue
        out.append(LyricSegment(index=int(idx), start=float(start), end=float(end), text=lyric_text))
    return out


def load_srt_segments(path: str) -> List[LyricSegment]:
    """Load and parse an SRT file without pulling in subtitle libraries."""
    p = str(path or "").strip()
    if not p or not os.path.isfile(p):
        return []
    last_error: Optional[Exception] = None
    for enc in ("utf-8-sig", "utf-8", "cp1252"):
        try:
            with open(p, "r", encoding=enc) as f:
                return parse_srt_text(f.read())
        except Exception as e:
            last_error = e
    if last_error is not None:
        raise last_error
    return []


def _lyric_segments_to_list(segments: Optional[List[LyricSegment]]) -> list:
    if not segments:
        return []
    try:
        from dataclasses import asdict
        return [asdict(seg) for seg in segments]
    except Exception:
        out = []
        for seg in segments or []:
            try:
                out.append(dict(getattr(seg, "__dict__", {})))
            except Exception:
                pass
        return out


def _lyric_segments_from_list(items: Optional[list]) -> List[LyricSegment]:
    out: List[LyricSegment] = []
    for d in (items or []):
        try:
            out.append(LyricSegment(
                index=int(d.get("index", len(out) + 1)),
                start=float(d.get("start") or 0.0),
                end=float(d.get("end") or 0.0),
                text=str(d.get("text") or "").strip(),
            ))
        except Exception:
            continue
    return [seg for seg in out if seg.text and seg.end > seg.start]



def _bridge_active_lyric_overlap_reason(sc_start: float, sc_end: float, overlaps: list) -> tuple:
    """Return conservative active lyric evidence for Planner Bridge scene export.

    This keeps lyric text attached for mood/context, but marks stale long SRT
    overlap as inactive so the bridge does not force lipsync during instrumental
    tails or repeated lyric blocks.
    """
    try:
        sc_start = float(sc_start or 0.0)
        sc_end = float(sc_end or 0.0)
    except Exception:
        sc_start, sc_end = 0.0, 0.0
    duration = max(0.05, sc_end - sc_start)
    best_reason = "no_active_lyric_overlap"
    best_start = 0.0
    best_end = 0.0
    for seg in overlaps or []:
        try:
            start = float(getattr(seg, "start", 0.0) or 0.0)
            end = float(getattr(seg, "end", 0.0) or 0.0)
        except Exception:
            continue
        if end <= start:
            continue
        seg_duration = max(0.0, end - start)
        long_block = seg_duration > 8.0
        active_end = min(end, start + 3.5) if long_block else end
        overlap = min(sc_end, active_end) - max(sc_start, start)
        if overlap < 0.35:
            best_reason = "lyric_overlap_too_short_or_stale"
            continue
        starts_inside_or_near = (sc_start - 0.65) <= start <= (sc_end - min(0.05, duration * 0.1))
        short_overlap_near_start = (not long_block) and overlap >= min(1.0, duration * 0.5) and (sc_start - start) <= 1.25
        if long_block and start < sc_start - 0.45:
            best_reason = "long_srt_block_started_before_scene"
            continue
        if starts_inside_or_near or short_overlap_near_start:
            return True, ("active_long_srt_phrase_start_inside_scene" if long_block else "active_lyric_phrase_start_inside_scene"), start, active_end
        best_reason = "lyric_text_overlap_but_no_active_phrase_start"
        best_start = start
        best_end = active_end
    return False, best_reason, best_start, best_end

def attach_lyrics_to_scenes(
    scenes: Optional[List["MusicScene"]],
    lyric_segments: Optional[List[LyricSegment]],
    srt_path: str = "",
) -> List["MusicScene"]:
    """Annotate Smart Scene Map scenes with overlapping lyric/SRT text.

    This does not change scene timing. It only adds metadata for traces and later
    Smart Director / Planner work.
    """
    if not scenes:
        return []
    segments = [seg for seg in (lyric_segments or []) if float(getattr(seg, "end", 0.0) or 0.0) > float(getattr(seg, "start", 0.0) or 0.0)]
    if not segments:
        return list(scenes)
    safe_path = str(srt_path or "")
    for sc in scenes:
        try:
            sc_start = float(getattr(sc, "start", 0.0) or 0.0)
            sc_end = float(getattr(sc, "end", 0.0) or 0.0)
            overlaps = [
                seg for seg in segments
                if max(sc_start, float(seg.start)) < min(sc_end, float(seg.end))
            ]
            if not overlaps:
                continue
            text = " ".join(str(seg.text or "").strip() for seg in overlaps if str(seg.text or "").strip())
            text = re.sub(r"\s+", " ", text).strip()
            if len(text) > 500:
                text = text[:497].rstrip() + "..."
            active_ok, active_reason, active_start, active_end = _bridge_active_lyric_overlap_reason(sc_start, sc_end, overlaps)
            setattr(sc, "lyric_text", text)
            setattr(sc, "lyric_start", float(min(seg.start for seg in overlaps)))
            setattr(sc, "lyric_end", float(max(seg.end for seg in overlaps)))
            setattr(sc, "active_vocal_window", bool(active_ok))
            setattr(sc, "vocal_timing_reason", str(active_reason or ""))
            if active_ok:
                setattr(sc, "active_lyric_start", float(active_start))
                setattr(sc, "active_lyric_end", float(active_end))
            setattr(sc, "srt_path", safe_path)
            note = str(getattr(sc, "notes", "") or "")
            if "lyrics_attached" not in note:
                setattr(sc, "notes", (note + "; lyrics_attached").strip("; "))
        except Exception:
            continue
    return list(scenes)


def attach_lyrics_to_scene_dicts(scene_items: Optional[list], lyric_segments: Optional[List[LyricSegment]], srt_path: str = "") -> list:
    """Best-effort lyric metadata attachment for queued payload scene-map dicts."""
    if not isinstance(scene_items, list):
        return []
    segments = [seg for seg in (lyric_segments or []) if seg.end > seg.start]
    if not segments:
        return scene_items
    out = []
    for item in scene_items:
        if not isinstance(item, dict):
            out.append(item)
            continue
        d = dict(item)
        try:
            sc_start = float(d.get("start") or 0.0)
            sc_end = float(d.get("end") or 0.0)
            overlaps = [seg for seg in segments if max(sc_start, seg.start) < min(sc_end, seg.end)]
            if overlaps:
                text = " ".join(seg.text.strip() for seg in overlaps if seg.text.strip())
                text = re.sub(r"\s+", " ", text).strip()
                if len(text) > 500:
                    text = text[:497].rstrip() + "..."
                active_ok, active_reason, active_start, active_end = _bridge_active_lyric_overlap_reason(sc_start, sc_end, overlaps)
                d["lyric_text"] = text
                d["lyric_start"] = float(min(seg.start for seg in overlaps))
                d["lyric_end"] = float(max(seg.end for seg in overlaps))
                d["active_vocal_window"] = bool(active_ok)
                d["vocal_timing_reason"] = str(active_reason or "")
                if active_ok:
                    d["active_lyric_start"] = float(active_start)
                    d["active_lyric_end"] = float(active_end)
                d["srt_path"] = str(srt_path or "")
        except Exception:
            pass
        out.append(d)
    return out


@dataclass
class MusicScene:
    index: int
    start: float
    end: float
    duration: float
    section_label: str
    energy_class: str
    beat_strength: float
    transition_intensity: float
    effect_intensity: float
    preferred_clip_role: str
    notes: str = ""
    beat_count: int = 0
    lyric_text: str = ""
    lyric_start: float = 0.0
    lyric_end: float = 0.0
    srt_path: str = ""


def build_smart_scene_map(
    analysis: MusicAnalysisResult,
    beats_per_segment: int = 8,
    director_preset: str = "Balanced",
    cut_style: str = "Auto",
    microclip_mode: int = 0,
    duration_guard_enabled: bool = True,
    min_scene_len: float = 1.5,
    max_scene_len: float = 5.0,
    max_scene_mode: str = "Auto (source-aware)",
    source_clip_durations: Optional[List[float]] = None,
    cut_timing_offset: float = 0.0,
) -> List[MusicScene]:
    """Build a section-aware scene plan before TimelineSegment creation.

    This is intentionally renderer-agnostic. It only decides where scenes should
    begin/end and how intense the director should be allowed to get. The normal
    build_timeline() pipeline still converts scenes into TimelineSegment objects.
    """
    if analysis is None:
        return []
    try:
        duration = float(getattr(analysis, "duration", 0.0) or 0.0)
    except Exception:
        duration = 0.0
    if duration <= 0.05:
        return []

    preset = _normalize_director_preset(director_preset)
    style = _normalize_cut_style(cut_style)
    cut_offset = _normalize_smart_cut_timing_offset(cut_timing_offset)
    director_cfg = _director_profile(preset)
    beats = sorted(list(getattr(analysis, "beats", []) or []), key=lambda b: float(getattr(b, "time", 0.0) or 0.0))
    duration_guard = _resolve_smart_scene_duration_guard(
        enabled=bool(duration_guard_enabled),
        min_scene_len=min_scene_len,
        max_scene_len=max_scene_len,
        max_scene_mode=max_scene_mode,
        source_clip_durations=source_clip_durations,
    )
    section_cut_points = _smart_section_start_cut_points(analysis, preset, style)
    section_cut_times = [float(t) for t, _reason in section_cut_points]

    def _make_scene(idx: int, start: float, end: float, beat_count: int) -> Optional[MusicScene]:
        start = max(0.0, min(duration, float(start)))
        end = max(0.0, min(duration, float(end)))
        if end - start <= 0.05:
            return None
        center = start + (end - start) * 0.5
        section = _music_section_at(analysis, center)
        strength = _representative_beat_strength(beats, start, end)
        energy = _smart_energy_class(section, strength)
        section_cfg = _section_director_defaults(section)
        transition_intensity = _clamp01(
            float(section_cfg.get("transition", 0.35))
            + float(director_cfg.get("transition", 0.0))
            + strength * 0.18
        )
        effect_intensity = _clamp01(
            float(section_cfg.get("effect", 0.28))
            + float(director_cfg.get("effect", 0.0))
            + strength * 0.22
        )
        # Microclip modes still matter as a preference signal. They do not force
        # the old arranger path, but they can make high/verse scenes more active.
        if int(microclip_mode or 0) == 1 and section in ("chorus", "drop"):
            transition_intensity = _clamp01(transition_intensity + 0.10)
            effect_intensity = _clamp01(effect_intensity + 0.10)
        elif int(microclip_mode or 0) == 2:
            transition_intensity = _clamp01(transition_intensity + 0.08)
            effect_intensity = _clamp01(effect_intensity + 0.08)
        elif int(microclip_mode or 0) == 3 and section == "verse":
            transition_intensity = _clamp01(transition_intensity + 0.10)
            effect_intensity = _clamp01(effect_intensity + 0.06)

        return MusicScene(
            index=idx,
            start=start,
            end=end,
            duration=end - start,
            section_label=section,
            energy_class=energy,
            beat_strength=strength,
            transition_intensity=transition_intensity,
            effect_intensity=effect_intensity,
            preferred_clip_role=str(section_cfg.get("role", "story")),
            notes="smart-scene-v1",
            beat_count=max(1, int(beat_count or 1)),
        )

    def _reindex_scenes(scene_list: List[MusicScene]) -> List[MusicScene]:
        for j, sc in enumerate(scene_list):
            sc.index = j
        return scene_list

    def _merge_tiny_legacy(scene_list: List[MusicScene]) -> List[MusicScene]:
        if len(scene_list) <= 1:
            return _reindex_scenes(scene_list)
        cleaned: List[MusicScene] = []
        for sc in scene_list:
            if cleaned and sc.duration < 0.35 and sc.section_label != "drop":
                prev = cleaned[-1]
                merged = _make_scene(prev.index, prev.start, sc.end, prev.beat_count + sc.beat_count)
                if merged is not None:
                    cleaned[-1] = merged
            else:
                cleaned.append(sc)
        return _reindex_scenes(cleaned)

    def _nearest_scene_beat(target: float, lower: float, upper: float) -> float:
        if upper <= lower:
            return max(lower, min(upper, target))
        candidates: List[float] = []
        for b in beats:
            try:
                t = float(getattr(b, "time", 0.0) or 0.0)
            except Exception:
                continue
            if lower <= t <= upper:
                candidates.append(t)
        if not candidates:
            return max(lower, min(upper, target))
        return min(candidates, key=lambda t: abs(t - target))

    def _finalize_scenes(scene_list: List[MusicScene]) -> List[MusicScene]:
        scene_list = [
            sc for sc in (scene_list or [])
            if float(getattr(sc, "end", 0.0) or 0.0) > float(getattr(sc, "start", 0.0) or 0.0)
        ]
        if not scene_list:
            return []
        if not bool(duration_guard.get("enabled")):
            return _merge_tiny_legacy(scene_list)

        min_len = float(duration_guard.get("min_len") or 1.5)
        max_len = float(duration_guard.get("max_len") or 0.0)

        # 1) Merge tiny scenes. Tiny scenes that END exactly at an important
        # section start are merged backward so the next scene can still begin on
        # the chorus/drop/break boundary instead of being pushed late. Other tiny
        # scenes merge forward as before.
        if len(scene_list) > 1 and min_len > 0.0:
            protected_premerge: List[MusicScene] = []
            for sc in scene_list:
                sc_end = float(getattr(sc, "end", 0.0) or 0.0)
                sc_dur = float(getattr(sc, "duration", 0.0) or 0.0)
                ends_at_section_start = any(abs(sc_end - sec_t) <= 0.05 for sec_t in section_cut_times)
                if protected_premerge and sc_dur < min_len and ends_at_section_start:
                    prev = protected_premerge.pop()
                    merged = _make_scene(
                        len(protected_premerge),
                        float(prev.start),
                        sc_end,
                        int(getattr(prev, "beat_count", 1) or 1) + int(getattr(sc, "beat_count", 1) or 1),
                    )
                    if merged is not None:
                        merged.notes = (str(merged.notes or "smart-scene-v1") + "; section_start_preserved").strip("; ")
                        protected_premerge.append(merged)
                else:
                    protected_premerge.append(sc)
            scene_list = protected_premerge

            merged_list: List[MusicScene] = []
            i = 0
            while i < len(scene_list):
                start = float(scene_list[i].start)
                end = float(scene_list[i].end)
                beat_count = int(getattr(scene_list[i], "beat_count", 1) or 1)
                while (end - start) < min_len and i < (len(scene_list) - 1):
                    i += 1
                    end = float(scene_list[i].end)
                    beat_count += int(getattr(scene_list[i], "beat_count", 1) or 1)
                sc_new = _make_scene(len(merged_list), start, end, beat_count)
                if sc_new is not None:
                    merged_list.append(sc_new)
                i += 1
            if len(merged_list) > 1 and merged_list[-1].duration < min_len:
                last = merged_list.pop()
                prev = merged_list.pop()
                sc_new = _make_scene(
                    len(merged_list),
                    prev.start,
                    last.end,
                    int(getattr(prev, "beat_count", 1) or 1) + int(getattr(last, "beat_count", 1) or 1),
                )
                if sc_new is not None:
                    merged_list.append(sc_new)
            scene_list = merged_list

        # 2) Split oversized scenes. This keeps 3-6 second source folders from
        # being forced into long held shots or unwanted slow-motion/stretching.
        if max_len > 0.0:
            split_list: List[MusicScene] = []
            for sc in scene_list:
                dur_sc = float(getattr(sc, "duration", 0.0) or 0.0)
                if dur_sc <= max_len + 0.05:
                    split_list.append(sc)
                    continue

                parts = max(2, int(math.ceil(dur_sc / max_len)))
                # Never split so aggressively that the new chunks become tiny.
                while parts > 1 and (dur_sc / parts) < min_len:
                    parts -= 1
                if parts <= 1:
                    split_list.append(sc)
                    continue

                protected_cuts: List[float] = []
                protected_start = float(sc.start)
                for sec_t in sorted(section_cut_times):
                    if sec_t <= float(sc.start) + 0.05 or sec_t >= float(sc.end) - 0.05:
                        continue
                    # Preserve important analysed section starts during max-length
                    # splitting when doing so does not violate the minimum guard.
                    if (sec_t - protected_start) >= min_len and (float(sc.end) - sec_t) >= min_len:
                        protected_cuts.append(sec_t)
                        protected_start = sec_t

                chunk_bounds = [float(sc.start)] + protected_cuts + [float(sc.end)]
                chunk_ranges: List[Tuple[float, float]] = []
                for chunk_idx in range(len(chunk_bounds) - 1):
                    chunk_start = chunk_bounds[chunk_idx]
                    chunk_end = chunk_bounds[chunk_idx + 1]
                    chunk_dur = max(0.0, chunk_end - chunk_start)
                    if chunk_dur <= max_len + 0.05:
                        chunk_ranges.append((chunk_start, chunk_end))
                        continue

                    chunk_parts = max(2, int(math.ceil(chunk_dur / max_len)))
                    while chunk_parts > 1 and (chunk_dur / chunk_parts) < min_len:
                        chunk_parts -= 1
                    if chunk_parts <= 1:
                        chunk_ranges.append((chunk_start, chunk_end))
                        continue

                    cut_points: List[float] = []
                    prev_cut = chunk_start
                    for part_idx in range(1, chunk_parts):
                        raw_target = chunk_start + chunk_dur * (part_idx / chunk_parts)
                        lower = prev_cut + min_len
                        upper = chunk_end - (chunk_parts - part_idx) * min_len
                        if upper < lower:
                            cut = max(chunk_start, min(chunk_end, raw_target))
                        else:
                            cut = _nearest_scene_beat(raw_target, lower, upper)
                        cut = max(prev_cut + 0.05, min(chunk_end - 0.05, cut))
                        cut_points.append(cut)
                        prev_cut = cut

                    start_piece = chunk_start
                    for cut in cut_points + [chunk_end]:
                        chunk_ranges.append((start_piece, cut))
                        start_piece = cut

                # Approximate beat count by duration share; the exact value is only
                # used as a pacing hint later, not as render timing authority.
                for start_t, end_t in chunk_ranges:
                    part_dur = max(0.0, end_t - start_t)
                    part_beats = max(1, int(round(int(getattr(sc, "beat_count", 1) or 1) * (part_dur / max(0.001, dur_sc)))))
                    sc_new = _make_scene(len(split_list), start_t, end_t, part_beats)
                    if sc_new is not None:
                        if any(abs(float(end_t) - sec_t) <= 0.05 for sec_t in protected_cuts) or any(abs(float(start_t) - sec_t) <= 0.05 for sec_t in protected_cuts):
                            sc_new.notes = (str(sc_new.notes or "smart-scene-v1") + "; section_start_preserved").strip("; ")
                        split_list.append(sc_new)
            scene_list = split_list

        scene_list = _reindex_scenes(scene_list)
        try:
            guard_note = (
                f"duration-guard min={float(duration_guard.get('min_len') or 0.0):.2f}s "
                f"max={float(duration_guard.get('max_len') or 0.0):.2f}s "
                f"mode={duration_guard.get('max_mode') or 'Auto'}"
            )
            for sc in scene_list:
                sc.notes = (str(sc.notes or "smart-scene-v1") + "; " + guard_note).strip("; ")
        except Exception:
            pass
        return scene_list

    def _apply_cut_timing_offset(scene_list: List[MusicScene]) -> List[MusicScene]:
        """Move internal smart-scene boundaries without shifting audio.

        The guard still owns legality: offset is clamped so it cannot create
        negative, overlapping, tiny, or source-max-breaking scenes.
        """
        if not scene_list or len(scene_list) <= 1 or abs(cut_offset) < 0.0005:
            return _reindex_scenes(scene_list or [])

        guard_on = bool(duration_guard.get("enabled"))
        min_len = float(duration_guard.get("min_len") or 0.35) if guard_on else 0.35
        max_len = float(duration_guard.get("max_len") or 0.0) if guard_on else 0.0
        min_len = max(0.05, min_len)

        original_boundaries = [float(sc.start) for sc in scene_list[1:]]
        new_boundaries: List[float] = []
        timeline_start = float(scene_list[0].start)
        timeline_end = float(scene_list[-1].end)
        prev_new = timeline_start

        for idx, old_boundary in enumerate(original_boundaries):
            next_original = float(scene_list[idx + 2].start) if (idx + 2) < len(scene_list) else timeline_end
            desired = old_boundary + cut_offset

            lower = prev_new + min_len
            upper = next_original - min_len
            if max_len > 0.0:
                # Previous scene cannot grow past max, and next scene cannot grow past max.
                upper = min(upper, prev_new + max_len)
                lower = max(lower, next_original - max_len)

            # Always keep cuts inside the actual timeline.
            lower = max(timeline_start + 0.05, lower)
            upper = min(timeline_end - 0.05, upper)

            if upper < lower:
                new_boundary = old_boundary
            else:
                new_boundary = max(lower, min(upper, desired))
            new_boundaries.append(new_boundary)
            prev_new = new_boundary

        rebuilt: List[MusicScene] = []
        start_t = timeline_start
        for idx, end_t in enumerate(new_boundaries + [timeline_end]):
            old_sc = scene_list[min(idx, len(scene_list) - 1)]
            sc_new = _make_scene(
                len(rebuilt),
                start_t,
                end_t,
                int(getattr(old_sc, "beat_count", 1) or 1),
            )
            if sc_new is not None:
                note = str(getattr(old_sc, "notes", "smart-scene-v1") or "smart-scene-v1")
                if idx > 0 or abs(start_t - float(getattr(old_sc, "start", start_t))) > 0.01:
                    note += f"; offset_applied={cut_offset:+.2f}s"
                sc_new.notes = note
                rebuilt.append(sc_new)
            start_t = end_t

        return _reindex_scenes(rebuilt)

    def _finalize_and_offset(scene_list: List[MusicScene]) -> List[MusicScene]:
        return _apply_cut_timing_offset(_finalize_scenes(scene_list))

    scenes: List[MusicScene] = []

    # Fallback for tracks with weak beat detection: use analysed sections, or
    # steady chunks if sections are missing.
    if len(beats) < 2:
        raw_sections = list(getattr(analysis, "sections", []) or [])
        if raw_sections:
            for sec in raw_sections:
                sc = _make_scene(len(scenes), float(sec.start), float(sec.end), 1)
                if sc is not None:
                    scenes.append(sc)
        else:
            step = 5.0
            if preset in ("Clean Cinematic", "Dreamy / Emotional"):
                step = 7.0
            elif preset == "DnB / Chaos" or style == "Busy music video":
                step = 2.0
            t = 0.0
            while t < duration - 0.05:
                sc = _make_scene(len(scenes), t, min(duration, t + step), 1)
                if sc is not None:
                    scenes.append(sc)
                t += step
        return _finalize_and_offset(scenes)

    # Use beat times and important analysed section starts as possible cut points. Strong-beats-only uses major beats
    # whenever available; otherwise it falls back to the normal beat list.
    if style == "Strong beats only":
        strong = [b for b in beats if str(getattr(b, "kind", "") or "").lower() == "major"]
        source_beats = strong if len(strong) >= 2 else beats
    else:
        source_beats = beats

    points = [0.0]
    for t, _reason in section_cut_points:
        if 0.02 < t < duration - 0.02:
            points.append(t)
    for b in source_beats:
        try:
            t = float(getattr(b, "time", 0.0) or 0.0)
        except Exception:
            continue
        if 0.02 < t < duration - 0.02:
            # If a beat is almost on top of a section start, keep the exact
            # section start. That avoids tiny intervals around drops/choruses
            # and stops the next clip from starting one beat late.
            if any(abs(t - sec_t) <= 0.08 for sec_t in section_cut_times):
                continue
            points.append(t)
    points.append(duration)
    points = sorted(set(round(float(x), 4) for x in points))

    intervals: List[Tuple[float, float]] = []
    for i in range(len(points) - 1):
        a, b = points[i], points[i + 1]
        if b - a > 0.03:
            intervals.append((a, b))
    if not intervals:
        sc = _make_scene(0, 0.0, duration, 1)
        return _finalize_and_offset([sc] if sc is not None else [])

    i = 0
    while i < len(intervals):
        start = intervals[i][0]
        section = _music_section_at(analysis, start + 0.001)
        target_beats = _smart_target_beats(beats_per_segment, section, style, preset)
        # Busy/drop styles should not create unreadably tiny flash cuts when the
        # source beat grid is very dense; these floors are intentionally modest.
        min_scene = 0.45 if (preset == "DnB / Chaos" or style == "Busy music video" or section == "drop") else 0.75
        if preset in ("Clean Cinematic", "Dreamy / Emotional") and section not in ("drop",):
            min_scene = 1.25

        end = intervals[i][1]
        count = 1
        section_end = _music_section_end_at(analysis, start + 0.001)
        while i + count < len(intervals):
            next_end = intervals[i + count][1]
            # Prefer not to cross section boundaries once the current scene has
            # enough duration to stand on its own. Important EDM-style entries
            # may cut a bit sooner, but the final duration guard still prevents
            # microclips or illegal scene lengths.
            boundary_floor = min_scene
            try:
                important_boundary = bool(section_end is not None and any(abs(float(section_end) - sec_t) <= 0.10 for sec_t in section_cut_times))
            except Exception:
                important_boundary = False
            if important_boundary:
                if preset in ("EDM / Festival", "DnB / Chaos") or style == "Busy music video":
                    boundary_floor = max(0.45, min_scene * 0.60)
                else:
                    boundary_floor = max(0.65, min_scene * 0.80)
            if section_end is not None and next_end > section_end + 0.03 and (end - start) >= boundary_floor:
                break
            if count >= target_beats and (end - start) >= min_scene:
                break
            end = next_end
            count += 1
            if count >= target_beats * 2 and (end - start) >= min_scene:
                break

        sc = _make_scene(len(scenes), start, end, count)
        if sc is not None:
            scenes.append(sc)
        i += max(1, count)

    return _finalize_and_offset(scenes)


# --------------------------- queue/headless helpers ------------------------

def _analysis_to_dict(a: "MusicAnalysisResult") -> dict:
    try:
        from dataclasses import asdict
        return asdict(a)
    except Exception:
        # Fallback: best-effort manual
        return {
            "beats": [getattr(b, "__dict__", {}) for b in (getattr(a, "beats", []) or [])],
            "sections": [getattr(s, "__dict__", {}) for s in (getattr(a, "sections", []) or [])],
            "duration": float(getattr(a, "duration", 0.0) or 0.0),
        }

def _analysis_from_dict(d: dict) -> "MusicAnalysisResult":
    beats = [Beat(**b) for b in (d.get("beats") or [])]
    sections = [Section(**s) for s in (d.get("sections") or [])]
    return MusicAnalysisResult(beats=beats, sections=sections, duration=float(d.get("duration") or 0.0))

def _segments_to_list(segments: list) -> list:
    try:
        from dataclasses import asdict
        return [asdict(s) for s in (segments or [])]
    except Exception:
        out = []
        for s in (segments or []):
            try:
                out.append(dict(getattr(s, "__dict__", {})))
            except Exception:
                pass
        return out

def _segments_from_list(items: list) -> list:
    out = []
    for d in (items or []):
        try:
            out.append(TimelineSegment(**d))
        except Exception:
            try:
                # tolerate missing keys
                out.append(TimelineSegment(
                    clip_path=str(d.get("clip_path","")),
                    clip_start=float(d.get("clip_start") or 0.0),
                    duration=float(d.get("duration") or 0.0),
                    effect=str(d.get("effect") or "none"),
                    energy_class=str(d.get("energy_class") or "mid"),
                    transition=str(d.get("transition") or "none"),
                    slow_factor=float(d.get("slow_factor") or 1.0),
                ))
            except Exception:
                pass
    return out



def _musicclip_load_ltx_bridge_module_for_queue(root_dir: str):
    """Load helpers/musicclip_planner_bridge.py for headless Queue LTX jobs."""
    try:
        import helpers.musicclip_planner_bridge as bridge  # type: ignore
        return _musicclip_patch_krea2_bridge(bridge)
    except Exception:
        pass
    try:
        import musicclip_planner_bridge as bridge  # type: ignore
        return _musicclip_patch_krea2_bridge(bridge)
    except Exception:
        pass
    import importlib.util
    root = Path(str(root_dir or _musicclip_project_root())).resolve()
    bridge_path = root / "helpers" / "musicclip_planner_bridge.py"
    if not bridge_path.is_file():
        bridge_path = root / "musicclip_planner_bridge.py"
    if not bridge_path.is_file():
        raise FileNotFoundError(f"musicclip_planner_bridge.py was not found for queued LTX run: {bridge_path}")
    spec = importlib.util.spec_from_file_location("musicclip_planner_bridge_queue", str(bridge_path))
    if spec is None or spec.loader is None:
        raise RuntimeError(f"Could not load bridge module spec: {bridge_path}")
    module = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(module)  # type: ignore[attr-defined]
    return _musicclip_patch_krea2_bridge(module)


def run_ltx_full_queue_payload(payload_path: str) -> int:
    """Headless entrypoint used by FrameVision Queue for Music Clip Creator LTX full runs."""
    try:
        payload_path = str(payload_path or "")
        if not payload_path or not os.path.isfile(payload_path):
            print(f"[musicclip_ltx_queue] ERROR: payload not found: {payload_path}", flush=True)
            return 2
        with open(payload_path, "r", encoding="utf-8") as f:
            payload = json.load(f)
        if not isinstance(payload, dict):
            print("[musicclip_ltx_queue] ERROR: payload JSON must be an object.", flush=True)
            return 3

        root_dir = str(payload.get("root_dir") or _musicclip_project_root())
        bridge = _musicclip_load_ltx_bridge_module_for_queue(root_dir)

        def _progress(text):
            msg = str(text or "").strip()
            if msg:
                print(f"[musicclip_ltx_queue] {msg}", flush=True)

        run_fn = getattr(bridge, "run_all_ltx_director_shots", None)
        if not callable(run_fn):
            print("[musicclip_ltx_queue] ERROR: run_all_ltx_director_shots is not available.", flush=True)
            return 4

        run_payload = dict(payload)
        run_payload["progress_callback"] = _progress
        run_payload.pop("cancel_check", None)
        _progress(f"Starting queued LTX full run using backend: {run_payload.get('ltx_backend') or run_payload.get('ltx_generation_backend') or 'auto'}")
        run_result = run_fn(run_payload)
        if not isinstance(run_result, dict) or not bool(run_result.get("ok")):
            msg = str(run_result.get("message") if isinstance(run_result, dict) else "LTX full run failed.")
            print(f"[musicclip_ltx_queue] ERROR: {msg}", flush=True)
            return 10

        final_output = ""
        assembly_result = {}
        if bool(payload.get("assemble_after", True)):
            assemble_fn = getattr(bridge, "assemble_ltx_music_video", None)
            if not callable(assemble_fn):
                print("[musicclip_ltx_queue] ERROR: assemble_ltx_music_video is not available.", flush=True)
                return 11
            assemble_payload = dict(payload)
            assemble_payload["progress_callback"] = _progress
            assemble_payload["output_dir"] = str(run_result.get("output_dir") or payload.get("output_dir") or "")
            _progress("Starting queued LTX assembly...")
            assembly_result = assemble_fn(assemble_payload)
            if not isinstance(assembly_result, dict) or not bool(assembly_result.get("ok")):
                msg = str(assembly_result.get("message") if isinstance(assembly_result, dict) else "LTX assembly failed.")
                print(f"[musicclip_ltx_queue] ERROR: {msg}", flush=True)
                return 12
            final_output = str(assembly_result.get("final_output_path") or "")

        queue_output_file = str(payload.get("queue_output_file") or "").strip()
        if queue_output_file:
            try:
                Path(queue_output_file).parent.mkdir(parents=True, exist_ok=True)
                if final_output and os.path.isfile(final_output):
                    shutil.copy2(final_output, queue_output_file)
                else:
                    # Keep the queue from reporting an invisible success when only shot generation was requested.
                    with open(queue_output_file, "w", encoding="utf-8") as marker:
                        marker.write(json.dumps({"ok": True, "run_result": run_result, "assembly_result": assembly_result}, indent=2))
            except Exception as copy_exc:
                print(f"[musicclip_ltx_queue] ERROR: could not write queue output file: {copy_exc}", flush=True)
                return 13

        report_path = str(payload.get("queue_report_path") or "").strip()
        if report_path:
            try:
                Path(report_path).parent.mkdir(parents=True, exist_ok=True)
                with open(report_path, "w", encoding="utf-8") as f:
                    json.dump({"ok": True, "run_result": run_result, "assembly_result": assembly_result, "queue_output_file": queue_output_file}, f, indent=2, ensure_ascii=False)
            except Exception:
                pass

        _progress("Queued LTX job finished.")
        return 0
    except Exception as exc:
        print(f"[musicclip_ltx_queue] ERROR: {exc}", flush=True)
        return 1

def run_queue_payload(payload_path: str) -> int:
    """Headless entrypoint used by queued jobs.

    This is intentionally dependency-light: it reuses RenderWorker's pipeline
    but swaps Qt signals for simple stdout progress lines so worker.tools_ffmpeg
    can parse percentages.
    """
    try:
        with open(payload_path, "r", encoding="utf-8") as f:
            payload = json.load(f)
    except Exception as e:
        try:
            print(f"ERROR: failed to read payload: {e}")
        except Exception:
            pass
        return 2

    try:
        analysis = _analysis_from_dict(payload.get("analysis") or {})
        segments = _segments_from_list(payload.get("segments") or [])
        audio_path = str(payload.get("audio_path") or "")
        output_dir = str(payload.get("output_dir") or "")
        ffmpeg = str(payload.get("ffmpeg") or ffmpeg_path())
        ffprobe = str(payload.get("ffprobe") or ffprobe_path())
        tr = payload.get("target_resolution")
        target_resolution = None
        if isinstance(tr, (list, tuple)) and len(tr) == 2:
            try:
                target_resolution = (int(tr[0]), int(tr[1]))
            except Exception:
                target_resolution = None
        fit_mode = int(payload.get("fit_mode") or 0)
        transition_mode = int(payload.get("transition_mode") or 0)
        intro_fade = bool(payload.get("intro_fade", True))
        outro_fade = bool(payload.get("outro_fade", True))
        keep_source_bitrate = bool(payload.get("keep_source_bitrate", False))
        use_visual_overlay = bool(payload.get("use_visual_overlay", False))
        visual_strategy = int(payload.get("visual_strategy") or 0)
        visual_section_overrides = payload.get("visual_section_overrides") or None
        visual_overlay_opacity = float(payload.get("visual_overlay_opacity") or 0.25)
        out_name_override = payload.get("out_name_override") or None
        # Smart Director settings are serialized for reproducibility/traceability.
        # The queued job renders the already-built TimelineSegments, so these are
        # restored mainly for status/logging and future-safe payload compatibility.
        smart_scene_mode = bool(payload.get("smart_scene_mode", False))
        director_preset = _normalize_director_preset(str(payload.get("director_preset") or "Balanced"))
        scene_cut_style = _normalize_cut_style(str(payload.get("scene_cut_style") or "Auto"))
        smart_scene_payload = payload.get("smart_scene_map") or []
        smart_scene_duration_guard = bool(payload.get("smart_scene_duration_guard", True))
        try:
            smart_min_scene_len = float(payload.get("smart_min_scene_len", 1.5))
        except Exception:
            smart_min_scene_len = 1.5
        try:
            smart_max_scene_len = float(payload.get("smart_max_scene_len", 5.0))
        except Exception:
            smart_max_scene_len = 5.0
        smart_max_scene_mode = _normalize_smart_scene_max_mode(str(payload.get("smart_max_scene_mode") or "Auto (source-aware)"))
        try:
            smart_cut_timing_offset = _normalize_smart_cut_timing_offset(float(payload.get("smart_cut_timing_offset", 0.0)))
        except Exception:
            smart_cut_timing_offset = 0.0
        use_lyrics_srt_timing = bool(payload.get("use_lyrics_srt_timing", False))
        srt_path = str(payload.get("srt_path") or "")
        lyric_segments = _lyric_segments_from_list(payload.get("lyric_segments") or [])
        if use_lyrics_srt_timing and not lyric_segments and srt_path:
            if os.path.isfile(srt_path):
                try:
                    lyric_segments = load_srt_segments(srt_path)
                except Exception as e:
                    try:
                        print(f"WARNING: failed to parse SRT file '{srt_path}': {e}")
                    except Exception:
                        pass
            else:
                try:
                    print(f"WARNING: SRT file not found, continuing without lyrics: {srt_path}")
                except Exception:
                    pass
        if use_lyrics_srt_timing and lyric_segments and isinstance(smart_scene_payload, list):
            try:
                smart_scene_payload = attach_lyrics_to_scene_dicts(smart_scene_payload, lyric_segments, srt_path)
            except Exception:
                pass
        strobe_on_time_times = payload.get("strobe_on_time_times") or None
        try:
            strobe_flash_strength = float(payload.get("strobe_flash_strength") or 0.0)
        except Exception:
            strobe_flash_strength = 0.0
        try:
            strobe_flash_speed_ms = int(payload.get("strobe_flash_speed_ms") or 250)
        except Exception:
            strobe_flash_speed_ms = 250
    except Exception as e:
        try:
            print(f"ERROR: invalid payload fields: {e}")
        except Exception:
            pass
        return 3

    if smart_scene_mode:
        try:
            scene_count = len(smart_scene_payload) if isinstance(smart_scene_payload, list) else 0
            guard_txt = ""
            if smart_scene_duration_guard:
                if smart_max_scene_mode == "Manual":
                    guard_txt = f", duration guard min {smart_min_scene_len:.1f}s max {smart_max_scene_len:.1f}s"
                elif smart_max_scene_mode == "Auto (source-aware)":
                    guard_txt = f", duration guard min {smart_min_scene_len:.1f}s auto max"
                else:
                    guard_txt = f", duration guard min {smart_min_scene_len:.1f}s"
            offset_txt = f", cut offset {smart_cut_timing_offset:+.2f}s" if abs(float(smart_cut_timing_offset or 0.0)) >= 0.005 else ""
            lyrics_txt = f", lyrics {len(lyric_segments)} segments" if bool(use_lyrics_srt_timing) and lyric_segments else ""
            print(f"0% Smart director: {director_preset}, {scene_count} scenes{guard_txt}{offset_txt}{lyrics_txt}")
        except Exception:
            pass

    # Create worker and monkeypatch progress signal to stdout
    rw = RenderWorker(
        audio_path=audio_path,
        output_dir=output_dir,
        analysis=analysis,
        segments=segments,
        ffmpeg=ffmpeg,
        ffprobe=ffprobe,
        target_resolution=target_resolution,
        fit_mode=fit_mode,
        transition_mode=transition_mode,
        intro_fade=intro_fade,
        outro_fade=outro_fade,
        keep_source_bitrate=keep_source_bitrate,
        use_visual_overlay=use_visual_overlay,
        visual_strategy=visual_strategy,
        visual_section_overrides=visual_section_overrides,
        visual_overlay_opacity=visual_overlay_opacity,
        out_name_override=out_name_override,
        strobe_on_time_times=strobe_on_time_times,
        strobe_flash_strength=strobe_flash_strength,
        strobe_flash_speed_ms=strobe_flash_speed_ms,
    )

    class _DummySig:
        def emit(self, pct, msg=""):
            try:
                ip = int(pct)
            except Exception:
                ip = pct
            try:
                print(f"{ip}% {msg}".strip())
            except Exception:
                try:
                    print(f"{ip}%")
                except Exception:
                    pass

    try:
        rw.progress = _DummySig()
    except Exception:
        pass

    try:
        rw._run_impl()
        try:
            print("100% Done.")
        except Exception:
            pass
        return 0
    except Exception as e:
        try:
            print(f"ERROR: {e}")
        except Exception:
            pass
        return 1


# --------------------------- music analysis --------------------------------


def analyze_music(audio_path: str, ffmpeg: str, config: Optional[MusicAnalysisConfig] = None) -> MusicAnalysisResult:
    """Very lightweight beat + energy analysis using ffmpeg + PCM RMS."""
    tmpdir = tempfile.mkdtemp(prefix="fv_mclip_an_")
    wav_path = os.path.join(tmpdir, "mono.wav")

    cmd = [
        ffmpeg,
        "-y",
        "-i",
        audio_path,
        "-vn",
        "-ac",
        "1",
        "-ar",
        "44100",
        "-f",
        "wav",
        wav_path,
    ]
    code, out = _run_ffmpeg(cmd)
    if code != 0 or not os.path.exists(wav_path):
        shutil.rmtree(tmpdir, ignore_errors=True)
        raise RuntimeError("Failed to convert audio for analysis:\n" + out)

    import wave
    import struct

    with wave.open(wav_path, "rb") as wf:
        fr = wf.getframerate()
        total_frames = wf.getnframes()
        duration = total_frames / float(fr)

        win_size = int(fr * 0.05)  # 50ms windows
        values = []
        times = []
        read = 0
        while read < total_frames:
            n = min(win_size, total_frames - read)
            raw = wf.readframes(n)
            read += n
            if not raw:
                break
            count = len(raw) // 2  # 16-bit
            if count == 0:
                rms = 0.0
            else:
                fmt = "<" + "h" * count
                samples = struct.unpack(fmt, raw)
                acc = 0.0
                for s in samples:
                    acc += (s / 32768.0) ** 2
                rms = math.sqrt(acc / count)
            values.append(rms)
            times.append(len(values) * (n / float(fr)))

    shutil.rmtree(tmpdir, ignore_errors=True)

    if not values:
        raise RuntimeError("Audio analysis produced no samples.")

    max_v = max(values) or 1.0
    norm = [v / max_v for v in values]

    mean = sum(norm) / len(norm)
    var = sum((v - mean) ** 2 for v in norm) / len(norm)
    std = math.sqrt(var)

    # Apply beat sensitivity from config.
    # Lower = much stricter / fewer beats, higher = looser / more beats.
    if config is not None:
        try:
            raw_val = float(config.sensitivity)
        except Exception:
            raw_val = 10.0
    else:
        raw_val = 10.0

    # Slider now uses a direct 0..20 scale where:
    #   0  = ultra strict (barely detect anything except the clearest peaks)
    #   10 = normal default
    #   20 = very loose
    sens = max(0.0, min(20.0, raw_val))

    # Use a deliberately non-linear mapping so the low end becomes much stricter
    # than before. That gives the user real room to suppress busy sub-second cuts.
    if sens <= 10.0:
        # 10 -> 1.00x, 0 -> 3.60x
        frac = (10.0 - sens) / 10.0
        scale = 1.0 + (frac ** 1.75) * 2.60
    else:
        # 10 -> 1.00x, 20 -> 0.58x
        frac = (sens - 10.0) / 10.0
        scale = 1.0 - (frac ** 1.20) * 0.42

    if scale < 0.55:
        scale = 0.55
    elif scale > 3.60:
        scale = 3.60

    beat_thr = mean + std * 0.7 * scale
    major_thr = mean + std * 1.4 * scale

    beats: List[Beat] = []
    last_peak = -9999
    min_dist = int(0.15 / 0.05)  # 150ms

    for i in range(1, len(norm) - 1):
        v = norm[i]
        if v < beat_thr:
            continue
        if v >= norm[i - 1] and v >= norm[i + 1]:
            if i - last_peak < min_dist:
                if beats and v > beats[-1].strength:
                    beats[-1] = Beat(
                        time=times[i],
                        strength=v,
                        kind="major" if v >= major_thr else "minor",
                    )
                    last_peak = i
                continue
            kind = "major" if v >= major_thr else "minor"
            beats.append(Beat(time=times[i], strength=v, kind=kind))
            last_peak = i

    # If we have beats but there's a long quiet tail with no peaks,
    # synthesize gentle extra beats in the tail so quiet / outro parts
    # still have material for the timeline.
    if beats:
        tail = duration - beats[-1].time
        if tail > 5.0:
            # Place minor beats at regular spacing in the tail.
            # Use a stable pattern so results remain predictable.
            num_virtual = max(2, min(16, int(tail / 1.0)))
            if num_virtual > 0:
                spacing = tail / (num_virtual + 1)
                t = beats[-1].time + spacing
                while t < duration - 0.25:
                    beats.append(
                        Beat(
                            time=t,
                            strength=mean,
                            kind="minor",
                        )
                    )
                    t += spacing

    # Ensure beats are sorted in time in case virtual beats were appended
    beats.sort(key=lambda b: b.time)

    # Energy profile in 1s windows
    win1 = int(1.0 / 0.05)
    e_vals = []
    e_times = []
    for i in range(0, len(norm), win1):
        chunk = norm[i : i + win1]
        if not chunk:
            continue
        e_vals.append(sum(chunk) / len(chunk))
        e_times.append(i * 0.05)

    if not e_vals:
        e_vals = [mean]
        e_times = [0.0]

    e_mean = sum(e_vals) / len(e_vals)
    e_var = sum((v - e_mean) ** 2 for v in e_vals) / len(e_vals)
    e_std = math.sqrt(e_var)

    low_thr = e_mean - 0.4 * e_std
    high_thr = e_mean + 0.4 * e_std

    sections: List[Section] = []
    cur_kind = None
    cur_start = 0.0

    def flush(end_t: float):
        nonlocal cur_kind, cur_start
        if cur_kind is None:
            return
        sections.append(Section(start=cur_start, end=end_t, kind=cur_kind))

    for i, v in enumerate(e_vals):
        t = e_times[i]
        if v < low_thr:
            kind = "intro_or_break"
        elif v > high_thr:
            kind = "chorus_or_drop"
        else:
            kind = "verse_or_mid"
        if cur_kind is None:
            cur_kind = kind
            cur_start = t
        elif kind != cur_kind:
            flush(t)
            cur_kind = kind
            cur_start = t
    flush(duration)

    labelled: List[Section] = []
    chorus_seen = False
    for idx, s in enumerate(sections):
        if idx == 0:
            k = "intro"
        elif s.kind == "chorus_or_drop":
            k = "chorus" if not chorus_seen else "drop"
            chorus_seen = True
        elif s.kind == "intro_or_break":
            k = "break"
        else:
            k = "verse"
        labelled.append(Section(start=s.start, end=s.end, kind=k))

    # Ensure we always end on an explicit "outro" section.
    if labelled:
        last = labelled[-1]
        last_duration = max(0.0, last.end - last.start)
        # If the final segment is extremely short, merge it with the
        # previous one so the outro feels like a real section instead
        # of a tiny fragment.
        if last_duration < 1.25 and len(labelled) >= 2:
            prev = labelled[-2]
            merged = Section(
                start=prev.start,
                end=last.end,
                kind="outro",
            )
            labelled[-2:] = [merged]
        else:
            labelled[-1] = Section(
                start=last.start,
                end=last.end,
                kind="outro",
            )

    return MusicAnalysisResult(beats=beats, sections=labelled, duration=duration)




def discover_video_sources(video_input: str, ffprobe: str) -> List[ClipSource]:
    """Return a list of ClipSource from a file, directory, or a '|' separated list of files."""
    exts = {".mp4", ".mov", ".mkv", ".avi", ".webm", ".mpg", ".mpeg"}
    sources: List[ClipSource] = []

    # Multiple explicit files
    if "|" in video_input:
        parts = [p.strip() for p in video_input.split("|") if p.strip()]
        for raw in parts:
            path = os.path.abspath(raw)
            if not os.path.isfile(path):
                continue
            _, ext = os.path.splitext(path)
            if ext.lower() not in exts:
                continue
            dur = _ffprobe_duration(ffprobe, path)
            if dur and dur > 0:
                sources.append(ClipSource(path=path, duration=dur))
        return sources

    # Single file or directory
    video_input = os.path.abspath(video_input)

    if os.path.isdir(video_input):
        for name in sorted(os.listdir(video_input)):
            path = os.path.join(video_input, name)
            if not os.path.isfile(path):
                continue
            _, ext = os.path.splitext(path)
            if ext.lower() not in exts:
                continue
            dur = _ffprobe_duration(ffprobe, path)
            if dur and dur > 0:
                sources.append(ClipSource(path=path, duration=dur))
    elif os.path.isfile(video_input):
        dur = _ffprobe_duration(ffprobe, video_input)
        if dur and dur > 0:
            sources.append(ClipSource(path=video_input, duration=dur))

    return sources

# --------------------------- timeline builder ------------------------------

def build_timeline(
    analysis: MusicAnalysisResult,
    sources: List[ClipSource],
    fx_level: str,
    microclip_mode: int,
    beats_per_segment: int,
    transition_mode: int,
    clip_order_mode: int,
    force_full_length: bool,
    seed_enabled: bool,
    seed_value: int,
    transition_random: bool,
    transition_modes_enabled: Optional[List[int]],
    intro_transitions_only: bool = False,
    slow_motion_enabled: bool = False,
    slow_motion_factor: float = 1.0,
    slow_motion_sections: Optional[List[str]] = None,
    slow_motion_random: bool = False,
    cine_enable: bool = False,
    cine_freeze: bool = False,
    cine_stutter: bool = False,
    cine_tear_v: bool = False,
    cine_tear_v_strength: float = 0.7,
    cine_tear_h: bool = False,
    cine_tear_h_strength: float = 0.7,
    cine_color_cycle: bool = False,
    cine_color_cycle_speed_ms: int = 400,
    cine_reverse: bool = False,
    cine_speedup_forward: bool = False,
    cine_speedup_forward_factor: float = 1.5,
    cine_speedup_backward: bool = False,
    cine_speedup_backward_factor: float = 1.5,
    cine_speed_ramp: bool = False,
    cine_freeze_len: float = 0.5,
    cine_freeze_zoom: float = 0.15,
    cine_stutter_repeats: int = 3,
    cine_reverse_len: float = 0.5,
    cine_ramp_in: float = 0.25,
    cine_ramp_out: float = 0.25,
    cine_boomerang: bool = False,
    cine_boomerang_bounces: int = 2,
    cine_dimension: bool = False,
    cine_pan916: bool = False,
    cine_pan916_speed_ms: int = 400,
    cine_pan916_parts: int = 3,
    cine_pan916_transparent: bool = False,
    cine_pan916_random: bool = False,
    cine_mosaic: bool = False,
    cine_mosaic_screens: int = 4,
    cine_mosaic_random: bool = False,
    cine_flip: bool = False,
    cine_rotate: bool = False,
    cine_rotate_max_degrees: float = 20.0,
    cine_multiply: bool = False,
    cine_multiply_screens: int = 4,
    cine_multiply_random: bool = False,
    cine_dolly: bool = False,
    cine_dolly_strength: float = 0.4,
    cine_kenburns: bool = False,
    cine_kenburns_strength: float = 0.35,
    cine_motion_dir: int = 0,
    audio_duration: float | None = None,
    impact_enable: bool = False,
    impact_flash: bool = False,
    impact_shock: bool = False,
    impact_echo_trail: bool = False,
    impact_confetti: bool = False,
    impact_zoom: bool = False,
    impact_shake: bool = False,
    impact_fog: bool = False,
    impact_fire_gold: bool = False,
    impact_fire_multi: bool = False,
    impact_color_cycle: bool = False,
    impact_random: bool = False,
    impact_flash_strength: float = 0.8,
    impact_flash_speed_ms: int = 250,
    impact_shock_strength: float = 0.75,
    impact_echo_trail_strength: float = 0.7,
    impact_confetti_density: float = 0.7,
    impact_zoom_amount: float = 0.2,
    impact_shake_strength: float = 0.6,
    impact_fog_density: float = 0.65,
    impact_fire_gold_intensity: float = 0.75,
    impact_fire_multi_intensity: float = 0.8,
    impact_color_cycle_speed: float = 0.7,
    strobe_on_time: bool = False,
    strobe_on_time_times: Optional[List[float]] = None,
    image_sources: Optional[List[ClipSource]] = None,
    section_overrides: Optional[Dict[int, ClipSource]] = None,
    image_segment_interval: int = 0,
    smart_scene_mode: bool = False,
    director_preset: str = "Balanced",
    scene_cut_style: str = "Auto",
    smart_scene_map: Optional[List[MusicScene]] = None,
    smart_scene_info: Optional[Dict[str, object]] = None,
    smart_scene_duration_guard: bool = True,
    smart_min_scene_len: float = 1.5,
    smart_max_scene_len: float = 5.0,
    smart_max_scene_mode: str = "Auto (source-aware)",
    smart_cut_timing_offset: float = 0.0,
) -> List[TimelineSegment]:


    """Build a musical timeline from beats, sections and sources.

    fx_level:
        "minimal", "moderate", "high"

    microclip_mode:
        0 = off
        1 = only in high-energy sections (chorus / drops)
        2 = whole track
        3 = verses only (microclips inside verse sections; longer cuts elsewhere)

    transition_mode:
        0 = soft fades
        1 = hard cuts
        2 = mixed (fades + flash cuts sometimes)

    clip_order_mode:
        0 = random (default)
        1 = sequential
        2 = shuffle (no repeats until all clips used)
    """
    if not sources:
        return []

    if image_sources is None:
        image_sources = []

    if seed_enabled:
        random.seed(int(seed_value) & 0xFFFFFFFF)

    smart_scene_enabled = bool(smart_scene_mode)
    director_preset = _normalize_director_preset(director_preset)
    scene_cut_style = _normalize_cut_style(scene_cut_style)
    smart_max_scene_mode = _normalize_smart_scene_max_mode(smart_max_scene_mode)
    smart_cut_timing_offset = _normalize_smart_cut_timing_offset(smart_cut_timing_offset)
    smart_source_durations = _source_durations_from_sources(sources)
    smart_duration_guard_info = _resolve_smart_scene_duration_guard(
        enabled=bool(smart_scene_duration_guard),
        min_scene_len=smart_min_scene_len,
        max_scene_len=smart_max_scene_len,
        max_scene_mode=smart_max_scene_mode,
        source_clip_durations=smart_source_durations,
    )

    # Helper: map a logical time (seconds) to a section label, including 'outro' for the final section.
    def _section_label_at(time_t: float) -> str:
        sections = analysis.sections
        if not sections:
            return "verse"
        last_idx = len(sections) - 1
        for idx, s in enumerate(sections):
            # Include the tail of the last section
            if s.start <= time_t < s.end or (idx == last_idx and time_t >= s.start):
                if idx == last_idx and s.kind not in ("intro",):
                    return "outro"
                return s.kind
        # Fallback: treat as part of the last section
        return sections[-1].kind

    def _section_index_at(time_t: float) -> Optional[int]:
        """Return the index of the section that contains the given time."""
        sections = analysis.sections
        if not sections:
            return None
        last_idx = len(sections) - 1
        for idx, s in enumerate(sections):
            if s.start <= time_t < s.end or (idx == last_idx and time_t >= s.start):
                return idx
        return last_idx

    def _apply_slow_motion(segments: List[TimelineSegment],
                           centers: List[float],
                           section_labels: List[str]) -> None:
        if not slow_motion_enabled or not segments:
            return

        # Normalize configuration
        selected_sections = set()
        if slow_motion_sections:
            selected_sections = {str(k).lower() for k in slow_motion_sections}

        # 1) Direct section-based slow motion
        slow_flags = [False] * len(segments)
        for idx, label in enumerate(section_labels):
            lbl = (label or "").lower()
            # Ignore intro when transitions-only is enabled
            if intro_transitions_only and lbl == "intro":
                continue
            if lbl in selected_sections:
                slow_flags[idx] = True

        # 2) Random slow motion: at most one event per 60 seconds of timeline
        if slow_motion_random:
            cumulative = 0.0
            centers_timeline: List[float] = []
            for seg in segments:
                center = cumulative + max(seg.duration, 0.0) * 0.5
                centers_timeline.append(center)
                cumulative += max(seg.duration, 0.0)

            blocks = {}
            for idx, t in enumerate(centers_timeline):
                if slow_flags[idx]:
                    continue  # already slowed via section selection
                # Skip intro when transitions-only is enabled
                try:
                    lbl = (section_labels[idx] or "").lower() if idx < len(section_labels) else ""
                except Exception:
                    lbl = ""
                if intro_transitions_only and lbl == "intro":
                    continue
                block = int(t // 60.0)
                blocks.setdefault(block, []).append(idx)

            for idx_list in blocks.values():
                if not idx_list:
                    continue
                choice = random.choice(idx_list)
                slow_flags[choice] = True

        # Apply final slow factors
        for idx, seg in enumerate(segments):
            if slow_flags[idx]:
                seg.slow_factor = float(slow_motion_factor or 1.0)
            else:
                seg.slow_factor = 1.0


    def _apply_cinematic_effects(segments: List[TimelineSegment], allow_mosaic: bool, section_labels: Optional[List[str]] = None) -> None:
        """Mark segments for rare cinematic effects (freeze, stutter, reverse, speedups, ramps).

        The logic is intentionally conservative: for the freeze / stutter / reverse
        effects we pick at most one segment per 5 seconds of video timeline, and
        only when the global cinematic toggle plus the corresponding effect toggle
        are enabled. Speed ramps are applied to all slow-motion segments when the
        option is on, but they currently piggy-back on the existing slow-factor
        logic rather than splitting segments.
        """
        if not cine_enable or not segments:
            return

        # Collect which cinematic effects are globally enabled.
        enabled_effects: List[str] = []
        # Dimension (portal shapes) uses a shuffle-bag so all shapes play once
        # before repeating.
        dimension_modes: List[str] = ["rect", "trapezoid", "diamond", "portrait"]
        dimension_bag: List[str] = []

        def _pick_dimension_kind() -> str:
            nonlocal dimension_bag
            if not dimension_bag:
                dimension_bag = list(dimension_modes)
                random.shuffle(dimension_bag)
            try:
                return str(dimension_bag.pop())
            except Exception:
                return "rect"

        boomerang_indices: List[int] = []
        used_segments = set()
        if cine_freeze:
            enabled_effects.append("freeze")
        if cine_tear_v:
            enabled_effects.append("tear_v")
        if cine_tear_h:
            enabled_effects.append("tear_h")

        if cine_color_cycle:
            enabled_effects.append("color_cycle")

        if cine_stutter:
            enabled_effects.append("stutter")
        if cine_reverse:
            enabled_effects.append("reverse")
        if cine_speedup_forward:
            enabled_effects.append("speedup_forward")
        if cine_speedup_backward:
            enabled_effects.append("speedup_backward")
        if cine_boomerang:
            enabled_effects.append("boomerang")
        if cine_dimension:
            enabled_effects.append("dimension")
        if cine_pan916:
            enabled_effects.append("pan916")
        # Mosaic uses the same 'one event per 5s' rule as the other cinematic effects.
        # Safety: only enable Mosaic when there are enough video clips loaded.
        if cine_mosaic and allow_mosaic:
            enabled_effects.append("mosaic")
        if cine_flip:
            enabled_effects.append("flip")
        if cine_rotate:
            enabled_effects.append("rotate")
        # Multiply (same-clip multi-screen) follows the same cadence as Mosaic.
        if cine_multiply:
            enabled_effects.append("multiply")

        # If nothing except ramps is enabled, we only tag slow-motion segments below.
        # (Still honour cine_enable so the user can quickly disable everything.)
        # Compute segment centres on the *video* timeline so we can respect the
        # "about once every 5 seconds" requirement.
        centers: List[float] = []
        cumulative = 0.0
        for seg in segments:
            duration = max(0.0, float(getattr(seg, "duration", 0.0)))
            centers.append(cumulative + duration * 0.5)
            cumulative += duration


        # Eligible indices (skip intro when transitions-only is enabled)
        eligible_idx: List[int] = list(range(len(segments)))
        if intro_transitions_only and segment_labels:
            eligible_idx = [i for i in eligible_idx if (section_labels[i] or "").lower() != "intro"]
        if smart_scene_enabled:
            filtered_idx: List[int] = []
            for i in eligible_idx:
                sc = segment_scenes[i] if i < len(segment_scenes) else None
                if _smart_scene_allows_cinematic(sc, director_preset):
                    filtered_idx.append(i)
            eligible_idx = filtered_idx

        if enabled_effects and cumulative > 0.0:
            # Use a cooldown so cinematic effects don't spam. Smart Director
            # adjusts the cooldown per preset instead of changing renderer logic.
            CINE_COOLDOWN_SEC = _smart_cinematic_cooldown(director_preset) if smart_scene_enabled else 10.0

            # Shuffle-bag: cycle through all enabled cinematic effects once before repeating.
            effect_bag: List[str] = []

            def _pick_effect_name() -> str:
                nonlocal effect_bag
                if not effect_bag:
                    effect_bag = list(enabled_effects)
                    random.shuffle(effect_bag)
                try:
                    return str(effect_bag.pop())
                except Exception:
                    return str(random.choice(enabled_effects))

            buckets: dict[int, List[int]] = {}
            for idx in eligible_idx:
                t = centers[idx]
                # Group by 10-second blocks to keep selection efficient, but enforce
                # a strict cooldown based on the exact selected time.
                block = int(t // CINE_COOLDOWN_SEC)
                buckets.setdefault(block, []).append(idx)

            last_cine_time = -1e9
            for block_idx in sorted(buckets.keys()):
                idx_list = buckets[block_idx]

                if not idx_list:
                    continue

                # Only pick segments that satisfy the cooldown vs the previous cinematic event.
                ok = [i for i in idx_list if (centers[i] - last_cine_time) >= CINE_COOLDOWN_SEC]
                if not ok:
                    continue

                if smart_scene_enabled:
                    def _cine_weight(i: int) -> float:
                        sc = segment_scenes[i] if i < len(segment_scenes) else None
                        try:
                            return float(getattr(sc, "effect_intensity", 0.0) or 0.0) + random.random() * 0.15
                        except Exception:
                            return random.random() * 0.15
                    seg_idx = max(ok, key=_cine_weight)
                else:
                    seg_idx = random.choice(ok)
                seg = segments[seg_idx]
                effect_name = _pick_effect_name()
                last_cine_time = float(centers[seg_idx])
                if effect_name == "freeze":

                    seg.cine_freeze = True
                    seg.cine_freeze_len = float(max(0.10, min(1.0, cine_freeze_len)))
                    # Slider stays the same (0.0–0.5), but now drives the Shutter-pop intensity.
                    seg.cine_freeze_zoom = float(max(0.0, min(0.5, cine_freeze_zoom)))
                    # Random left/right chroma direction so repeats feel less samey.
                    seg.cine_freeze_dir = random.choice([-1, 1])
                elif effect_name == "stutter":
                    seg.cine_stutter = True
                    seg.cine_stutter_repeats = int(max(2, min(5, cine_stutter_repeats)))
                elif effect_name == "tear_v":
                    seg.cine_tear_v = True

                    # Base strength from slider (0.1–1.0)
                    base = float(max(0.1, min(1.0, cine_tear_v_strength)))

                    # Per-event strength jitter (keeps it from feeling identical)
                    jitter = random.uniform(0.85, 1.15)
                    seg.cine_tear_v_strength = float(max(0.1, min(1.0, base * jitter)))

                    # Per-event direction (left slice goes left OR right, right slice mirrors)
                    # We store it on the segment; no dataclass change required.
                    seg.cine_tear_v_dir = random.choice([-1, 1])
                elif effect_name == "tear_h":
                    seg.cine_tear_h = True

                    # Base strength from slider (0.1–1.0)
                    base = float(max(0.1, min(1.0, cine_tear_h_strength)))

                    # Per-event strength jitter (keeps it from feeling identical)
                    jitter = random.uniform(0.85, 1.15)
                    seg.cine_tear_h_strength = float(max(0.1, min(1.0, base * jitter)))

                    # Per-event direction (top slice goes up OR down, bottom slice mirrors)
                    # We store it on the segment; no dataclass change required.
                    seg.cine_tear_h_dir = random.choice([-1, 1])
                elif effect_name == "color_cycle":
                    seg.cine_color_cycle = True
                    try:
                        ms = int(cine_color_cycle_speed_ms)
                    except Exception:
                        ms = 400
                    ms = max(100, min(1000, ms))
                    # Snap to 50ms steps like the other speed sliders.
                    ms = int(round(ms / 50.0) * 50)
                    seg.cine_color_cycle_speed_ms = ms
                elif effect_name == "reverse":
                    seg.cine_reverse = True
                    seg.cine_reverse_len = float(max(0.10, min(1.5, cine_reverse_len)))
                    # Preserve the musical segment duration.
                    # Store a dedicated short window for the reverse-bounce renderer.
                    try:
                        win = float(seg.cine_reverse_len or 0.0)
                    except Exception:
                        win = 0.0
                    if win <= 0.0:
                        win = 0.5
                    try:
                        base_len = float(getattr(seg, "duration", 0.0) or 0.0)
                    except Exception:
                        base_len = 0.0
                    if base_len > 0.0:
                        win = min(win, base_len)
                    seg.cine_reverse_window = win
                elif effect_name == "speedup_forward":
                    seg.cine_speedup_forward = True
                    try:
                        factor = float(cine_speedup_forward_factor)
                    except Exception:
                        factor = 1.5
                    factor = max(1.25, min(4.0, factor))
                    seg.cine_speedup_forward_factor = factor
                    # Reuse the shared speed pipeline.
                    seg.slow_factor = factor
                elif effect_name == "speedup_backward":
                    seg.cine_speedup_backward = True
                    try:
                        factor = float(cine_speedup_backward_factor)
                    except Exception:
                        factor = 1.5
                    factor = max(1.25, min(4.0, factor))
                    seg.cine_speedup_backward_factor = factor
                    seg.cine_reverse = True
                    seg.slow_factor = factor
                elif effect_name == "boomerang":
                    # Mark this segment as a boomerang loop                    boomerang_indices.append(seg_idx)
                    seg.cine_boomerang = True
                    try:
                        bounces = int(cine_boomerang_bounces)
                    except Exception:
                        bounces = 2
                    bounces = max(1, min(9, bounces))
                    seg.cine_boomerang_bounces = bounces
                    # Ensure the clip region used for this segment lives fully
                    # inside a short punchy window of the source clip, but do NOT
                    # shrink the musical segment duration. We store a dedicated
                    # boomerang window length for the renderer.
                    try:
                        max_window = 0.25  # use only the first ~0.25 second of the source clip for boomerang
                        target_len = float(seg_trim_dur or 0.0)
                        if target_len <= 0.0:
                            target_len = 0.1
                        cur_dur = min(target_len, max_window)
                        if cur_dur <= 0.0:
                            cur_dur = 0.1
                        setattr(seg, "cine_boomerang_window", cur_dur)
                        cur_start = float(getattr(seg, "clip_start", 0.0) or 0.0)
                        if cur_start < 0.0:
                            cur_start = 0.0
                        if cur_start + cur_dur > max_window:
                            cur_start = max(0.0, max_window - cur_dur)
                        seg.clip_start = cur_start
                    except Exception:
                        # As a safety fallback, just pin to the absolute start.
                        try:
                            setattr(seg, "cine_boomerang_window", 0.25)
                            seg.clip_start = 0.0
                        except Exception:
                            pass
                elif effect_name == "dimension":
                    # Dimension portal: show the segment inside a randomly chosen portal shape.
                    # Uses a shuffle-bag so each shape is used once before repeating.
                    seg.cine_dimension = True
                    seg.cine_dimension_kind = _pick_dimension_kind()

                elif effect_name == "pan916":
                    # Slice reveal (boomerang across 3 positions).
                    seg.cine_pan916 = True
                    try:
                        ms = int(cine_pan916_speed_ms)
                    except Exception:
                        ms = 400
                    ms = max(200, min(1000, ms))
                    # Snap to the 50ms steps used by the UI slider.
                    ms = int(round(ms / 50.0) * 50)
                    seg.cine_pan916_speed_ms = ms
                    # Extra options: number of slices and background transparency.
                    seg.cine_pan916_random = bool(cine_pan916_random)
                    if seg.cine_pan916_random:
                        # Random slice count (deterministic when the user enables seeding).
                        parts = int(random.randint(2, 6))
                    else:
                        try:
                            parts = int(cine_pan916_parts)
                        except Exception:
                            parts = 3
                        parts = max(2, min(6, parts))
                    seg.cine_pan916_parts = parts
                    seg.cine_pan916_transparent = bool(cine_pan916_transparent)
                    if seg.cine_pan916_random:
                        # Deterministic if the user enabled seeding above.
                        period = max(2, (2 * parts - 2))
                        seg.cine_pan916_phase = int(random.randint(0, max(0, period - 1)))
                        seg.cine_pan916_flip_lr = bool(random.getrandbits(1))
                    else:
                        seg.cine_pan916_phase = 0
                        seg.cine_pan916_flip_lr = False

                elif effect_name == "mosaic":
                    seg.cine_mosaic = True
                    if cine_mosaic_random:
                        # Pick any layout between 2 and 9 screens each time Mosaic is assigned.
                        screens = random.randint(2, 9)
                    else:
                        try:
                            screens = int(cine_mosaic_screens)
                        except Exception:
                            screens = 4
                        # Clamp to the supported 2–9 range
                        screens = max(2, min(9, screens))
                    seg.cine_mosaic_screens = screens

                elif effect_name == "flip":
                    # Mark this segment for a 180° upside-down hit, and also
                    # apply a rotating-screen spin so it feels intentional.
                    seg.cine_flip = True
                    seg.cine_rotate = True
                    try:
                        max_deg = float(cine_rotate_max_degrees)
                    except Exception:
                        max_deg = 20.0
                    # Clamp to a safe range to avoid nausea.
                    max_deg = max(5.0, min(90.0, max_deg))
                    seg.cine_rotate_degrees = max_deg

                elif effect_name == "rotate":
                    # Apply a short rotating-screen hit with a random angle
                    # up to the user-specified maximum.
                    seg.cine_rotate = True
                    try:
                        max_deg = float(cine_rotate_max_degrees)
                    except Exception:
                        max_deg = 20.0
                    # Clamp to a safe range to avoid nausea.
                    max_deg = max(5.0, min(90.0, max_deg))
                    seg.cine_rotate_degrees = max_deg

                elif effect_name == "multiply":
                    # Multiply uses the same layouts as Mosaic, but
                    # shows multiple copies of *the same* clip instead of
                    # filling the grid with different sources.
                    seg.cine_multiply = True
                    if cine_multiply_random:
                        # Pick any layout between 2 and 9 screens each time Multiply is assigned.
                        screens = random.randint(2, 9)
                    else:
                        try:
                            screens = int(cine_multiply_screens)
                        except Exception:
                            screens = 4
                        # Clamp to the supported 2–9 range
                        screens = max(2, min(9, screens))
                    seg.cine_multiply_screens = screens

        # Camera motion hits (dolly-zoom / Ken Burns) – rarer, about one per 15s block.
        camera_enabled = (cine_dolly or cine_kenburns)
        if camera_enabled and cumulative > 0.0:
            cam_buckets: dict[int, List[int]] = {}
            for idx in eligible_idx:
                t = centers[idx]
                block = int(t // 15.0)
                cam_buckets.setdefault(block, []).append(idx)

            def _pick_motion_dir(global_dir: int, allowed_dirs) -> int:
                try:
                    g = int(global_dir)
                except Exception:
                    g = 0
                allowed_list = list(allowed_dirs)
                if not allowed_list:
                    return 0
                # If the user picked a specific direction and it's allowed, honour it.
                if g in allowed_list:
                    return g
                # Otherwise pick a random direction from the allowed set.
                return random.choice(allowed_list)

            available_cams: List[str] = []
            if cine_dolly:
                available_cams.append("dolly")
            if cine_kenburns:
                available_cams.append("kenburns")

            for block_idx, idx_list in cam_buckets.items():
                if not idx_list or not available_cams:
                    continue
                seg_idx = random.choice(idx_list)
                seg = segments[seg_idx]
                which = random.choice(available_cams)
                if which == "dolly":
                    seg.cine_dolly = True
                    seg.cine_dolly_strength = float(max(0.10, min(1.0, cine_dolly_strength)))
                    seg.cine_motion_dir = int(_pick_motion_dir(cine_motion_dir, (1, 2)))
                elif which == "kenburns":
                    seg.cine_kenburns = True
                    seg.cine_kenburns_strength = float(max(0.10, min(1.0, cine_kenburns_strength)))
                    seg.cine_motion_dir = int(_pick_motion_dir(cine_motion_dir, (3, 4, 5, 6)))

        # Speed ramps: tag all slow-motion segments (slow_factor != 1.0) when enabled.
        if cine_speed_ramp and slow_motion_enabled:
            for seg in segments:
                if float(getattr(seg, "slow_factor", 1.0)) != 1.0:
                    seg.cine_speed_ramp = True
                    seg.cine_ramp_in = float(max(0.05, min(0.60, cine_ramp_in)))
                    seg.cine_ramp_out = float(max(0.05, min(0.60, cine_ramp_out)))

    


    def _apply_break_impact_fx(segments: List[TimelineSegment],
                               centers: List[float],
                               segment_labels: Optional[List[str]] = None) -> None:
        """Mark segments that should receive 'break impact' FX (first beat after a break).

        We scan music sections for 'break' regions, then for each break we find the
        first strong beat that follows the end of the break (within a short window).
        The segment whose logical centre is closest to that beat (or whose
        approximate coverage includes it) is tagged as an impact segment and
        receives break impact parameters according to the UI configuration.

        If no explicit 'break' sections are found, we fall back to section boundaries
        into high–energy parts (chorus / drop). As a last resort, we pick the first
        beat after the largest silence / gap between beats so that the feature still
        does something musical on simpler tracks.
        """
        if not impact_enable or not segments:
            return

        beats = analysis.beats
        if not beats:
            return

        impact_times: List[float] = []

        # --- Primary: merged 'break' clusters --------------------------------
        raw_breaks: List[Section] = [sec for sec in analysis.sections if sec.kind == "break"]
        if raw_breaks:
            raw_breaks.sort(key=lambda s: s.start)
            merged: List[Section] = []
            cur = raw_breaks[0]
            gap_limit = 4.0  # seconds; small gaps are treated as one big build‑up
            for sec in raw_breaks[1:]:
                if sec.start - cur.end <= gap_limit:
                    # Extend current build‑up cluster.
                    cur = Section(start=cur.start, end=max(cur.end, sec.end), kind="break")
                else:
                    merged.append(cur)
                    cur = sec
            merged.append(cur)

            for mb in merged:
                end_t = float(mb.end)
                # Consider beats up to a few seconds after the *merged* break.
                window_end = min(analysis.duration, end_t + 4.0)
                cand = [b for b in beats if end_t <= b.time <= window_end]
                if not cand:
                    continue
                majors = [b for b in cand if b.kind == "major"]
                if majors:
                    chosen = min(majors, key=lambda b: b.time)
                else:
                    chosen = min(cand, key=lambda b: b.time)
                impact_times.append(chosen.time)

        # --- Fallback 1: boundaries into chorus / drop -----------------------
        if not impact_times and analysis.sections:
            for prev, cur in zip(analysis.sections, analysis.sections[1:]):
                if cur.kind in ("chorus", "drop") and cur.start > prev.end:
                    start_t = float(prev.end)
                    window_end = min(analysis.duration, float(cur.start) + 4.0)
                    cand = [b for b in beats if start_t <= b.time <= window_end]
                    if not cand:
                        continue
                    majors = [b for b in cand if b.kind == "major"]
                    if majors:
                        chosen = min(majors, key=lambda b: b.time)
                    else:
                        chosen = min(cand, key=lambda b: b.time)
                    impact_times.append(chosen.time)

        # --- Fallback 2: largest beat gap (main drop guess) ------------------
        if not impact_times and len(beats) >= 2:
            max_gap = 0.0
            drop_time = None
            for i in range(len(beats) - 1):
                gap = float(beats[i + 1].time - beats[i].time)
                if gap > max_gap:
                    max_gap = gap
                    drop_time = float(beats[i + 1].time)
            # Require a reasonably long gap so we don't fire on micro‑pauses.
            if drop_time is not None and max_gap >= 1.0:
                impact_times.append(drop_time)

        if not impact_times:
            return

        # Prepare list of enabled effects for selection.
        enabled_effect_names: List[str] = []
        if impact_flash:
            enabled_effect_names.append("flash")
        if impact_shock:
            enabled_effect_names.append("shock")
        if impact_echo_trail:
            enabled_effect_names.append("echo_trail")
        if impact_confetti:
            enabled_effect_names.append("confetti")
        if impact_zoom:
            enabled_effect_names.append("zoom")
        if impact_shake:
            enabled_effect_names.append("shake")
        if impact_fog:
            enabled_effect_names.append("fog")
        if impact_fire_gold:
            enabled_effect_names.append("fire_gold")
        if impact_fire_multi:
            enabled_effect_names.append("fire_multi")
        if impact_color_cycle:
            enabled_effect_names.append("color_cycle")

        if not enabled_effect_names:
            # Nothing to do even if master toggle is on.
            return

        # Helper to assign parameters for a chosen set of effect names on a segment.
        def _tag_segment(seg: TimelineSegment, chosen_effects: List[str]) -> None:
            seg.is_break_impact = True

            seg.impact_flash_strength = impact_flash_strength if "flash" in chosen_effects else 0.0
            seg.impact_flash_speed_ms = impact_flash_speed_ms if "flash" in chosen_effects else 0
            seg.impact_shock_strength = impact_shock_strength if "shock" in chosen_effects else 0.0
            seg.impact_echo_trail_strength = impact_echo_trail_strength if "echo_trail" in chosen_effects else 0.0
            seg.impact_confetti_density = impact_confetti_density if "confetti" in chosen_effects else 0.0
            seg.impact_zoom_amount = impact_zoom_amount if "zoom" in chosen_effects else 0.0
            seg.impact_shake_strength = impact_shake_strength if "shake" in chosen_effects else 0.0
            seg.impact_fog_density = impact_fog_density if "fog" in chosen_effects else 0.0
            seg.impact_fire_gold_intensity = impact_fire_gold_intensity if "fire_gold" in chosen_effects else 0.0
            seg.impact_fire_multi_intensity = impact_fire_multi_intensity if "fire_multi" in chosen_effects else 0.0
            seg.impact_color_cycle_speed = impact_color_cycle_speed if "color_cycle" in chosen_effects else 0.0

        # Map each impact time to the segment whose centre best matches it.
        impact_candidates: List[int] = []
        for t_imp in impact_times:
            best_idx: Optional[int] = None
            best_dist: Optional[float] = None

            for idx, seg in enumerate(segments):
                seg_len = max(0.1, float(getattr(seg, "duration", 0.0)))
                center_t = centers[idx] if idx < len(centers) else 0.0
                start_t = center_t - 0.5 * seg_len
                end_t = center_t + 0.5 * seg_len

                if start_t <= t_imp <= end_t:
                    best_idx = idx
                    break

                # Fallback: pick segment whose centre is closest to the impact time.
                dist = abs(center_t - t_imp)
                if best_dist is None or dist < best_dist:
                    best_dist = dist
                    best_idx = idx

            if best_idx is not None:
                # Skip intro when transitions-only is enabled
                if intro_transitions_only and segment_labels:
                    try:
                        lbl = (section_labels[best_idx] or "").lower()
                    except Exception:
                        lbl = ""
                    if lbl == "intro":
                        continue
                impact_candidates.append(best_idx)

        if smart_scene_enabled and impact_candidates:
            preferred_candidates: List[int] = []
            for idx in impact_candidates:
                lbl = ""
                if segment_labels and idx < len(segment_labels):
                    try:
                        lbl = str(segment_labels[idx] or "").lower()
                    except Exception:
                        lbl = ""
                if lbl in ("drop", "chorus"):
                    preferred_candidates.append(idx)
            if preferred_candidates:
                impact_candidates = preferred_candidates

        if not impact_candidates:
            return

        # Group candidates into ~5 second buckets along the video timeline,
        # mirroring the cadence of cinematic effects.
        bucket_map: Dict[int, List[int]] = {}
        for idx in impact_candidates:
            center_t = centers[idx] if idx < len(centers) else 0.0
            bucket = int(center_t // 2.7) # second place to change speed of change
            bucket_map.setdefault(bucket, []).append(idx)

        chosen_indices: List[int] = []
        for bucket_idx in sorted(bucket_map.keys()):
            idx_list = bucket_map[bucket_idx]
            if not idx_list:
                continue
            # Avoid duplicates inside a bucket, then pick a single segment.
            unique = sorted(set(idx_list))
            chosen_indices.append(random.choice(unique))

        if not chosen_indices:
            return

        # Assign break-impact FX. We always apply exactly one effect per chosen
        # segment so they are spaced out like cinematic FX instead of all
        # firing at once. With "Random" enabled, the chosen effect is random
        # per impact; otherwise we cycle deterministically through the enabled
        # list.
        num_effects = len(enabled_effect_names)
        eff_cursor = 0

        for seg_idx in sorted(set(chosen_indices)):
            seg = segments[seg_idx]

            # Per‑segment enabled list: colour strobe ("confetti") is only used
            # on segments that are at most 2 seconds long so the strobe stays snappy.
            per_seg_enabled = list(enabled_effect_names)
            try:
                seg_len = float(getattr(seg, "duration", 0.0) or 0.0)
            except Exception:
                seg_len = 0.0
            if seg_len > 2.0 and "confetti" in per_seg_enabled:
                per_seg_enabled = [e for e in per_seg_enabled if e != "confetti"]

            if not per_seg_enabled:
                continue

            if impact_random:
                eff_name = random.choice(per_seg_enabled)
            else:
                # Cycle deterministically through the global list, but fall back
                # to the first allowed effect if the chosen one was filtered out.
                base_name = enabled_effect_names[eff_cursor % num_effects]
                eff_cursor += 1
                eff_name = base_name if base_name in per_seg_enabled else per_seg_enabled[0]

            _tag_segment(seg, [eff_name])



    def _rebuild_timeline_positions(segments: List[TimelineSegment]) -> None:
        """Rebuild absolute timeline_start / timeline_end for all segments.

        We treat each segment's ``duration`` as the *base* amount of source
        material (real-time seconds). When a segment is slowed down
        (slow_factor < 1.0), it needs *more* room on the musical timeline to
        play the same material, so we stretch its logical length by dividing
        by the slow factor. For all other cases we keep the base duration.

        This mirrors the intent of:

            base_duration = beats_per_segment * avg_beat_interval
            if seg.slow_factor < 1.0 and seg.slow_factor > 0.01:
                seg_duration = base_duration / seg.slow_factor
            else:
                seg_duration = base_duration

        and ensures that cumulative timeline time always uses the stretched
        duration, not the base duration.
        """
        current_time = 0.0
        for seg in segments:
            base_duration = float(getattr(seg, "duration", 0.0))
            try:
                sf = float(getattr(seg, "slow_factor", 1.0) or 1.0)
            except Exception:
                sf = 1.0
            if 0.01 < sf < 1.0 and base_duration > 0.0:
                seg_duration = base_duration / sf
            else:
                seg_duration = base_duration
            seg.timeline_start = current_time
            current_time += seg_duration
            seg.timeline_end = current_time


# Determine which transition modes are allowed for randomization
    allowed_modes: List[int] = []
    if transition_modes_enabled:
        for m in transition_modes_enabled:
            if 0 <= m <= 14 and m not in allowed_modes:
                allowed_modes.append(m)
    if not allowed_modes:
        allowed_modes.append(transition_mode)

    beats = analysis.beats
    if len(beats) < 4:
        # Single-segment fallback for very short tracks.
        seg = TimelineSegment(
            clip_path=sources[0].path,
            clip_start=0.0,
            duration=analysis.duration,
            effect="none",
            energy_class="mid",
            transition="none" if transition_mode == 1 else "fade",
        )
        segments_tmp = [seg]
        center_time = max(0.0, analysis.duration * 0.5)
        label = _section_label_at(center_time)
        _apply_slow_motion(segments_tmp, [center_time], [label])
        return segments_tmp

    def energy_class(time_t: float) -> str:
        for s in analysis.sections:
            if s.start <= time_t < s.end:
                if s.kind in ("chorus", "drop"):
                    return "high"
                if s.kind in ("intro", "break"):
                    return "low"
                return "mid"
        return "mid"

    # Beat intervals
    # We build intervals between consecutive beats (plus a tail segment up to the
    # end of the track), then group those intervals into base segments according
    # to beats_per_segment. For each grouped segment we also track how many beats
    # it spans so we can detect "calm" regions (large gaps between beats).
    intervals = []
    for i in range(len(beats) - 1):
        t0 = beats[i].time
        t1 = beats[i + 1].time
        if t1 > t0:
            intervals.append((t0, t1))
    if beats[-1].time < analysis.duration:
        intervals.append((beats[-1].time, analysis.duration))

    grouped = []  # list of (start_time, end_time, beat_count)
    cur_start = None
    cur_count = 0
    for (t0, t1) in intervals:
        if cur_start is None:
            cur_start = t0
            cur_count = 1
        else:
            cur_count += 1
        if cur_count >= max(1, beats_per_segment):
            grouped.append((cur_start, t1, cur_count))
            cur_start = None
            cur_count = 0
    if cur_start is not None:
        # Tail segment that didn't reach beats_per_segment; still keep its count.
        grouped.append((cur_start, analysis.duration, max(1, cur_count)))

    # Enforce a practical minimum base segment length so ultra-short beat windows
    # do not survive as annoying sub-second cuts. This also makes
    # ``beats_per_segment`` matter more in fast music because tiny grouped windows
    # are merged forward before per-segment clip lengths are chosen.
    MIN_SEGMENT_LEN = 1.5
    if len(grouped) > 1:
        merged_grouped = []
        i = 0
        while i < len(grouped):
            start_t, end_t, beat_count = grouped[i]
            while (end_t - start_t) < MIN_SEGMENT_LEN and i < (len(grouped) - 1):
                i += 1
                _, next_end_t, next_beat_count = grouped[i]
                end_t = next_end_t
                beat_count += next_beat_count
            merged_grouped.append((start_t, end_t, beat_count))
            i += 1
        grouped = merged_grouped

    smart_scenes: List[MusicScene] = []
    if smart_scene_enabled:
        try:
            smart_scenes = list(smart_scene_map or [])
        except Exception:
            smart_scenes = []
        if not smart_scenes:
            smart_scenes = build_smart_scene_map(
                analysis,
                beats_per_segment=beats_per_segment,
                director_preset=director_preset,
                cut_style=scene_cut_style,
                microclip_mode=microclip_mode,
                duration_guard_enabled=bool(smart_scene_duration_guard),
                min_scene_len=float(smart_min_scene_len),
                max_scene_len=float(smart_max_scene_len),
                max_scene_mode=smart_max_scene_mode,
                source_clip_durations=smart_source_durations,
                cut_timing_offset=smart_cut_timing_offset,
            )
        if smart_scenes:
            grouped = [
                (float(sc.start), float(sc.end), max(1, int(getattr(sc, "beat_count", 1) or 1)))
                for sc in smart_scenes
                if float(getattr(sc, "end", 0.0) or 0.0) > float(getattr(sc, "start", 0.0) or 0.0)
            ]
        if smart_scene_info is not None:
            try:
                smart_scene_info.clear()
                smart_scene_info.update({
                    "enabled": bool(smart_scenes),
                    "director_preset": director_preset,
                    "scene_cut_style": scene_cut_style,
                    "duration_guard": dict(smart_duration_guard_info),
                    "cut_timing_offset": float(smart_cut_timing_offset),
                    "scene_count": len(smart_scenes),
                    "scene_map": _scene_map_to_list(smart_scenes),
                    "lyrics_attached": any(bool(getattr(sc, "lyric_text", "")) for sc in smart_scenes),
                    "srt_path": next((str(getattr(sc, "srt_path", "") or "") for sc in smart_scenes if getattr(sc, "srt_path", "")), ""),
                })
            except Exception:
                pass

    num_sources = len(sources)
    allow_mosaic = num_sources >= 10
    last_source_idx: Optional[int] = None
    shuffle_pool = list(range(num_sources))
    random.shuffle(shuffle_pool)
    shuffle_pos = 0
    clip_offsets = {i: 0.0 for i in range(num_sources)}
    section_overrides = section_overrides or {}
    section_override_offsets: Dict[int, float] = {}

    def _pick_source_index() -> int:
        nonlocal last_source_idx, shuffle_pool, shuffle_pos
        if num_sources == 1:
            idx = 0
        elif clip_order_mode == 1:  # sequential
            if last_source_idx is None:
                idx = 0
            else:
                idx = (last_source_idx + 1) % num_sources
        elif clip_order_mode == 2:  # shuffle, no repeats until all used
            if shuffle_pos >= len(shuffle_pool):
                shuffle_pool = list(range(num_sources))
                random.shuffle(shuffle_pool)
                shuffle_pos = 0
            idx = shuffle_pool[shuffle_pos]
            shuffle_pos += 1
        else:  # 0 = random (no immediate repeat if possible)
            candidates = list(range(num_sources))
            if last_source_idx is not None and num_sources > 1:
                try:
                    candidates.remove(last_source_idx)
                except ValueError:
                    pass
            idx = random.choice(candidates)
        last_source_idx = idx
        return idx

    def pick_region(length: float) -> Tuple[str, float]:
        idx = _pick_source_index()
        src = sources[idx]
        offset = clip_offsets.get(idx, 0.0)
        if offset + length > src.duration:
            offset = 0.0
        start = offset
        clip_offsets[idx] = offset + length
        return src.path, max(0.0, start)

    segments: List[TimelineSegment] = []

    # User-controlled pacing for still images: how many segments between image inserts.
    try:
        image_interval = int(image_segment_interval or 0)
    except Exception:
        image_interval = 0
    if image_interval < 0:
        image_interval = 0
    image_index = 0
    segments_since_image = 0


    # Smart energy-aware pacing:
    # In calm regions (few / widely spaced beats or low-energy sections),
    # we prefer longer shots so the video can breathe instead of cutting
    # every beat. In active regions we keep the existing microclip logic.
    CALM_GAP_THRESHOLD = 1.4   # seconds between beats to consider section "calm"
    CALM_MIN_LEN = 3.0         # preferred minimum length for calm shots
    CALM_MAX_LEN = 7.0         # preferred maximum length for calm shots

    previous_was_calm = False

    # Track segment centers and section labels for slow-motion targeting
    segment_centers: List[float] = []
    segment_labels: List[str] = []
    segment_scenes: List[Optional[MusicScene]] = []

    for group_idx, (t0, t1, beat_count) in enumerate(grouped):
        smart_scene = smart_scenes[group_idx] if smart_scene_enabled and group_idx < len(smart_scenes) else None
        dur = max(0.35, t1 - t0)
        center = 0.5 * (t0 + t1)
        if smart_scene is not None:
            energy = str(getattr(smart_scene, "energy_class", "mid") or "mid")
            section_label = str(getattr(smart_scene, "section_label", _section_label_at(center)) or _section_label_at(center))
        else:
            energy = energy_class(center)
            section_label = _section_label_at(center)
        # Intro transitions-only: strip FX early (keep transitions)
        if intro_transitions_only and (section_label or '').lower() == 'intro':
            effect = 'none'

        if smart_scene is not None:
            # The scene map already decided the cut window. Use that full scene
            # duration so director presets/cut style actually control pacing.
            seg_len = min(dur, max(0.20, float(getattr(smart_scene, "duration", dur) or dur)))
            is_calm = (energy == "low")
            just_after_calm = False
        else:
            # Average spacing between beats in this segment (proxy for beat density)
            avg_gap = dur / max(1, beat_count)
            is_calm = (avg_gap >= CALM_GAP_THRESHOLD) or (energy == "low")
            just_after_calm = (not is_calm) and previous_was_calm

            # Base segment length
            if is_calm:
                # Calm / break-like section: use longer, more relaxed shots.
                if dur <= CALM_MIN_LEN:
                    seg_len = dur
                else:
                    max_len = min(CALM_MAX_LEN, dur)
                    seg_len = random.uniform(CALM_MIN_LEN, max_len)
            elif just_after_calm:
                # First segment right after a calm/break: emphasise the beat
                # by forcing a short accent shot so the new beat is noticeable.
                if dur <= 1.0:
                    seg_len = dur
                else:
                    seg_len = max(0.3, min(1.0, dur, random.uniform(0.4, 1.0)))
            else:
                # Microclip logic for active sections.
                if microclip_mode == 0:
                    seg_len = min(dur, 4.0)
                elif microclip_mode == 1:
                    if energy == "high":
                        seg_len = max(0.3, min(0.8, dur, random.uniform(0.3, 0.8)))
                    else:
                        seg_len = min(dur, 4.0)
                elif microclip_mode == 2:
                    if energy == "high":
                        base_min, base_max = 0.25, 0.7
                    elif energy == "mid":
                        base_min, base_max = 0.4, 1.0
                    else:
                        base_min, base_max = 0.6, 1.3
                    seg_len = max(
                        base_min,
                        min(base_max, dur, random.uniform(base_min, base_max)),
                    )
                else:
                    # Verses only: microclips are used only during verse sections.
                    if section_label == "verse":
                        if energy == "high":
                            base_min, base_max = 0.25, 0.7
                        elif energy == "mid":
                            base_min, base_max = 0.4, 1.0
                        else:
                            base_min, base_max = 0.6, 1.3
                        seg_len = max(
                            base_min,
                            min(base_max, dur, random.uniform(base_min, base_max)),
                        )
                    else:
                        seg_len = min(dur, 4.0)

        # Safety: never exceed the beat-group window duration.
        seg_len = min(seg_len, dur)

        # Hard floor for visible pacing: when a grouped window is long enough,
        # keep each rendered segment on screen for at least 1.5 seconds so the
        # clip and transition can actually register.
        if smart_scene is None and dur >= MIN_SEGMENT_LEN:
            seg_len = max(MIN_SEGMENT_LEN, seg_len)
            seg_len = min(seg_len, dur)

        use_image = False

        # Prefer explicit per-section media overrides when present.
        sec_idx = _section_index_at(center)
        override_src: Optional[ClipSource] = None
        if section_overrides and sec_idx is not None:
            override_src = section_overrides.get(sec_idx)

        if override_src is not None:
            if bool(getattr(override_src, "is_image", False)):
                # For still images, always use the full frame.
                clip_path = override_src.path
                clip_start = 0.0
                use_image = True
            else:
                # For override videos, walk through the file across segments.
                total = float(getattr(override_src, "duration", 0.0) or 0.0)
                offset = section_override_offsets.get(sec_idx, 0.0)
                if total > 0.0 and offset + seg_len > total:
                    offset = 0.0
                clip_path = override_src.path
                clip_start = max(0.0, offset)
                section_override_offsets[sec_idx] = offset + seg_len
        elif image_sources:
            # Deterministic pacing for still images based on the user slider.
            # If image_interval <= 0, fall back to the previous random behaviour.
            if image_interval > 0 and image_sources:
                if segments_since_image >= max(1, image_interval) - 1:
                    source = image_sources[image_index % len(image_sources)]
                    image_index += 1
                    clip_path = source.path
                    clip_start = 0.0  # Images have no "start" in file
                    use_image = True
                    segments_since_image = 0
                else:
                    clip_path, clip_start = pick_region(seg_len)
                    segments_since_image += 1
            else:
                # Legacy ~15%% random image insert behaviour.
                if image_sources and random.random() < 0.15:
                    source = random.choice(image_sources)
                    clip_path = source.path
                    clip_start = 0.0  # Images have no "start" in file
                    use_image = True
                else:
                    clip_path, clip_start = pick_region(seg_len)
        else:
            clip_path, clip_start = pick_region(seg_len)

        previous_was_calm = is_calm

        # FX selection by level and energy. Smart Scene Map keeps the same
        # existing effect names, but chooses them according to section/director
        # intensity instead of pure random chance.
        effect = "none"
        if smart_scene is not None:
            effect = _smart_pick_effect(
                fx_level=fx_level,
                energy=energy,
                section_label=section_label,
                effect_intensity=float(getattr(smart_scene, "effect_intensity", 0.0) or 0.0),
                director_preset=director_preset,
            )
        else:
            r = random.random()

            if fx_level == "minimal":
                # Very subtle: only occasional zoom on strong peaks
                if energy == "high" and r < 0.18:
                    effect = "zoom"

            elif fx_level == "moderate":
                if energy == "high":
                    if r < 0.25:
                        effect = "zoom"
                    elif r < 0.45:
                        effect = "flash"
                    elif r < 0.65:
                        effect = "rgb_split"
                    elif r < 0.78:
                        effect = "vhs"
                    elif r < 0.90:
                        effect = "motion_blur"
                elif energy == "mid":
                    if r < 0.20:
                        effect = random.choice(["zoom", "rgb_split"])

            elif fx_level == "high":  # high
                if energy == "high":
                    if r < 0.25:
                        effect = "zoom"
                    elif r < 0.25:
                        effect = "flash"
                    elif r < 0.85:
                        effect = "rgb_split"
                    elif r < 0.80:
                        effect = "vhs"
                    else:
                        effect = "motion_blur"
                elif energy == "mid":
                    if r < 0.30:
                        effect = random.choice(["zoom", "rgb_split", "flash"])
                    elif r < 0.45:
                        effect = "vhs"
                    elif r < 0.60:
                        effect = "motion_blur"
                else:
                    if r < 0.22:
                        effect = random.choice(["zoom", "rgb_split"])

        if intro_transitions_only and (section_label or '').lower() == 'intro':
            effect = 'none'

        # Transition choice (fade-safe, using a small transition effect library)
        if smart_scene is not None:
            mode_for_segment = _smart_pick_transition_mode(
                default_mode=transition_mode,
                random_enabled=bool(transition_random),
                allowed_modes=allowed_modes,
                section_label=section_label,
                transition_intensity=float(getattr(smart_scene, "transition_intensity", 0.0) or 0.0),
                director_preset=director_preset,
            )
        elif transition_random and allowed_modes:
            mode_for_segment = random.choice(allowed_modes)
        else:
            mode_for_segment = transition_mode

        # Transition style mapping (must match the UI order in "Transitions" + "Manage transitions")
        # 0  Soft film dissolves           -> real between-clip dissolve (stitched later)
        # 1  Hard cuts                     -> no transition
        # 2  Scale punch (zoom)            -> real xfade punch (stitched later)
        # 3  Shimmer blur (shiny)           -> real blurred crossfade (stitched later)

        # 4  Iris reveal (circle)          -> real stitched iris transition (xfade)
        # 5  Motion blur whip-cuts         -> in-clip motion blur boost
        # 6  Slit-scan smear push          -> real modern smear + push (stitched later)
        # 7  Radial burst reveal           -> real stitched burst reveal (circleopen + flash/blur overlap)
        # 8  Directional push (slide)      -> real between-clip push/slide (stitched later)
        # 9  Wipe                          -> real between-clip wipe (stitched later)
        # 10 Smooth zoom crossfade         -> in-clip smooth zoom
        # 11 Curtain open (doors)         -> real between-clip curtain/doors open (stitched later)
        # 12 Pixelize                      -> real between-clip pixelize (stitched later)
        # 13 Distance (liquid blend)          -> real xfade distance (stitched later)
        # 14 Wind smears                    -> real xfade wind smears (stitched later)
        if mode_for_segment == 1:  # Hard cuts
            transition = "none"

        elif mode_for_segment == 0:  # Soft film dissolves (real dissolve between clips)
            transition = "t_exposure_dissolve"

        elif mode_for_segment == 2:  # Scale punch (zoom)
            transition = "t_scale_punch"

        elif mode_for_segment == 3:  # Shimmer blur (shiny)
            transition = "t_shimmer_blur"

        elif mode_for_segment == 4:  # Iris reveal (circle)
            transition = "t_iris"

        elif mode_for_segment == 5:  # Motion blur whip-cuts
            transition = "t_motion_blur"

        elif mode_for_segment == 6:  # Slit-scan smear push (real between-clip transition)
            transition = "t_slitscan_push"


        elif mode_for_segment == 7:  # Radial burst reveal (real stitched transition)
            transition = "t_radial_burst"

        elif mode_for_segment == 8:  # Directional push (slide)
            transition = "t_push"

        elif mode_for_segment == 9:  # Wipe
            transition = "t_wipe"

        elif mode_for_segment == 10:  # Smooth zoom crossfade
            transition = "t_smooth_zoom"

        elif mode_for_segment == 11:  # Curtain open (doors)
            transition = "t_curtain_open"

        elif mode_for_segment == 12:  # Pixelize
            transition = "t_pixelize"

        elif mode_for_segment == 13:  # Distance (liquid blend)
            transition = "t_distance"

        elif mode_for_segment == 14:  # Wind smears
            transition = "t_wind_smears"

        else:
            transition = "none"
        segments.append(
            TimelineSegment(
                clip_path=clip_path,
                clip_start=clip_start,
                duration=seg_len,
                effect=effect,
                energy_class=energy,
                transition=transition,
                is_image=use_image,
            )
        )
        # Track center time and section label for slow-motion logic
        segment_centers.append(center)
        segment_labels.append(section_label)
        segment_scenes.append(smart_scene)


    # Apply slow-motion decisions on built segments
    _apply_slow_motion(segments, segment_centers, segment_labels)

    # Rebuild timeline positions so slow-motion segments
    # take up more room on the musical timeline.
    _rebuild_timeline_positions(segments)



    # REAL DROP DETECTION – THE ONE THAT ACTUALLY FEELS PERFECT
    # For each detected 'break' section, look ahead a few seconds and find the
    # strongest major beat that follows. The segment that actually *contains*
    # that beat becomes the break-impact moment, and its FX strength scales
    # with the beat power so hard drops feel noticeably bigger.
    if impact_enable and analysis.sections and analysis.beats and segments:
        break_sections = [s for s in analysis.sections if s.kind == "break"]

        for break_sec in break_sections:
            window_start = break_sec.end
            window_end = min(analysis.duration, window_start + 6.0)  # look up to 6 seconds after break

            # Get all major beats in this window
            candidates = [
                b for b in analysis.beats
                if window_start <= b.time < window_end and b.kind == "major"
            ]

            if not candidates:
                continue

            # THIS IS THE MAGIC LINE
            strongest_beat = max(candidates, key=lambda b: b.strength)

            # Find the segment that contains this absolute god-tier beat
            for seg in segments:
                if seg.timeline_start <= strongest_beat.time < seg.timeline_end:
                    seg.is_break_impact = True

                    # Optional: make the impact strength follow the actual beat power
                    power = min(1.0, strongest_beat.strength * 1.8)  # your strength is ~0.3–1.0

                    if impact_flash:
                        seg.impact_flash_strength = max(seg.impact_flash_strength, power * 1.0)
                    if impact_shock:
                        seg.impact_shock_strength = max(seg.impact_shock_strength, power * 0.9)
                    if impact_zoom:
                        seg.impact_zoom_amount = max(seg.impact_zoom_amount, power * 0.4)
                    if impact_shake:
                        seg.impact_shake_strength = max(seg.impact_shake_strength, power * 0.8)
                    if impact_confetti:
                        seg.impact_confetti_density = max(seg.impact_confetti_density, power * 0.7)
                    if impact_color_cycle:
                        seg.impact_color_cycle_speed = max(seg.impact_color_cycle_speed, power * 1.0)
                    break

    # Extra: ensure the main drop (loudest beat inside any 'drop' section)
    # is always tagged as an impact segment based on its true beat strength.
    if impact_enable and analysis.sections and analysis.beats:
        drop_ranges = [(s.start, s.end) for s in analysis.sections if s.kind == "drop"]
        if drop_ranges:
            drop_beats: List[Beat] = []
            for b in analysis.beats:
                for start_t, end_t in drop_ranges:
                    if start_t <= b.time < end_t:
                        drop_beats.append(b)
                        break
            if drop_beats:
                chosen_beat = max(drop_beats, key=lambda b: b.strength)
                intensity = min(1.0, chosen_beat.strength * 2.0)
                for seg in segments:
                    if seg.timeline_start <= chosen_beat.time < seg.timeline_end:
                        seg.is_break_impact = True
                        # Optionally boost the effect strength based on how hard the beat actually is.
                        if impact_flash:
                            seg.impact_flash_strength = max(seg.impact_flash_strength, intensity * 1.0)
                        if impact_zoom:
                            seg.impact_zoom_amount = max(seg.impact_zoom_amount, intensity * 0.3)
                        if impact_shake:
                            seg.impact_shake_strength = max(seg.impact_shake_strength, intensity * 0.8)
                        if impact_color_cycle:
                            seg.impact_color_cycle_speed = max(seg.impact_color_cycle_speed, intensity * 1.0)
                        break

    # Optionally extend timeline so total video duration matches full music length
    if force_full_length and segments:
        total_video = sum(seg.duration for seg in segments)
        target = analysis.duration
        if audio_duration is not None and audio_duration > 0:
            try:
                target = max(target, float(audio_duration))
            except Exception:
                pass
        # Only extend (never shrink); allow a small tolerance before extending.
        if total_video < target * 0.998 and target > 0:
            remaining = target - total_video
            # Use a conservative average length for filler segments
            avg_len = max(0.5, min(2.5, total_video / len(segments)))
            def _make_filler_segment(start_fraction: float, length: float) -> TimelineSegment:
                # Clamp logical time to the track duration
                t_center = target * min(max(start_fraction, 0.0), 1.0)
                energy = energy_class(t_center)
                clip_path, clip_start = pick_region(length)
                # Use similar transition logic for fillers, but a bit softer
                if transition_random and allowed_modes:
                    mode_for_segment = random.choice(allowed_modes)
                else:
                    mode_for_segment = transition_mode

                if mode_for_segment == 1:  # Hard cuts
                    transition = "none"
                elif mode_for_segment == 0:  # Soft film dissolves (stitched later)
                    transition = "t_exposure_dissolve"
                elif mode_for_segment == 2:  # Scale punch (zoom)
                    # Keep a tiny chance of a flashcut on high energy to avoid "too smooth" late filler.
                    if energy == "high" and random.random() < 0.22:
                        transition = "flashcut"
                    else:
                        transition = "t_scale_punch"
                elif mode_for_segment == 3:  # Shimmer blur (shiny)
                    transition = "t_shimmer_blur"
                elif mode_for_segment == 4:  # Iris reveal (circle)
                    transition = "t_iris"
                elif mode_for_segment == 5:  # Motion blur whip-cuts
                    transition = "t_motion_blur"
                elif mode_for_segment == 6:  # Slit-scan smear push (stitched later)
                    transition = "t_slitscan_push"
                elif mode_for_segment == 7:  # Radial burst reveal (stitched later)
                    transition = "t_radial_burst"
                elif mode_for_segment == 8:  # Directional push (stitched later)
                    transition = "t_push"
                elif mode_for_segment == 9:  # Wipe (stitched later)
                    transition = "t_wipe"
                elif mode_for_segment == 10:  # Smooth zoom crossfade
                    transition = "t_smooth_zoom"
                elif mode_for_segment == 11:  # Curtain open (stitched later)
                    transition = "t_curtain_open"
                elif mode_for_segment == 12:  # Pixelize (stitched later)
                    transition = "t_pixelize"
                elif mode_for_segment == 13:  # Distance (stitched later)
                    transition = "t_distance"
                elif mode_for_segment == 14:  # Wind smears (stitched later)
                    transition = "t_wind_smears"
                else:
                    transition = "none"
                seg = TimelineSegment(
                    clip_path=clip_path,
                    clip_start=clip_start,
                    duration=length,
                    effect="none",
                    energy_class=energy,
                    transition=transition,
                )
                # Track filler center time and label as well
                segment_centers.append(t_center)
                segment_labels.append(_section_label_at(t_center))
                return seg

            # Add filler segments towards the end of the track until we cover the gap
            while remaining > 0.05:
                seg_len = min(avg_len, remaining)
                start_frac = (target - remaining + seg_len * 0.5) / target
                filler = _make_filler_segment(start_frac, seg_len)
                segments.append(filler)
                remaining -= seg_len

    # Final pass: also rebuild after any optional extension so filler
    # segments receive proper timeline_start / timeline_end values.
    _rebuild_timeline_positions(segments)

    # After extension, apply cinematic and break-impact FX across the
    # full timeline so late filler segments also get hits. We then
    # rebuild positions again before constructing the calm outro, so
    # the last few seconds can still avoid hard cuts.
    if segments:
        segment_centers_final: List[float] = []
        for seg in segments:
            start_t = float(getattr(seg, 'timeline_start', 0.0) or 0.0)
            end_t = float(getattr(seg, 'timeline_end', 0.0) or 0.0)
            center_t = start_t + max(0.0, (end_t - start_t)) * 0.5
            segment_centers_final.append(center_t)

        _apply_cinematic_effects(segments, allow_mosaic, segment_labels)
        _apply_break_impact_fx(segments, segment_centers_final, segment_labels)
        _rebuild_timeline_positions(segments)

    # --- CINEMATIC OUTRO: reserve the final few seconds for 1–2 calm shots ---
    OUTRO_DURATION = 8.0

    # Prefer an explicit audio duration when available, otherwise fall back to
    # the analysed track length.
    track_len = None
    try:
        if audio_duration is not None and float(audio_duration) > 0.0:
            track_len = float(audio_duration)
        else:
            track_len = float(analysis.duration)
    except Exception:
        track_len = None

    if segments and track_len is not None and track_len > 10.0:
        # We want the last ~OUTRO_DURATION seconds to be a calm outro.
        target_outro_start = max(0.0, track_len - OUTRO_DURATION)

        # Keep all segments that clearly end before the planned outro window.
        main_segments: List[TimelineSegment] = []
        for seg in segments:
            if getattr(seg, "timeline_end", 0.0) <= target_outro_start:
                main_segments.append(seg)
            else:
                break

        if main_segments:
            # Remaining logical time we want to cover with the outro.
            outro_start_time = getattr(main_segments[-1], "timeline_end", 0.0)
            remaining = max(0.5, track_len - outro_start_time)

            # Pick the longest (or two longest) clips that can reasonably cover the outro.
            eligible = [s for s in sources if s.duration >= remaining * 0.7]
            if eligible:
                k = min(8, len(eligible))
                candidates = random.sample(eligible, k=k)
            else:
                candidates = sorted(sources, key=lambda s: s.duration, reverse=True)[:8]
            if not candidates:
                candidates = sorted(sources, key=lambda s: s.duration, reverse=True)[:2]

            outro_segments: List[TimelineSegment] = []
            time_left = remaining
            for clip in candidates:
                if time_left <= 0.0:
                    break
                seg_dur = min(clip.duration, time_left)
                if seg_dur < 2.0:
                    continue

                seg = TimelineSegment(
                    clip_path=clip.path,
                    clip_start=0.0,
                    duration=seg_dur,
                    effect="minimal",
                    energy_class="low",
                    transition="fade",
                    slow_factor=0.85,   # gentle slow‑mo
                    cine_speed_ramp=True,
                    cine_ramp_out=0.15,
                )
                outro_segments.append(seg)
                time_left -= seg_dur

            if outro_segments:
                # Adjust the final outro segment so that, after slow‑motion is applied,
                # the overall logical length is close to the track length.
                def _effective_len(seg: TimelineSegment) -> float:
                    try:
                        sf = float(getattr(seg, "slow_factor", 1.0) or 1.0)
                    except Exception:
                        sf = 1.0
                    base = float(getattr(seg, "duration", 0.0))
                    if 0.01 < sf < 1.0 and base > 0.0:
                        return base / sf
                    return base

                combined = main_segments + outro_segments
                total_eff = sum(_effective_len(s) for s in combined)
                if total_eff > 0.0:
                    last = outro_segments[-1]
                    last_eff = _effective_len(last)
                    delta = track_len - total_eff
                    # Convert the desired change in effective length back to base duration.
                    try:
                        sf_last = float(getattr(last, "slow_factor", 1.0) or 1.0)
                    except Exception:
                        sf_last = 1.0
                    adjust = delta * (sf_last if sf_last < 1.0 else 1.0)
                    if last.duration + adjust > 0.2:
                        last.duration += adjust

                segments = main_segments + outro_segments

                # Rebuild positions one more time so the new outro snaps cleanly
                # to the end of the track.
                _rebuild_timeline_positions(segments)

    # Final safety: when intro transitions-only is enabled, ensure no FX are applied during intro.
    if intro_transitions_only and segments:
        # Ensure timeline positions exist so we can detect intro segments reliably.
        try:
            _rebuild_timeline_positions(segments)
        except Exception:
            pass

        def _reset_fx_on_segment(seg: TimelineSegment) -> None:
            # Core toggles
            try:
                seg.effect = "none"
            except Exception:
                pass
            try:
                seg.slow_factor = 1.0
            except Exception:
                pass

            # Clear known / dynamic cinematic + impact attributes
            try:
                items = list(vars(seg).items())
            except Exception:
                items = []
            for k, v in items:
                if not (k.startswith("cine_") or k.startswith("impact_") or k == "is_break_impact"):
                    continue
                try:
                    if isinstance(v, bool):
                        setattr(seg, k, False)
                    elif isinstance(v, int):
                        setattr(seg, k, 0)
                    elif isinstance(v, float):
                        if k.endswith("_factor"):
                            setattr(seg, k, 1.0)
                        else:
                            setattr(seg, k, 0.0)
                    elif isinstance(v, str):
                        setattr(seg, k, "")
                    else:
                        try:
                            delattr(seg, k)
                        except Exception:
                            pass
                except Exception:
                    pass

        for seg in segments:
            try:
                st = float(getattr(seg, "timeline_start", 0.0) or 0.0)
                en = float(getattr(seg, "timeline_end", st) or st)
                center_t = st + max(0.0, en - st) * 0.5
            except Exception:
                center_t = 0.0
            lbl = (_section_label_at(center_t) or "").lower()
            if lbl == "intro":
                _reset_fx_on_segment(seg)

    # Timed strobe: map user timestamps to segment-local offsets so the Flash strobe can fire on time.
    if strobe_on_time and strobe_on_time_times and segments:
        times: List[float] = []
        for v in strobe_on_time_times:
            try:
                fv = float(v)
            except Exception:
                continue
            if fv < 0.0:
                continue
            times.append(fv)
        # De-dup + sort
        uniq: List[float] = []
        for t in sorted(times):
            if not uniq or abs(uniq[-1] - t) >= 0.01:
                uniq.append(t)

        for t in uniq:
            # Find the segment that covers this timestamp (output timeline seconds).
            best_idx: Optional[int] = None
            for i, seg in enumerate(segments):
                try:
                    st = float(getattr(seg, "timeline_start", 0.0) or 0.0)
                    en = float(getattr(seg, "timeline_end", st) or st)
                except Exception:
                    continue
                if st <= t < en or (i == len(segments) - 1 and st <= t <= en):
                    best_idx = i
                    break
            if best_idx is None:
                continue

            seg = segments[best_idx]
            try:
                st = float(getattr(seg, "timeline_start", 0.0) or 0.0)
                en = float(getattr(seg, "timeline_end", st) or st)
            except Exception:
                st, en = 0.0, 0.0
            seg_len = max(0.0, en - st)
            if seg_len <= 0.0:
                continue

            off = max(0.0, min(seg_len, t - st))
            try:
                seg.strobe_on_time_offsets.append(off)
            except Exception:
                try:
                    setattr(seg, "strobe_on_time_offsets", [off])
                except Exception:
                    pass

            # Reuse the Flash strobe settings (strength/speed) even if the break-impact toggles are off.
            try:
                cur = float(getattr(seg, "impact_flash_strength", 0.0) or 0.0)
            except Exception:
                cur = 0.0
            try:
                setattr(seg, "impact_flash_strength", max(cur, float(impact_flash_strength)))
            except Exception:
                pass
            try:
                setattr(seg, "impact_flash_speed_ms", int(impact_flash_speed_ms))
            except Exception:
                pass


    return segments


