class SourceScanWorker(QThread):
    progress = Signal(int, str)
    finished_ok = Signal(list)
    failed = Signal(str)

    def __init__(
        self,
        video_input: str,
        ffprobe: str,
        min_clip_length: float | None = None,
        parent=None,
    ) -> None:
        super().__init__(parent)
        self.video_input = video_input
        self.ffprobe = ffprobe
        self.min_clip_length = min_clip_length

    def run(self) -> None:
        """Scan video sources in a background thread with caching + progress.

        This worker mirrors discover_video_sources() but:
        - Emits incremental progress updates so the UI can show scan status.
        - Caches per‑file durations under the app's temp directory so
          repeated scans of the same folder are much faster.
        """
        try:
            exts = {".mp4", ".mov", ".mkv", ".avi", ".webm", ".mpg", ".mpeg"}

            video_input = self.video_input
            ffprobe = self.ffprobe

            # Build list of candidate files (single file, folder, or '|' list).
            paths: list[str] = []
            if "|" in video_input:
                parts = [p.strip() for p in str(video_input).split("|") if p.strip()]
                for raw in parts:
                    path = os.path.abspath(raw)
                    if not os.path.isfile(path):
                        continue
                    _, ext = os.path.splitext(path)
                    if ext.lower() not in exts:
                        continue
                    paths.append(path)
            else:
                base = os.path.abspath(video_input)
                if os.path.isdir(base):
                    try:
                        names = sorted(os.listdir(base))
                    except Exception:
                        names = []
                    for name in names:
                        path = os.path.join(base, name)
                        if not os.path.isfile(path):
                            continue
                        _, ext = os.path.splitext(path)
                        if ext.lower() not in exts:
                            continue
                        paths.append(path)
                elif os.path.isfile(base):
                    _, ext = os.path.splitext(base)
                    if ext.lower() in exts:
                        paths.append(base)

            if not paths:
                self.failed.emit("__no_clips__")
                return

            # Cache disabled: do not read or write scan_cache.json; always probe durations fresh.
            cache: dict[str, dict] = {}
            cache_file: str | None = None
            dirty = False

            sources: list[ClipSource] = []
            total = len(paths)

            for idx, path in enumerate(paths):
                try:
                    st = os.stat(path)
                    key = os.path.abspath(path)
                    entry = cache.get(key) if isinstance(cache, dict) else None
                    dur: float | None = None

                    if isinstance(entry, dict):
                        try:
                            if (
                                entry.get("mtime") == st.st_mtime
                                and entry.get("size") == st.st_size
                            ):
                                d_val = float(entry.get("duration", 0.0) or 0.0)
                                if d_val > 0.0:
                                    dur = d_val
                        except Exception:
                            dur = None

                    if dur is None:
                        dur = _ffprobe_duration(ffprobe, path)
                        if dur and dur > 0:
                            if isinstance(cache, dict):
                                cache[key] = {
                                    "duration": float(dur),
                                    "mtime": st.st_mtime,
                                    "size": st.st_size,
                                }
                                dirty = True

                    if dur and dur > 0:
                        sources.append(ClipSource(path=path, duration=float(dur)))
                except Exception:
                    # Ignore individual file failures; we only care about usable clips.
                    pass

                # Update scan progress (0–10%% reserved for scanning).
                try:
                    pct = int(1 + 9 * ((idx + 1) / max(1, total)))
                    self.progress.emit(pct, f"Scanning clips {idx+1}/{total}...")
                except Exception:
                    pass

            if not sources:
                self.failed.emit("__no_clips__")
                return

            # Apply optional minimum clip length filter.
            if self.min_clip_length is not None and self.min_clip_length > 0:
                usable = [s for s in sources if s.duration >= self.min_clip_length]
                if not usable:
                    # Signal a specific "all too short" condition back to the UI.
                    self.failed.emit(f"__all_short__:{self.min_clip_length:.1f}")
                    return
                sources = usable

            # Cache persistence disabled: no scan_cache.json will be written.
            # if dirty and cache_file and isinstance(cache, dict):
            #     try:
            #         with open(cache_file, "w", encoding="utf-8") as f:
            #             json.dump(cache, f)
            #     except Exception:
            #         # Cache write failure is non-fatal.
            #         pass

            self.finished_ok.emit(sources)
        except Exception as e:
            self.failed.emit(str(e))


class LtxDirectorPlanWorker(QThread):
    progress_text = Signal(str)
    finished_result = Signal(dict)
    failed = Signal(str)

    def __init__(self, bridge_module, payload: dict, parent=None) -> None:
        super().__init__(parent)
        self.bridge_module = bridge_module
        self.payload = dict(payload or {})

    def run(self) -> None:
        try:
            create_fn = getattr(self.bridge_module, "create_ltx_director_plan", None)
            if not callable(create_fn):
                self.failed.emit("LTX director plan creation is not available in this bridge file.")
                return

            def _progress(text):
                try:
                    msg = str(text or "").strip()
                    if msg:
                        self.progress_text.emit(msg)
                except Exception:
                    pass

            payload = dict(self.payload)
            payload["progress_callback"] = _progress
            self.progress_text.emit("Loading director backend...")
            result = create_fn(payload)
            if isinstance(result, dict) and bool(result.get("ok")):
                self.finished_result.emit(result)
            else:
                msg = "LTX director plan creation failed."
                if isinstance(result, dict):
                    msg = str(result.get("message") or msg)
                self.failed.emit(msg)
        except Exception as exc:
            self.failed.emit(str(exc))


class LtxQueuePrepareWorker(QThread):
    """Prepare Prompt Plan -> LTX Shot Plan -> LTX Director Plan off the UI thread.

    This is used by the one-click LTX Queue/Generate button so the user does not
    have to click three preparation buttons manually and the main app stays
    responsive while the bridge creates JSON plans.
    """

    progress_text = Signal(str)
    finished_result = Signal(dict)
    failed = Signal(str)

    def __init__(self, bridge_module, payload: dict, parent=None) -> None:
        super().__init__(parent)
        self.bridge_module = bridge_module
        self.payload = dict(payload or {})

    def _emit_progress(self, text: str) -> None:
        try:
            msg = str(text or "").strip()
            if msg:
                self.progress_text.emit(msg)
        except Exception:
            pass

    @staticmethod
    def _message_from_result(result: dict, fallback: str) -> str:
        try:
            return str((result or {}).get("message") or fallback)
        except Exception:
            return str(fallback)

    def run(self) -> None:
        try:
            bridge = self.bridge_module
            if bridge is None:
                self.failed.emit("Planner Bridge is not available in this build.")
                return

            create_prompt = getattr(bridge, "create_prompt_plan", None)
            create_shot = getattr(bridge, "create_ltx_shot_plan", None)
            create_director = getattr(bridge, "create_ltx_director_plan", None)
            if not callable(create_prompt):
                self.failed.emit("Prompt plan creation is not available in this bridge file.")
                return
            if not callable(create_shot):
                self.failed.emit("LTX shot plan creation is not available in this bridge file.")
                return
            if not callable(create_director):
                self.failed.emit("LTX director plan creation is not available in this bridge file.")
                return

            payload = dict(self.payload or {})
            root_dir = str(payload.get("root_dir") or _musicclip_project_root())
            scene_plan_path = str(payload.get("scene_plan_path") or "").strip()
            if not scene_plan_path or not os.path.isfile(scene_plan_path):
                self.failed.emit("Scene plan was not found; could not prepare LTX queue job.")
                return

            creative_brief = dict(payload.get("creative_brief") or {})
            generation_settings = dict(payload.get("bridge_generation_settings") or {})
            character_reference = dict(payload.get("character_reference") or {})

            def _progress_callback(text):
                self._emit_progress(text)

            self._emit_progress("Creating prompt plan...")
            prompt_payload = {
                "scene_plan_path": scene_plan_path,
                "creative_brief": creative_brief,
                "prompt_backend": str(payload.get("prompt_backend") or "template_rule_based"),
                "use_vocal_scene_roles": bool(payload.get("use_vocal_scene_roles", True)),
                "bridge_generation_settings": generation_settings,
                "character_reference": character_reference,
                "progress_callback": _progress_callback,
            }
            prompt_result = create_prompt(prompt_payload)
            if not isinstance(prompt_result, dict) or not bool(prompt_result.get("ok")):
                self.failed.emit(self._message_from_result(prompt_result if isinstance(prompt_result, dict) else {}, "Prompt plan creation failed."))
                return
            prompt_plan_path = str(prompt_result.get("prompt_plan_path") or "").strip()
            if not prompt_plan_path or not os.path.isfile(prompt_plan_path):
                self.failed.emit("Prompt plan was created but the saved JSON file could not be found.")
                return

            self._emit_progress("Creating LTX shot plan...")
            shot_payload = {
                "root_dir": root_dir,
                "prompt_plan_path": prompt_plan_path,
                "scene_plan_path": scene_plan_path,
                "creative_brief": creative_brief,
                "grouping_mode": str(payload.get("grouping_mode") or "Auto"),
                "export_audio_chunks": bool(payload.get("export_audio_chunks", True)),
                "fps": int(payload.get("fps") or 24),
                "bridge_generation_settings": generation_settings,
                "character_reference": character_reference,
                "progress_callback": _progress_callback,
            }
            shot_result = create_shot(shot_payload)
            if not isinstance(shot_result, dict) or not bool(shot_result.get("ok")):
                self.failed.emit(self._message_from_result(shot_result if isinstance(shot_result, dict) else {}, "LTX shot plan creation failed."))
                return
            ltx_shot_plan_path = str(shot_result.get("ltx_shot_plan_path") or "").strip()
            if not ltx_shot_plan_path or not os.path.isfile(ltx_shot_plan_path):
                self.failed.emit("LTX shot plan was created but the saved JSON file could not be found.")
                return

            self._emit_progress("Creating LTX director plan...")
            director_payload = {
                "root_dir": root_dir,
                "ltx_shot_plan_path": ltx_shot_plan_path,
                "creative_brief": creative_brief,
                "director_backend": str(payload.get("director_backend") or "Template cleanup"),
                "bridge_generation_settings": generation_settings,
                "character_reference": character_reference,
                "progress_callback": _progress_callback,
            }
            if isinstance(payload.get("llama_settings"), dict):
                director_payload["llama_settings"] = dict(payload.get("llama_settings") or {})
            director_result = create_director(director_payload)
            if not isinstance(director_result, dict) or not bool(director_result.get("ok")):
                self.failed.emit(self._message_from_result(director_result if isinstance(director_result, dict) else {}, "LTX director plan creation failed."))
                return
            director_plan_path = str(director_result.get("ltx_director_plan_path") or "").strip()
            if not director_plan_path or not os.path.isfile(director_plan_path):
                self.failed.emit("LTX director plan was created but the saved JSON file could not be found.")
                return

            self.finished_result.emit({
                "ok": True,
                "scene_plan_path": scene_plan_path,
                "prompt_plan_path": prompt_plan_path,
                "ltx_shot_plan_path": ltx_shot_plan_path,
                "ltx_director_plan_path": director_plan_path,
                "prompt_result": prompt_result,
                "shot_result": shot_result,
                "director_result": director_result,
                "ltx_shot_count": int(director_result.get("ltx_shot_count") or shot_result.get("ltx_shot_count") or 0),
                "director_backend": str(director_result.get("director_backend") or director_result.get("requested_director_backend") or payload.get("director_backend") or ""),
            })
        except Exception as exc:
            self.failed.emit(str(exc))


