            class _LtxCollapsibleSection(QFrame):
                """Small arrow-based collapsible section for the LTX Workflow tab.

                This intentionally does not use a checkbox/checkable group box: the
                header only expands/collapses the UI and must not look like an
                enable/disable toggle for the whole section.
                """

                def __init__(self, title: str, parent: QWidget, expanded: bool = False):
                    super().__init__(parent)
                    self._title = str(title or "Section")
                    self._expanded = bool(expanded)
                    try:
                        self.setFrameShape(QFrame.StyledPanel)
                    except Exception:
                        pass

                    outer = QVBoxLayout(self)
                    outer.setContentsMargins(8, 6, 8, 8)
                    outer.setSpacing(6)

                    self.header_button = QPushButton(self)
                    self.header_button.setFlat(True)
                    self.header_button.setCursor(Qt.PointingHandCursor)
                    self.header_button.setToolTip("Expand/collapse this section. This does not enable or disable any feature.")
                    self.header_button.setStyleSheet("text-align: left; padding: 6px 8px; font-weight: 600;")
                    outer.addWidget(self.header_button)

                    self.content = QWidget(self)
                    self.content_layout = QVBoxLayout(self.content)
                    self.content_layout.setContentsMargins(0, 2, 0, 0)
                    self.content_layout.setSpacing(6)
                    outer.addWidget(self.content)

                    self.header_button.clicked.connect(lambda: self.setExpanded(not self._expanded))
                    self.setExpanded(self._expanded)

                def setExpanded(self, expanded: bool) -> None:
                    self._expanded = bool(expanded)
                    try:
                        self.content.setVisible(self._expanded)
                    except Exception:
                        pass
                    arrow = "▼" if self._expanded else "▶"
                    try:
                        self.header_button.setText(f"{arrow} {self._title}")
                    except Exception:
                        pass

                # Compatibility with the previous checkable QGroupBox implementation.
                # Some nearby code may still call setChecked()/isChecked() for section
                # expansion state; keep that working without showing a checkbox.
                def setChecked(self, checked: bool) -> None:
                    self.setExpanded(bool(checked))

                def isChecked(self) -> bool:
                    return bool(self._expanded)

            def _make_ltx_section(title: str, expanded: bool = False):
                section_box = _LtxCollapsibleSection(title, self.box_planner_bridge, expanded=expanded)
                return section_box, section_box.content_layout

