        # Install tabs. Keep the Music Clip Creator tab row fixed at the top.
        # Tall form pages need their own scroll areas again (Generation, Settings,
        # LTX workflow, LTX Review), but the Timeline page must stay a direct
        # full-height tab so its own table/timeline can use the available space.
        def _scroll_tab_page(page: QWidget) -> QScrollArea:
            scroll = QScrollArea(self.tabs)
            scroll.setWidgetResizable(True)
            scroll.setFrameShape(QFrame.NoFrame)
            scroll.setHorizontalScrollBarPolicy(Qt.ScrollBarAlwaysOff)
            scroll.setWidget(page)
            try:
                scroll.viewport().setAutoFillBackground(False)
            except Exception:
                pass
            return scroll

        try:
            self.tabs.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Expanding)
        except Exception:
            pass

        self.tabs.addTab(_scroll_tab_page(page_main), "Normal")

        # Music timeline tab lives in a separate helper module so it can grow
        # without bloating this file too much. Do not wrap this tab in a
        # QScrollArea: the timeline/table must stretch to the full tab height.
        if TimelinePanel is not None:
            self.timeline_panel = TimelinePanel(self)
        else:
            self.timeline_panel = QWidget(self)
            tl = QVBoxLayout(self.timeline_panel)
            lbl = QLabel(
                "Timeline view will show the analyzed music structure here once available.",
                self.timeline_panel,
            )
            lbl.setWordWrap(True)
            tl.addWidget(lbl)
            tl.addStretch(1)
        try:
            self.timeline_panel.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Expanding)
        except Exception:
            pass
        # The Timeline page is not inserted at startup. Keep the widget explicitly
        # hidden too: after removeTab(), Qt can leave custom child widgets (notably
        # video/preview surfaces inside the timeline panel) painted above the next
        # tab if the page itself is still visible/parented to the tab stack.
        try:
            self.timeline_panel.setVisible(False)
        except Exception:
            pass
        # Keep the normal-workflow Timeline tab hidden until the user analyzes
        # a music track in this session. This avoids showing an empty/stale
        # normal-workflow timeline to users who only use the LTX workflow.
        self._timeline_tab_visible = False
        self._timeline_tab_title = "Timeline"
        if page_ltx_workflow is not None:
            self.tabs.addTab(_scroll_tab_page(page_ltx_workflow), "LTX workflow")
        if page_ltx_review is not None:
            # LTX Review already contains its own scroll area plus a fixed bottom
            # action bar, so do not wrap the whole tab in another scroll area.
            self.tabs.addTab(page_ltx_review, "LTX Review")
        self.tabs.addTab(_scroll_tab_page(page_settings), "Settings")

