    def _planner_bridge_existing_ltx_director_plan_path(self) -> str:
        """Return the latest known LTX director plan path if it exists."""
        try:
            path = str(getattr(self, "_planner_bridge_last_ltx_director_plan_path", "") or "").strip()
            if path and os.path.isfile(path) and self._planner_bridge_plan_matches_current_brief(path):
                return path
        except Exception:
            pass
        for attr in ("_planner_bridge_last_ltx_shot_plan_path", "_planner_bridge_last_prompt_plan_path", "_planner_bridge_last_scene_plan_path"):
            try:
                base = str(getattr(self, attr, "") or "").strip()
                if base:
                    cand = os.path.join(os.path.dirname(base), "musicclip_ltx_director_plan.json")
                    if os.path.isfile(cand) and self._planner_bridge_plan_matches_current_brief(cand):
                        self._planner_bridge_last_ltx_director_plan_path = cand
                        return cand
            except Exception:
                pass
        return ""

    def _ltx_combo_set_data(self, combo, data_value: str) -> bool:
        try:
            if combo is None:
                return False
            for idx in range(combo.count()):
                if str(combo.itemData(idx) or "") == str(data_value or ""):
                    combo.setCurrentIndex(idx)
                    return True
        except Exception:
            pass
        return False

    def _update_ltx_character_source_ui(self) -> None:
        try:
            source_combo = getattr(self, "combo_bridge_character_source", None)
            source = str(source_combo.currentData() if source_combo is not None else "built_in")
            ref_mode = source == "reference_images"
            ref_section = getattr(self, "ltx_section_reference_images", None)
            if ref_section is not None:
                ref_section.setVisible(ref_mode)
            chars = getattr(self, "edit_bridge_characters_subjects", None)
            if chars is not None:
                chars.setPlaceholderText(
                    "Example: singers, dancers, creatures, objects"
                    if ref_mode
                    else "Example: a woman with wavy long black hair and a funny green alien"
                )
            note = getattr(self, "label_bridge_character_source_note", None)
            if note is not None:
                try:
                    note.setText(
                        "Reference image mode — HiDream reference/edit workflow is used."
                        if ref_mode
                        else "Built-in character bible mode — reference image section auto-hidden."
                    )
                except Exception:
                    pass
            image_combo = getattr(self, "combo_ltx_single_image_mode", None)
            if image_combo is not None:
                if ref_mode:
                    image_combo.blockSignals(True)
                    self._ltx_combo_set_data(image_combo, "hidream")
                    image_combo.blockSignals(False)
                    image_combo.setEnabled(False)
                    image_combo.setToolTip("Reference images are active, so the start-image workflow is locked to HiDream reference/edit mode.")
                else:
                    image_combo.setEnabled(True)
                    image_combo.setToolTip(
                        "Choose whether to use a ready-made start image or generate one with an image model. "
                        "When Reference images is selected, this is locked to HiDream."
                    )
            self._update_ltx_single_image_mode_ui()
        except Exception:
            pass

    def _update_ltx_lipsync_trim_lock(self) -> None:
        try:
            trim = getattr(self, "check_ltx_full_trim_clips", None)
            if trim is None:
                return
            roles_on = bool(getattr(self, "check_bridge_use_vocal_roles", None) and self.check_bridge_use_vocal_roles.isChecked())
            chunks_on = bool(getattr(self, "check_bridge_ltx_export_audio_chunks", None) and self.check_bridge_ltx_export_audio_chunks.isChecked())
            locked = roles_on or chunks_on
            if locked:
                trim.blockSignals(True)
                trim.setChecked(True)
                trim.blockSignals(False)
                trim.setEnabled(False)
                trim.setToolTip("Required while vocal/non-vocal roles or LTX lipsync audio chunks are enabled, so generated clips stay aligned to the timeline.")
            else:
                trim.setEnabled(True)
                trim.setToolTip("Creates sync-safe trimmed clips using the shot-plan duration.")
        except Exception:
            pass

    def _update_ltx_single_image_mode_ui(self) -> None:
        try:
            source_combo = getattr(self, "combo_bridge_character_source", None)
            if source_combo is not None and str(source_combo.currentData() or "") == "reference_images":
                combo = getattr(self, "combo_ltx_single_image_mode", None)
                if combo is not None and str(combo.currentData() or "") != "hidream":
                    combo.blockSignals(True)
                    self._ltx_combo_set_data(combo, "hidream")
                    combo.blockSignals(False)
            combo = getattr(self, "combo_ltx_single_image_mode", None)
            mode = combo.currentData() if combo is not None else "existing"
            visible = str(mode or "existing") == "existing"
            row = getattr(self, "row_ltx_single_start_image", None)
            if row is not None:
                row.setVisible(visible)
        except Exception:
            pass

