    def _ltx_shot_browse_text(self, shot: dict) -> str:
        try:
            sid = str(shot.get("id") or "").strip()
            start = float(shot.get("song_start") or 0.0)
            end = float(shot.get("song_end") or 0.0)
            dur = float(shot.get("duration") or max(0.0, end - start))
            lipsync = "lipsync" if bool(shot.get("needs_lipsync")) else "music/rhythm"
            role = str(shot.get("scene_role_summary") or shot.get("microclip_style") or "").strip()
            prompt = str(shot.get("director_timestamped_video_prompt") or shot.get("timestamped_video_prompt") or shot.get("director_video_prompt") or shot.get("video_prompt") or "").strip()
            prompt = re.sub(r"\s+", " ", prompt)[:650]
            lines = [f"{sid} | {start:.2f}s-{end:.2f}s | {dur:.2f}s | {lipsync}"]
            if role:
                lines.append(f"Role: {role}")
            if prompt:
                lines.append(f"Prompt: {prompt}")
            return "\n".join(lines)
        except Exception:
            return "LTX shot details unavailable."

    def _on_ltx_single_shot_selection_changed(self, _index: int = -1) -> None:
        """Browse LTX shot metadata without changing the active render target."""
        combo = getattr(self, "combo_ltx_single_shot", None)
        if combo is None or combo.count() <= 0:
            return
        try:
            shot_id = str(combo.currentData() or combo.currentText() or "").split(" ")[0].strip()
        except Exception:
            shot_id = ""
        try:
            self._ltx_ui_selected_shot_id = shot_id
        except Exception:
            pass
        meta = getattr(self, "_ltx_single_shot_meta", {}) or {}
        shot = meta.get(shot_id) if isinstance(meta, dict) else None
        if isinstance(shot, dict):
            tip = self._ltx_shot_browse_text(shot)
            try:
                combo.setToolTip(tip)
            except Exception:
                pass
            if bool(getattr(self, "_ltx_full_run_running", False)):
                active = str(getattr(self, "_ltx_active_render_shot_id", "") or "").strip()
                active_note = f" Active render: {active}." if active else ""
                self._set_planner_bridge_status(f"Planner Bridge: browsing {shot_id} during generation.{active_note}")

    def _ltx_duration_guard_payload(self) -> dict:
        """Build the small payload used by the LTX duration/audio-chunk guard.

        This is intentionally limited to the guard inputs. It does not alter final
        assembly or muxing; it only gives the splitter enough context to rebuild
        per-shot WAV chunks from the original track when shot timings change.
        """
        payload = {
            "ltx_backend": self._current_ltx_generation_backend(),
            "root_dir": _musicclip_project_root(),
        }
        try:
            settings = self._planner_bridge_generation_settings()
            if isinstance(settings, dict):
                payload["bridge_generation_settings"] = settings
        except Exception:
            pass
        try:
            export_chunks = bool(getattr(self, "check_bridge_ltx_export_audio_chunks", None) is None or self.check_bridge_ltx_export_audio_chunks.isChecked())
            payload["export_audio_chunks"] = export_chunks
        except Exception:
            payload["export_audio_chunks"] = True
        try:
            audio = ""
            if getattr(self, "edit_ltx_audio", None) is not None:
                audio = str(self.edit_ltx_audio.text() or "").strip()
            if not audio and getattr(self, "edit_audio", None) is not None:
                audio = str(self.edit_audio.text() or "").strip()
            if audio:
                # Multiple names are deliberate: bridge/plan files used both
                # audio_path and music_path over time. These are source paths,
                # not generated chunk paths.
                payload["source_audio"] = audio
                payload["audio_path"] = audio
                payload["music_path"] = audio
                payload["media_path"] = audio
                payload["full_song_path"] = audio
        except Exception:
            pass
        for attr, key in (
            ("_planner_bridge_last_scene_plan_path", "scene_plan_path"),
            ("_planner_bridge_last_prompt_plan_path", "prompt_plan_path"),
            ("_planner_bridge_last_ltx_shot_plan_path", "ltx_shot_plan_path"),
            ("_planner_bridge_last_ltx_director_plan_path", "ltx_director_plan_path"),
        ):
            try:
                val = str(getattr(self, attr, "") or "").strip()
                if val:
                    payload[key] = val
            except Exception:
                pass
        return payload

    def _apply_ltx_duration_guard_for_plan(self, plan_path: str, label: str = "LTX director plan") -> dict:
        """Split overlong LTX shots and immediately rebuild only per-shot audio chunks."""
        payload = self._ltx_duration_guard_payload()
        report = _musicclip_ltx_sanitize_plan_file(plan_path, payload, label)
        if isinstance(report, dict) and report.get("changed"):
            audio_report = _musicclip_ltx_regenerate_audio_chunks_for_plan(plan_path, payload, label)
            report["audio_chunk_report"] = audio_report
        return report

    def _refresh_ltx_single_shots(self) -> None:
        combo = getattr(self, "combo_ltx_single_shot", None)
        if combo is None:
            return
        combo.clear()
        path = self._planner_bridge_existing_ltx_director_plan_path()
        if not path:
            self._set_planner_bridge_status("Planner Bridge: Create an LTX director plan first, then refresh LTX shots.")
            return
        try:
            try:
                report = self._apply_ltx_duration_guard_for_plan(path, "LTX director plan")
                if isinstance(report, dict) and report.get("changed"):
                    audio_report = report.get("audio_chunk_report") if isinstance(report.get("audio_chunk_report"), dict) else {}
                    audio_note = " Audio chunks rebuilt." if audio_report.get("changed") else ""
                    self._set_planner_bridge_status(f"Planner Bridge: Duration guard split {int(report.get('split_count') or 0)} over-10s LTX shot(s).{audio_note}")
            except Exception:
                pass
            with open(path, "r", encoding="utf-8") as f:
                data = json.load(f)
            shots = [s for s in (data.get("shots") or []) if isinstance(s, dict)] if isinstance(data, dict) else []
            if not shots:
                self._set_planner_bridge_status("Planner Bridge: Director plan has no LTX shots.")
                return
            meta = {}
            for shot in shots:
                sid = str(shot.get("id") or "").strip() or "LTX"
                start = float(shot.get("song_start") or 0.0)
                end = float(shot.get("song_end") or 0.0)
                dur = float(shot.get("duration") or max(0.0, end - start))
                lipsync = "lipsync" if bool(shot.get("needs_lipsync")) else "music/rhythm"
                role = str(shot.get("scene_role_summary") or shot.get("microclip_style") or "").strip()
                label_role = f" — {role[:32]}" if role else ""
                combo.addItem(f"{sid} — {start:.2f}s-{end:.2f}s — {dur:.1f}s — {lipsync}{label_role}", sid)
                meta[sid] = dict(shot)
            try:
                self._ltx_single_shot_meta = meta
            except Exception:
                pass
            try:
                self._planner_bridge_last_ltx_director_plan_path = path
            except Exception:
                pass
            self._on_ltx_single_shot_selection_changed(combo.currentIndex())
            self._set_planner_bridge_status(f"Planner Bridge: Loaded {len(shots)} LTX director shots.")
        except Exception as exc:
            self._set_planner_bridge_status(f"Planner Bridge: Could not load LTX shots: {exc}")
            try:
                QMessageBox.warning(self, "Planner Bridge", f"Could not load LTX shots:\n{exc}", QMessageBox.Ok)
            except Exception:
                pass

