    def _on_ltx_full_run_progress(self, text: str) -> None:
        msg_raw = str(text or "").strip()
        if not msg_raw:
            return
        try:
            m = re.match(r"\s*(LTX\d+)\s*:", msg_raw, flags=re.IGNORECASE)
            if m:
                self._ltx_active_render_shot_id = m.group(1).upper()
        except Exception:
            pass
        msg = msg_raw
        if not msg.lower().startswith("planner bridge:"):
            msg = f"Planner Bridge: {msg}"
        self._set_planner_bridge_status(msg)
        try:
            if hasattr(self, "progress"):
                self.progress.setFormat(str(text or "Generating all LTX shots..."))
        except Exception:
            pass

    def _on_ltx_full_run_finished(self, result: dict) -> None:
        self._set_ltx_full_run_busy(False)
        self._ltx_full_run_worker = None
        try:
            self._ltx_active_render_shot_id = ""
        except Exception:
            pass
        if not isinstance(result, dict):
            result = {"ok": False, "message": "Full LTX run returned an invalid result."}
        if bool(result.get("cancelled")):
            try:
                self._ltx_videoclip_auto_after_generation = False
                self._ltx_videoclip_auto_after_assembly = False
                self._ltx_review_continue_after_missing_generation = False
            except Exception:
                pass
            msg = str(result.get("message") or "LTX generation cancelled.")
            self._set_planner_bridge_status(f"Planner Bridge: {msg}")
            try:
                if hasattr(self, "progress"):
                    self.progress.setFormat("LTX generation cancelled.")
            except Exception:
                pass
            if bool(getattr(self, "_ltx_videoclip_workflow_running", False)):
                self._ltx_finish_videoclip_workflow(False, "LTX generation cancelled.")
            return
        msg = str(result.get("message") or "Full LTX run finished.")
        out_dir = str(result.get("output_dir") or "").strip()
        if out_dir and out_dir not in msg:
            msg += f" Output: {out_dir}"
        self._set_planner_bridge_status(f"Planner Bridge: {msg}")
        try:
            plan_for_meta = str(result.get("ltx_director_plan_path") or self._ltx_review_current_plan_path() or "").strip()
            if plan_for_meta:
                self._ltx_review_update_job_metadata(plan_for_meta)
        except Exception:
            pass
        try:
            if hasattr(self, "progress"):
                self.progress.setFormat("Full LTX run finished.")
        except Exception:
            pass
        try:
            self._on_refresh_ltx_review_clicked(silent=True)
        except Exception:
            pass
        if bool(getattr(self, "_ltx_review_continue_after_missing_generation", False)):
            self._ltx_review_continue_after_missing_generation = False
            QTimer.singleShot(0, self._on_ltx_review_continue_reassemble_clicked)
            return
        if bool(getattr(self, "_ltx_videoclip_auto_after_generation", False)):
            self._ltx_videoclip_auto_after_generation = False
            QTimer.singleShot(0, self._continue_ltx_videoclip_after_generation)
            return
        try:
            self._show_toast("Full LTX run finished.")
        except Exception:
            pass

    def _on_ltx_full_run_failed(self, message: str) -> None:
        self._set_ltx_full_run_busy(False)
        self._ltx_full_run_worker = None
        try:
            self._ltx_active_render_shot_id = ""
        except Exception:
            pass
        msg = str(message or "Full LTX run failed.")
        self._set_planner_bridge_status(f"Planner Bridge: {msg}")
        try:
            if hasattr(self, "progress"):
                self.progress.setFormat("Full LTX run failed.")
        except Exception:
            pass
        try:
            QMessageBox.warning(self, "Planner Bridge", msg, QMessageBox.Ok)
        except Exception:
            pass
        if bool(getattr(self, "_ltx_videoclip_workflow_running", False)):
            self._ltx_finish_videoclip_workflow(False, f"Full LTX generation failed: {msg}")

